        BuildPipeline.BuildPlayer(CreateWindowsBuildOptions(WindowsQaBuildPath, new[] { "CARE_REVIEW_QA_TOOLS" }));
        RemoveNonGameplayPlayerFiles(WindowsQaBuildPath);
    }

