    private static void PackageWindowsRelease()
    {
        string executablePath = Path.Combine(WindowsBuildPath, "CareReviewOffice.exe");
        if (!File.Exists(executablePath))
        {
            throw new FileNotFoundException("Windows build is missing. Run BuildWindows first.", executablePath);
        }

        Directory.CreateDirectory(ReleaseRootPath);
        RemoveStaleReleasePackages();
        string targetPath = Path.Combine(ReleaseRootPath, ReleasePackageName);
        if (Directory.Exists(targetPath))
        {
            Directory.Delete(targetPath, true);
        }

        CopyDirectory(WindowsBuildPath, targetPath);
        File.WriteAllText(Path.Combine(targetPath, "README_KR.txt"), BuildReadmeText(), new UTF8Encoding(false));
        File.WriteAllText(
            Path.Combine(targetPath, "RELEASE_MANIFEST.txt"),
            BuildManifestText(),
            new UTF8Encoding(false));

        WriteReleaseZipForCurrentPackage();
        AssetDatabase.Refresh();
        Debug.Log("Care Review Office release package created at " + targetPath);
    }

    private static void RemoveStaleReleasePackages()
    {
        if (!Directory.Exists(ReleaseRootPath))
        {
            return;
        }

        string releaseRootFullPath = Path.GetFullPath(ReleaseRootPath);
        foreach (string directoryPath in Directory.GetDirectories(ReleaseRootPath, "CareReviewOffice_Windows_v*"))
        {
            if (string.Equals(Path.GetFileName(directoryPath), ReleasePackageName, StringComparison.Ordinal))
            {
                continue;
            }

            string fullPath = Path.GetFullPath(directoryPath);
            if (!fullPath.StartsWith(releaseRootFullPath + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase))
            {
                throw new InvalidOperationException("Refusing to delete release directory outside release root: " + fullPath);
            }

            Directory.Delete(fullPath, true);
        }

        foreach (string filePath in Directory.GetFiles(ReleaseRootPath, "CareReviewOffice_Windows_v*"))
        {
            string fileName = Path.GetFileName(filePath);
            if (string.Equals(fileName, ReleasePackageName + ".zip", StringComparison.Ordinal) ||
                string.Equals(fileName, ReleasePackageName + "_SHA256.txt", StringComparison.Ordinal))
            {
                continue;
            }

            string fullPath = Path.GetFullPath(filePath);
            if (!fullPath.StartsWith(releaseRootFullPath + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase))
            {
                throw new InvalidOperationException("Refusing to delete release file outside release root: " + fullPath);
            }

            File.Delete(fullPath);
        }
    }

    private static void RemoveNonGameplayPlayerFiles(string rootPath)
    {
        if (!Directory.Exists(rootPath))
        {
            return;
        }

        string crashHandlerPath = Path.Combine(rootPath, "UnityCrashHandler64.exe");
        if (File.Exists(crashHandlerPath))
        {
            File.Delete(crashHandlerPath);
        }

        string managedPath = Path.Combine(rootPath, "CareReviewOffice_Data", "Managed");
        foreach (string moduleName in NonGameplayManagedModuleFiles)
        {
            string modulePath = Path.Combine(managedPath, moduleName);
            if (File.Exists(modulePath))
            {
                File.Delete(modulePath);
            }
        }

        foreach (string libraryName in NonGameplayManagedLibraryFiles)
        {
            string libraryPath = Path.Combine(managedPath, libraryName);
            if (File.Exists(libraryPath))
            {
                File.Delete(libraryPath);
            }
        }

        string monoConfigPath = Path.Combine(rootPath, "MonoBleedingEdge", "etc", "mono");
        if (Directory.Exists(monoConfigPath))
        {
            foreach (string fileName in NonGameplayMonoWebRuntimeFiles)
            {
                foreach (string filePath in Directory.GetFiles(monoConfigPath, fileName, SearchOption.AllDirectories))
                {
                    File.Delete(filePath);
                }
            }
        }

        foreach (string relativePath in NonGameplayMonoRuntimeRelativeFiles)
        {
            string filePath = Path.Combine(rootPath, relativePath.Replace('/', Path.DirectorySeparatorChar));
            if (File.Exists(filePath))
            {
                File.Delete(filePath);
            }
        }
    }

    private static void WriteReleaseZipForCurrentPackage()
    {
        string releasePath = Path.Combine(ReleaseRootPath, ReleasePackageName);
        string releaseZipPath = Path.Combine(ReleaseRootPath, ReleasePackageName + ".zip");
        string releaseHashPath = Path.Combine(ReleaseRootPath, ReleasePackageName + "_SHA256.txt");
        if (!Directory.Exists(releasePath))
        {
            throw new DirectoryNotFoundException("Release package folder is missing. " + releasePath);
        }

        if (File.Exists(releaseZipPath))
        {
            File.Delete(releaseZipPath);
        }

        ZipFile.CreateFromDirectory(releasePath, releaseZipPath, System.IO.Compression.CompressionLevel.Optimal, false);
        File.WriteAllText(releaseHashPath, ComputeSha256(releaseZipPath), new UTF8Encoding(false));
    }

    private static void PackageSteamworksDepot()
    {
        string releasePath = Path.Combine(ReleaseRootPath, ReleasePackageName);
        string releaseExecutablePath = Path.Combine(releasePath, "CareReviewOffice.exe");
        if (!File.Exists(releaseExecutablePath))
        {
            throw new FileNotFoundException("Release package is missing. Run PackageWindowsRelease first.", releaseExecutablePath);
        }

        if (Directory.Exists(SteamworksContentPath))
        {
            Directory.Delete(SteamworksContentPath, true);
        }

        Directory.CreateDirectory(SteamworksRootPath);
        Directory.CreateDirectory(SteamworksScriptsPath);
        Directory.CreateDirectory(SteamworksOutputPath);
        Directory.CreateDirectory(SteamworksStorePagePath);
        CopyDirectory(releasePath, SteamworksContentPath);

        int contentFileCount = CountFiles(SteamworksContentPath);
        long contentBytes = SumFileBytes(SteamworksContentPath);
        string zipHashPath = Path.Combine(ReleaseRootPath, ReleasePackageName + "_SHA256.txt");
        string zipHash = File.Exists(zipHashPath) ? File.ReadAllText(zipHashPath, Encoding.UTF8).Trim() : "not generated";

        File.WriteAllText(Path.Combine(SteamworksScriptsPath, "app_build_" + PlaceholderSteamAppId + ".vdf"), BuildSteamAppBuildVdf(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksScriptsPath, "depot_build_" + PlaceholderSteamDepotId + ".vdf"), BuildSteamDepotBuildVdf(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksScriptsPath, "upload_preview_steamcmd.ps1"), BuildSteamUploadPreviewScript(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksScriptsPath, "configure_steamworks_ids.ps1"), BuildSteamConfigureIdsScript(), new UTF8Encoding(false));
        WriteStoreCandidateCaptureSyncAssets();
        CopyStorePageDocument("Docs/Steam_상점페이지_자료.md", "STORE_PAGE_METADATA_KO.md");
        CopyStorePageDocument("Docs/Steam_상점페이지_제출안.md", "STORE_PAGE_SUBMISSION_DRAFT_KO.md");
        CopyStorePageDocument("Docs/Steam_개인정보_데이터_처리_고지.md", "PRIVACY_AND_DATA_NOTICE_KO.md");
        CopyStorePageDocument("Docs/트레일러_리마스터_작업표.md", "TRAILER_REMASTER_WORK_ORDER_KO.md");
        CopyStorePageCandidateScreenshots();
        File.WriteAllText(Path.Combine(SteamworksStorePagePath, "TRAILER_UPLOAD_SELECTION_KO.md"), BuildTrailerUploadSelectionManifest(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksStorePagePath, "STORE_PRESENCE_SELECTION_KO.md"), BuildStorePresenceSelectionManifest(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksStorePagePath, "STORE_VALUE_POSITIONING_KO.md"), BuildStoreValuePositioningManifest(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksStorePagePath, "ACHIEVEMENT_CANDIDATES_KO.md"), BuildAchievementCandidateMarkdown(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksStorePagePath, "ACHIEVEMENT_CANDIDATES.csv"), BuildAchievementCandidateCsv(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksRootPath, "README_STEAMWORKS_KR.txt"), BuildSteamworksReadmeText(contentFileCount, contentBytes), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksRootPath, "STEAMWORKS_UPLOAD_MANIFEST.txt"), BuildSteamworksUploadManifest(contentFileCount, contentBytes, zipHash), new UTF8Encoding(false));
        BuildExternalValidationHandoffFiles(null);
        File.WriteAllText(Path.Combine(SteamworksRootPath, "STEAM_SUBMISSION_PREFLIGHT_KO.md"), BuildSteamSubmissionPreflightReport(contentFileCount, contentBytes, zipHash), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksRootPath, "RELEASE_CANDIDATE_AUDIT_NOTE_KO.md"), BuildReleaseCandidateAuditNote(), new UTF8Encoding(false));
        WriteSteamworksZip();

        AssetDatabase.Refresh();
        Debug.Log("Care Review Office Steamworks depot prepared at " + SteamworksRootPath);
    }

    private static void WriteSteamworksZip()
    {
        Directory.CreateDirectory(Path.GetDirectoryName(SteamworksZipPath));
        if (File.Exists(SteamworksZipPath))
        {
            File.Delete(SteamworksZipPath);
        }

        ZipFile.CreateFromDirectory(SteamworksRootPath, SteamworksZipPath, System.IO.Compression.CompressionLevel.Optimal, true);
        File.WriteAllText(SteamworksHashPath, ComputeSha256(SteamworksZipPath), new UTF8Encoding(false));
    }

