        audit.filesHaveNoLocalAbsolutePath = !ContainsLocalAbsolutePath(SafeReadAllText(Path.Combine(reportPath, "final_report.md")) + SafeReadAllText(Path.Combine(aiUsagePath, "AI_USAGE_LOG.md")) + SafeReadAllText(Path.Combine(ethicsPath, "synthetic_data_notice.md")) + SafeReadAllText(Path.Combine(ethicsPath, "privacy_ethics_review.md")) + SafeReadAllText(Path.Combine(presentationPath, "presentation_deck.md")) + SafeReadAllText(Path.Combine(CourseFinalSubmissionPath, "00_GOAL_COMPLETION_AUDIT.md")));
        audit.packageReadyForMarkdownSubmission = audit.blockerCount == 0 && audit.hasFinalSubmissionFolder && audit.hasGameBuild && audit.hasScreenshots && audit.hasPlayerLogs && audit.hasAgentLogs && audit.hasDashboard && audit.hasReportMarkdown && audit.hasPresentationDeck && audit.hasGoalCompletionAudit && audit.hasAiUsageLog && audit.hasEthicsDocs && audit.hasQaEvidence && audit.filesHaveNoLocalAbsolutePath;
        audit.finalSubmissionFullyReady = audit.packageReadyForMarkdownSubmission && audit.hasReportPdf && audit.hasPresentationPdf;

        string auditJsonPath = Path.Combine(CourseFinalSubmissionAuditPath, "care_review_final_submission_audit.json");
        string auditCsvPath = Path.Combine(CourseFinalSubmissionAuditPath, "care_review_final_submission_audit.csv");
        string auditMarkdownPath = Path.Combine(CourseFinalSubmissionAuditPath, "care_review_final_submission_audit.md");
        File.WriteAllText(auditJsonPath, BuildCourseSubmissionAuditJson(audit), new UTF8Encoding(false));
        File.WriteAllText(auditCsvPath, BuildCourseSubmissionAuditCsv(audit), new UTF8Encoding(false));
        File.WriteAllText(auditMarkdownPath, BuildCourseSubmissionAuditMarkdown(audit), new UTF8Encoding(false));
        File.Copy(auditJsonPath, Path.Combine(CourseFinalSubmissionPath, "00_PACKAGE_AUDIT.json"), true);
        File.Copy(auditMarkdownPath, Path.Combine(CourseFinalSubmissionPath, "00_PACKAGE_AUDIT.md"), true);

        AssetDatabase.Refresh();
        return audit;
    }

    private static void EnsureReleaseZipForSubmission()
    {
        string releasePath = Path.Combine(ReleaseRootPath, ReleasePackageName);
        if (!Directory.Exists(releasePath) && File.Exists(Path.Combine(WindowsBuildPath, "CareReviewOffice.exe")))
        {
            PackageWindowsRelease();
        }

        string releaseZipPath = Path.Combine(ReleaseRootPath, ReleasePackageName + ".zip");
        if (!File.Exists(releaseZipPath) && Directory.Exists(releasePath))
        {
            ZipFile.CreateFromDirectory(releasePath, releaseZipPath, System.IO.Compression.CompressionLevel.Optimal, false);
            File.WriteAllText(Path.Combine(ReleaseRootPath, ReleasePackageName + "_SHA256.txt"), ComputeSha256(releaseZipPath), new UTF8Encoding(false));
        }

        string hashPath = Path.Combine(ReleaseRootPath, ReleasePackageName + "_SHA256.txt");
        if (File.Exists(releaseZipPath) && !File.Exists(hashPath))
        {
            File.WriteAllText(hashPath, ComputeSha256(releaseZipPath), new UTF8Encoding(false));
        }
    }

    private static void CopySubmissionFile(CourseSubmissionAudit audit, string label, string sourcePath, string targetPath, bool required = true)
    {
        if (File.Exists(sourcePath))
        {
            Directory.CreateDirectory(Path.GetDirectoryName(targetPath));
            File.Copy(sourcePath, targetPath, true);
            AddCourseSubmissionCheck(audit, label, true, targetPath.Replace("\\", "/"), required);
        }
        else
        {
            AddCourseSubmissionCheck(audit, label, !required, "missing: " + sourcePath.Replace("\\", "/"), required);
        }
    }

    private static void AddCourseSubmissionCheck(CourseSubmissionAudit audit, string label, bool passed, string evidence, bool required = true)
    {
        audit.checks.Add(new CourseSubmissionCheck
        {
            label = label,
            passed = passed,
            required = required,
            evidence = evidence.Replace("\\", "/")
        });
    }

    private static string BuildCourseFinalReportMarkdown()
    {
        string summaryJson = SafeReadAllText("Builds/QA/v0.3.0/playtest_packet/care_review_playtest_summary.json");
        string caseCount = FirstNonEmpty(ExtractJsonNumber(summaryJson, "caseCount"), "40");
        string logCount = FirstNonEmpty(ExtractJsonNumber(summaryJson, "logCount"), "40");
        string campaignMandateName = FirstNonEmpty(ExtractJsonString(summaryJson, "campaignMandateName"), "균형 심사");
        string campaignGrade = FirstNonEmpty(ExtractJsonString(summaryJson, "campaignGrade"), "B");
        string campaignScore = FirstNonEmpty(ExtractJsonNumber(summaryJson, "campaignScore"), "73");
        string finalBudget = FirstNonEmpty(ExtractJsonNumber(summaryJson, "finalBudget"), "-697");
        string finalStability = FirstNonEmpty(ExtractJsonNumber(summaryJson, "finalStability"), "93");
        string finalEquity = FirstNonEmpty(ExtractJsonNumber(summaryJson, "finalEquity"), "99");
        string finalMissedRisk = FirstNonEmpty(ExtractJsonNumber(summaryJson, "finalMissedRisk"), "23");
        string finalComplaints = FirstNonEmpty(ExtractJsonNumber(summaryJson, "finalComplaints"), "80");
        string supportCount = FirstNonEmpty(ExtractJsonNumber(summaryJson, "supportCount"), "10");
        string conditionalCount = FirstNonEmpty(ExtractJsonNumber(summaryJson, "conditionalCount"), "15");
        string investigationCount = FirstNonEmpty(ExtractJsonNumber(summaryJson, "investigationCount"), "8");
        string holdCount = FirstNonEmpty(ExtractJsonNumber(summaryJson, "holdCount"), "5");
        string rejectCount = FirstNonEmpty(ExtractJsonNumber(summaryJson, "rejectCount"), "2");
        string matchRate = FirstNonEmpty(ExtractJsonNumber(summaryJson, "recommendedMatchRatePercent"), "100.0");
        string urgentMismatchCount = FirstNonEmpty(ExtractJsonNumber(summaryJson, "urgentMismatchCount"), "0");
        string highCostSupportCount = FirstNonEmpty(ExtractJsonNumber(summaryJson, "highCostSupportCount"), "25");
        string topRationale = FirstNonEmpty(ExtractJsonString(summaryJson, "topDecisionRationaleName"), "균형 검토");
        string topRationaleCount = FirstNonEmpty(ExtractJsonNumber(summaryJson, "topDecisionRationaleCount"), "40");
        string challengeTitle = FirstNonEmpty(ExtractJsonString(summaryJson, "campaignChallengeTitle"), "근거 일치 계약");
        string challengeProgress = FirstNonEmpty(ExtractJsonString(summaryJson, "campaignChallengeProgress"), "권장 일치 100.0% · 고위험 불일치 0건");
        string nextMandate = FirstNonEmpty(ExtractJsonString(summaryJson, "nextCampaignMandateName"), "긴축 감사");
        string nextReason = FirstNonEmpty(ExtractJsonString(summaryJson, "nextCampaignReason"), "예산 압박 보강");

        StringBuilder builder = new();
        builder.AppendLine("# 돌봄지원 심사소 최종 보고서");
        builder.AppendLine();
        builder.AppendLine("## 1. 프로젝트 개요");
        builder.AppendLine();
        builder.AppendLine("`돌봄지원 심사소`는 합성 가족지원 신청 사례를 게임 안에서 심사하게 만들고, 플레이어와 가상 AI 에이전트의 판단 로그를 수집해 판단 경향을 대시보드와 보고서로 분석하는 게임형 의사결정 실험 플랫폼이다. 발표에서는 다음 한 문장으로 설명할 수 있다.");
        builder.AppendLine();
        builder.AppendLine("> 합성 가족지원 신청 사례를 게임 안에서 심사하게 만들고, 플레이어와 여러 AI 에이전트의 판단 로그를 수집해, 가족 유형·위험도·서류 완성도·예산 상황에 따라 승인/거절/추가조사 판단이 어떻게 달라지는지 분석하는 프로젝트입니다.");
        builder.AppendLine();
        builder.AppendLine("## 2. Research Questions");
        builder.AppendLine();
