    private static string BuildAgentComparisonTableMarkdown(string csvPath)
    {
        if (!File.Exists(csvPath))
        {
            return "에이전트 로그 CSV가 없어 표를 생성하지 못했다.\n";
        }

        Dictionary<string, AgentSubmissionSummary> summaries = new(StringComparer.OrdinalIgnoreCase);
        string[] lines = File.ReadAllLines(csvPath, Encoding.UTF8);
        for (int i = 1; i < lines.Length; i++)
        {
            if (string.IsNullOrWhiteSpace(lines[i]))
            {
                continue;
            }

            string[] cells = SplitSimpleCsvLine(lines[i]);
            if (cells.Length < 12)
            {
                continue;
            }

            string personaName = cells[1];
            string decision = cells[9];
            bool matched = string.Equals(cells[11], "true", StringComparison.OrdinalIgnoreCase);
            if (!summaries.TryGetValue(personaName, out AgentSubmissionSummary summary))
            {
                summary = new AgentSubmissionSummary { personaName = personaName };
                summaries.Add(personaName, summary);
            }

            summary.caseCount++;
            if (decision == "승인" || decision == "조건부 승인")
            {
                summary.supportCount++;
            }
            else if (decision == "추가조사")
            {
                summary.investigationCount++;
            }
            else
            {
                summary.holdOrRejectCount++;
            }

            if (matched)
            {
                summary.matchedCount++;
            }
        }

        StringBuilder builder = new();
        builder.AppendLine("| 에이전트 | 사례 수 | 지원 | 추가조사 | 보류/거절 | 권장 일치율 |");
        builder.AppendLine("| --- | ---: | ---: | ---: | ---: | ---: |");
        foreach (AgentSubmissionSummary summary in summaries.Values)
        {
            float matchRate = summary.caseCount > 0 ? summary.matchedCount * 100f / summary.caseCount : 0f;
            builder.AppendLine("| " + summary.personaName + " | " + summary.caseCount + " | " + summary.supportCount + " | " + summary.investigationCount + " | " + summary.holdOrRejectCount + " | " + FormatFloat(matchRate) + "% |");
        }

        return builder.ToString();
    }

    private static string[] SplitSimpleCsvLine(string line)
    {
        List<string> cells = new();
        StringBuilder cell = new();
        bool inQuotes = false;
        for (int i = 0; i < line.Length; i++)
        {
            char current = line[i];
            if (current == '"')
            {
                if (inQuotes && i + 1 < line.Length && line[i + 1] == '"')
                {
                    cell.Append('"');
                    i++;
                }
                else
                {
                    inQuotes = !inQuotes;
                }
            }
            else if (current == ',' && !inQuotes)
            {
                cells.Add(cell.ToString());
                cell.Clear();
            }
            else
            {
                cell.Append(current);
            }
        }
        cells.Add(cell.ToString());
        return cells.ToArray();
    }

