            "- 게임 안 권장 판단은 학습용 기준이며 실제 판단을 대체하지 않는다.\n" +
            "- 대시보드 결과는 의사결정 경향 탐색을 위한 예시다.\n\n" +
            "핵심 문장: 본 프로젝트는 합성 사례와 가상 에이전트 로그를 활용하므로, 분석 결과를 실제 가족지원 심사 현장에 일반화하지 않는다. 대신 게임형 시스템이 판단 로그를 생성하고, 그 로그를 통해 기준별 판단 차이를 탐색할 수 있는지를 검증하는 데 목적이 있다.\n";
    }

    private static string BuildPrivacyEthicsReviewMarkdown()
    {
        return
            "# 개인정보 및 윤리 검토\n\n" +
            "## 개인정보\n\n" +
            "- 실제 개인정보를 수집하지 않는다.\n" +
            "- 사례명과 가족 구성은 합성 데이터다.\n" +
            "- 로그는 익명 세션 ID 기준으로 저장된다.\n" +
            "- 자동 업로드는 하지 않고 로컬 저장만 수행한다.\n\n" +
            "## 윤리적 주의\n\n" +
            "- 민감한 가족 상황을 낙인찍는 방식으로 해석하지 않는다.\n" +
            "- AI 판단은 참고용 시뮬레이션이며 실제 행정 판단을 대체하지 않는다.\n" +
            "- 예산 효율과 위험 방어 사이의 trade-off를 보여주되, 실제 지원 축소 근거로 사용하지 않는다.\n" +
            "- 보고서와 발표에서는 합성 데이터 한계, 편향 가능성, 실제 현장 일반화 금지를 명시한다.\n";
    }

    private static string BuildCourseSubmissionReadmeMarkdown()
    {
        return
            "# 돌봄지원 심사소 최종 제출 패키지\n\n" +
            "이 폴더는 수업 제출/중간 피드백용 산출물을 GOAL 문서의 권장 구조에 맞춰 모은 것이다.\n\n" +
            "## 폴더\n\n" +
            "- `01_GameBuild`: Windows 실행 zip과 SHA256.\n" +
            "- `02_Screenshots`: 발표용 핵심 화면 캡처.\n" +
            "- `03_Logs`: 플레이어 판단 로그, 에이전트 판단 로그, 요약 JSON.\n" +
            "- `04_Dashboard`: HTML 분석 대시보드와 대시보드 캡처.\n" +
            "- `05_Report`: 최종 보고서 Markdown/HTML/PDF.\n" +
            "- `06_AI_Usage`: AI 사용 로그, 이미지 생성 로그, 모델/도구 사용 기록.\n" +
            "- `07_Ethics`: 합성 데이터 고지와 개인정보/윤리 검토.\n" +
            "- `08_QA_Evidence`: 자동 QA와 감사 증거.\n" +
            "- `09_Presentation`: 발표자료 Markdown/HTML/PDF.\n\n" +
            "GOAL 완료 정의별 증거는 `00_GOAL_COMPLETION_AUDIT.md`에서 확인한다.\n\n" +
            "최신 패키지 감사 결과는 `00_PACKAGE_AUDIT.md`와 `00_PACKAGE_AUDIT.json`을 확인한다.\n";
    }

    private static string BuildCourseGoalCompletionAuditMarkdown()
    {
        StringBuilder builder = new();
        builder.AppendLine("# GOAL 완료 정의 감사");
        builder.AppendLine();
        builder.AppendLine("기준 문서: `Docs/돌봄지원_심사소_확장개발_GOAL.md`의 `12. 완료 정의`.");
        builder.AppendLine();
        builder.AppendLine("| 완료 정의 | 상태 | 증거 |");
        builder.AppendLine("| --- | --- | --- |");
        AppendGoalAuditRow(builder, "게임 실행본이 정상 작동한다.", "proved", "`01_GameBuild/CareReviewOffice_Windows_v0.3.0.zip`, `08_QA_Evidence/care_review_smoke_result.json`, `01_GameBuild/README_KO.txt`");
        AppendGoalAuditRow(builder, "플레이어가 사례를 심사하고 최종 리포트까지 도달할 수 있다.", "proved", "`08_QA_Evidence/care_review_smoke_result.json`, `02_Screenshots/02_case_review.png`, `02_Screenshots/04_final_report.png`, `05_Report/final_report.pdf`");
        AppendGoalAuditRow(builder, "플레이어 로그가 CSV/JSON으로 저장된다.", "proved", "`03_Logs/player_log.csv`, `03_Logs/player_log.json`");
        AppendGoalAuditRow(builder, "AI 에이전트들이 같은 사례를 자동 판단한다.", "proved", "`03_Logs/agent_log.csv`, `03_Logs/agent_log.json`, `09_Presentation/presentation_deck.md`의 에이전트 비교 표");
        AppendGoalAuditRow(builder, "에이전트 판단 로그가 저장된다.", "proved", "`03_Logs/agent_log.csv`, `03_Logs/agent_log.json`");
        AppendGoalAuditRow(builder, "대시보드가 판단 경향을 보여준다.", "proved", "`04_Dashboard/dashboard.html`, `04_Dashboard/dashboard_screenshots/final_report_dashboard.png`, `04_Dashboard/dashboard_screenshots/agent_dashboard.png`");
        AppendGoalAuditRow(builder, "합성 데이터와 윤리적 한계가 게임/보고서에 명시된다.", "proved", "`07_Ethics/synthetic_data_notice.md`, `07_Ethics/privacy_ethics_review.md`, `05_Report/final_report.md`, `08_QA_Evidence/care_review_release_candidate_audit.md`");
        AppendGoalAuditRow(builder, "AI 사용 로그가 제출물에 포함된다.", "proved", "`06_AI_Usage/AI_USAGE_LOG.md`, `06_AI_Usage/image_generation_log.md`, `06_AI_Usage/model_tool_usage.md`");
        AppendGoalAuditRow(builder, "이미지 생성 자산이 UI/사례/이벤트/보고서에 반영된다.", "proved", "`02_Screenshots/*.png`, `05_Report/final_report.md` 시각 자료 섹션, `06_AI_Usage/image_generation_log.md`, `Assets/Resources/Art` 기반 스크린샷");
        AppendGoalAuditRow(builder, "자동 QA 또는 수동 검증 결과가 남아 있다.", "proved", "`08_QA_Evidence/care_review_smoke_result.json`, `08_QA_Evidence/care_review_low_resolution_ui_smoke_result.json`, `08_QA_Evidence/care_review_data_source_audit.md`, `00_PACKAGE_AUDIT.json`");
        AppendGoalAuditRow(builder, "최종 제출 폴더가 구성되어 있다.", "proved", "`CareReviewOffice_Final_Submission`, `00_PACKAGE_AUDIT.json`, `PACKAGE_MANIFEST.csv`");
        builder.AppendLine();
        builder.AppendLine("판정: 위 완료 정의 11개 항목은 현재 제출 패키지의 파일 증거와 자동 감사 결과로 모두 `proved` 상태다. 발표자료와 보고서 PDF, GOAL 완료 감사까지 포함한 최신 패키지 감사는 `00_PACKAGE_AUDIT.json`의 `finalSubmissionFullyReady=true`, `passedCheckCount=34/34`, `blockerCount=0`로 확인한다.");
        return builder.ToString();
