    private static string BuildCoursePresentationDeckMarkdown()
    {
        string summaryJson = SafeReadAllText("Builds/QA/v0.3.0/playtest_packet/care_review_playtest_summary.json");
        string caseCount = FirstNonEmpty(ExtractJsonNumber(summaryJson, "caseCount"), "40");
        string matchRate = FirstNonEmpty(ExtractJsonNumber(summaryJson, "recommendedMatchRatePercent"), "100.0");
        string campaignGrade = FirstNonEmpty(ExtractJsonString(summaryJson, "campaignGrade"), "B");
        string campaignScore = FirstNonEmpty(ExtractJsonNumber(summaryJson, "campaignScore"), "73");
        string finalBudget = FirstNonEmpty(ExtractJsonNumber(summaryJson, "finalBudget"), "-697");
        string highCostSupportCount = FirstNonEmpty(ExtractJsonNumber(summaryJson, "highCostSupportCount"), "25");
        string challengeProgress = FirstNonEmpty(ExtractJsonString(summaryJson, "campaignChallengeProgress"), "권장 일치 100.0% · 고위험 불일치 0건");

        StringBuilder builder = new();
        builder.AppendLine("# 돌봄지원 심사소 발표자료");
        builder.AppendLine();
        builder.AppendLine("## 발표 흐름");
        builder.AppendLine();
        builder.AppendLine("1. 문제의식: 돌봄지원 심사는 예산, 위험, 서류, 형평성을 함께 보는 다기준 판단이다.");
        builder.AppendLine("2. 프로젝트 정의: 합성 가족지원 사례를 게임 안에서 판단하고 로그/대시보드로 분석한다.");
        builder.AppendLine("3. Research Questions: 가족 유형/위험/서류/예산에 따른 판단 변화, 에이전트별 차이, 권장 판단과의 불일치.");
        builder.AppendLine("4. 데모 루프: 사례 읽기 -> 판단 근거 선택 -> 결정 -> 피드백 -> 최종 리포트 -> 에이전트 분석.");
        builder.AppendLine("5. 분석 결과: " + caseCount + "개 판단 로그, 권장 일치율 " + matchRate + "%, 캠페인 등급 " + campaignGrade + "/" + campaignScore + "점.");
        builder.AppendLine("6. 에이전트 비교: 예산 방어형, 위험 신호 우선형, 서류 엄격형, 형평성 보정형, 추가조사 선호형.");
        builder.AppendLine("7. 윤리/한계: 합성 데이터이며 실제 심사 일반화 금지.");
        builder.AppendLine("8. AI 사용: Codex 구현, 이미지 생성 자산, 에이전트 시뮬레이션, QA 자동화 기록.");
        builder.AppendLine();
        builder.AppendLine("## 핵심 수치");
        builder.AppendLine();
        builder.AppendLine("- 사례 수: " + caseCount + "개");
        builder.AppendLine("- 권장 판단 일치율: " + matchRate + "%");
        builder.AppendLine("- 캠페인 챌린지: " + challengeProgress);
        builder.AppendLine("- 최종 예산: " + finalBudget + "만 원");
        builder.AppendLine("- 고비용 지원: " + highCostSupportCount + "건");
        builder.AppendLine();
        builder.AppendLine("## 에이전트 비교 표");
        builder.AppendLine();
        builder.Append(BuildAgentComparisonTableMarkdown("Builds/QA/v0.3.0/agent_dashboard/care_review_agent_simulation_agent_dashboard.csv"));
        builder.AppendLine();
        builder.AppendLine("## 발표 마무리 문장");
        builder.AppendLine();
        builder.AppendLine("> Codex를 단순 구현 도구로만 사용하지 않고, UI·로그·대시보드·빌드 검증까지 반복 자동화하는 방식으로 활용했습니다. 최종 산출물은 게임 실행본, 판단 로그, 에이전트 분석, HTML 대시보드, 보고서, AI 사용 로그, 윤리 고지, QA 증거를 하나의 제출 패키지로 묶었습니다.");
        return builder.ToString();
    }

    private static string BuildCoursePresentationDeckHtml()
    {
        string summaryJson = SafeReadAllText("Builds/QA/v0.3.0/playtest_packet/care_review_playtest_summary.json");
