        string score = FirstNonEmpty(ExtractJsonNumber(summaryJson, "campaignScore"), "73");
        string budget = FirstNonEmpty(ExtractJsonNumber(summaryJson, "finalBudget"), "-697");
        string challengeProgress = FirstNonEmpty(ExtractJsonString(summaryJson, "campaignChallengeProgress"), "권장 일치 100.0% · 고위험 불일치 0건");

        StringBuilder html = new();
        html.AppendLine("<!doctype html><html lang=\"ko\"><head><meta charset=\"utf-8\"><title>돌봄지원 심사소 발표자료</title>");
        html.AppendLine("<style>@page{size:16in 9in;margin:0}body{margin:0;background:#18212a;color:#17212b;font-family:'Malgun Gothic','Noto Sans KR',Arial,sans-serif}.slide{box-sizing:border-box;width:16in;height:9in;padding:.62in .75in;page-break-after:always;background:#f7f3ea;position:relative;overflow:hidden}.slide.dark{background:#1f2d38;color:#f7f3ea}.slide h1{font-size:44px;margin:0 0 20px}.slide h2{font-size:36px;margin:0 0 18px;color:#23435c}.dark h2,.dark h1{color:#fff}.slide p,.slide li{font-size:22px;line-height:1.5}.kicker{font-size:18px;color:#67747f;font-weight:bold}.dark .kicker{color:#b8c8d8}.grid{display:grid;grid-template-columns:1fr 1fr;gap:28px}.card{background:rgba(255,255,255,.72);border:1px solid #d8ccb7;padding:22px}.dark .card{background:rgba(255,255,255,.08);border-color:rgba(255,255,255,.2)}.metric{display:inline-block;margin:10px 14px 10px 0;padding:14px 18px;background:#e4edf1;border-left:6px solid #426f8c;font-size:24px}.shot{width:100%;max-height:420px;object-fit:contain;border:1px solid #d8ccb7;background:#fff}.table{font-size:17px;line-height:1.35}.note{position:absolute;bottom:.38in;left:.75in;right:.75in;color:#667;font-size:16px}</style></head><body>");
        AppendSlide(html, true, "돌봄지원 심사소", "합성 가족지원 사례를 심사하고, 플레이어와 AI 에이전트 판단 로그를 대시보드로 분석하는 게임형 의사결정 실험 플랫폼", "<p>핵심: 게임 실행본 + 판단 로그 + 에이전트 분석 + 윤리/AI 사용 기록 + QA 증거</p>");
        AppendSlide(html, false, "Research Questions", "무엇을 알고 싶은가", "<ol><li>가족 유형, 위험 신호, 서류 완성도, 예산 상황에 따라 판단은 어떻게 달라지는가?</li><li>서로 다른 성향의 AI 에이전트는 같은 사례를 어떻게 다르게 판단하는가?</li><li>플레이어 판단과 기준 기반 권장 판단은 어떤 상황에서 어긋나는가?</li></ol>");
        AppendSlide(html, false, "게임 루프", "Input -> 판단 -> 로그 -> 분석 output", "<div class='grid'><div><ol><li>합성 사례 제시</li><li>판단 근거 선택</li><li>승인/조건부/보류/조사/거절</li><li>예산·위험·형평성·민원 지표 변화</li><li>CSV/JSON/HTML export</li></ol></div><div><img class='shot' src='../02_Screenshots/02_case_review.png'></div></div>");
        AppendSlide(html, false, "샘플 로그 결과", caseCount + "개 판단 로그", "<p><span class='metric'>권장 일치 " + HtmlEscape(matchRate) + "%</span><span class='metric'>등급 " + HtmlEscape(grade) + " / " + HtmlEscape(score) + "점</span><span class='metric'>예산 " + HtmlEscape(budget) + "만 원</span></p><p>캠페인 챌린지: " + HtmlEscape(challengeProgress) + "</p><img class='shot' src='../02_Screenshots/04_final_report.png'>");
        AppendSlide(html, false, "에이전트 분석", "같은 사례라도 기준이 다르면 판단이 달라진다", "<div class='grid'><div class='table'>" + HtmlEscape(BuildAgentComparisonTableMarkdown("Builds/QA/v0.3.0/agent_dashboard/care_review_agent_simulation_agent_dashboard.csv")).Replace("\n", "<br>") + "</div><div><img class='shot' src='../02_Screenshots/05_agent_analysis.png'></div></div>");
        AppendSlide(html, false, "대시보드", "게임 결과를 분석 가능한 output으로 회수", "<div class='grid'><div><ul><li>판단 분포</li><li>권장 판단 일치율</li><li>판단 근거 분포</li><li>결정 감사 일차표</li><li>고압력 사례 재검토 큐</li></ul></div><div><img class='shot' src='../04_Dashboard/dashboard_screenshots/final_report_dashboard.png'></div></div>");
        AppendSlide(html, false, "윤리와 한계", "합성 데이터 사용 이유와 해석 제한", "<ul><li>실제 가족지원 심사 데이터가 아니다.</li><li>실제 정책 효과나 가족 유형 특성으로 일반화하지 않는다.</li><li>AI 판단은 참고용 시뮬레이션이며 실제 행정 판단을 대체하지 않는다.</li><li>목적은 판단 로그 생성과 기준별 판단 차이 탐색이다.</li></ul>");
        AppendSlide(html, false, "AI 사용 기록", "기획, 구현, 자산, 에이전트, QA를 모두 기록", "<ul><li>Codex: Unity 구현, 로그 export, 대시보드, QA 자동화, 제출 패키징</li><li>이미지 생성: 배경, 가족 초상, 증빙 카드, 사건 카드, 도장, UI 크롬</li><li>에이전트 시뮬레이션: 판단 기준별 차이 탐색</li><li>제출 폴더: AI_USAGE_LOG.md, image_generation_log.md, model_tool_usage.md</li></ul>");
        AppendSlide(html, true, "제출 패키지", "CareReviewOffice_Final_Submission", "<ul><li>실행본, 스크린샷, 플레이어/에이전트 로그</li><li>HTML 대시보드, 보고서 Markdown/PDF, 발표자료</li><li>AI 사용 로그, 윤리 고지, QA 증거</li><li>자동 감사: packageReadyForMarkdownSubmission / finalSubmissionFullyReady</li></ul>");
        html.AppendLine("</body></html>");
        return html.ToString();
    }

    private static void AppendSlide(StringBuilder html, bool dark, string title, string subtitle, string body)
    {
        html.Append("<section class='slide");
        if (dark)
        {
            html.Append(" dark");
        }
        html.AppendLine("'>");
        html.AppendLine("<div class='kicker'>돌봄지원 심사소</div>");
        html.AppendLine("<h1>" + HtmlEscape(title) + "</h1>");
        html.AppendLine("<h2>" + HtmlEscape(subtitle) + "</h2>");
        html.AppendLine(body);
        html.AppendLine("<div class='note'>합성 사례 기반 의사결정 실험 플랫폼 · 실제 심사 판단 비대체</div>");
        html.AppendLine("</section>");
    }

    private static string BuildCourseSubmissionManifestCsv(string rootPath)
    {
        StringBuilder builder = new();
        builder.AppendLine("relative_path,bytes,sha256");
        if (!Directory.Exists(rootPath))
        {
            return builder.ToString();
        }

        foreach (string filePath in Directory.GetFiles(rootPath, "*", SearchOption.AllDirectories))
        {
            string relativePath = filePath.Substring(rootPath.Length).TrimStart(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar).Replace("\\", "/");
            builder.Append(EscapeCsv(relativePath)).Append(',')
                .Append(new FileInfo(filePath).Length.ToString(CultureInfo.InvariantCulture)).Append(',')
                .AppendLine(EscapeCsv(ComputeSha256(filePath)));
        }
        return builder.ToString();
    }

    private static string BuildCourseSubmissionAuditJson(CourseSubmissionAudit audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("{");
        builder.AppendLine("  \"generatedAt\": \"" + EscapeJson(audit.generatedAt) + "\",");
        builder.AppendLine("  \"version\": \"" + EscapeJson(audit.version) + "\",");
        builder.AppendLine("  \"rootPath\": \"" + EscapeJson(audit.rootPath) + "\",");
        builder.AppendLine("  \"packageReadyForMarkdownSubmission\": " + BoolJson(audit.packageReadyForMarkdownSubmission) + ",");
        builder.AppendLine("  \"finalSubmissionFullyReady\": " + BoolJson(audit.finalSubmissionFullyReady) + ",");
        builder.AppendLine("  \"hasFinalSubmissionFolder\": " + BoolJson(audit.hasFinalSubmissionFolder) + ",");
        builder.AppendLine("  \"hasGameBuild\": " + BoolJson(audit.hasGameBuild) + ",");
        builder.AppendLine("  \"hasScreenshots\": " + BoolJson(audit.hasScreenshots) + ",");
        builder.AppendLine("  \"hasPlayerLogs\": " + BoolJson(audit.hasPlayerLogs) + ",");
        builder.AppendLine("  \"hasAgentLogs\": " + BoolJson(audit.hasAgentLogs) + ",");
        builder.AppendLine("  \"hasDashboard\": " + BoolJson(audit.hasDashboard) + ",");
        builder.AppendLine("  \"hasReportMarkdown\": " + BoolJson(audit.hasReportMarkdown) + ",");
        builder.AppendLine("  \"hasReportPdf\": " + BoolJson(audit.hasReportPdf) + ",");
        builder.AppendLine("  \"hasPresentationDeck\": " + BoolJson(audit.hasPresentationDeck) + ",");
        builder.AppendLine("  \"hasPresentationPdf\": " + BoolJson(audit.hasPresentationPdf) + ",");
        builder.AppendLine("  \"hasGoalCompletionAudit\": " + BoolJson(audit.hasGoalCompletionAudit) + ",");
        builder.AppendLine("  \"hasAiUsageLog\": " + BoolJson(audit.hasAiUsageLog) + ",");
        builder.AppendLine("  \"hasEthicsDocs\": " + BoolJson(audit.hasEthicsDocs) + ",");
        builder.AppendLine("  \"hasQaEvidence\": " + BoolJson(audit.hasQaEvidence) + ",");
        builder.AppendLine("  \"filesHaveNoLocalAbsolutePath\": " + BoolJson(audit.filesHaveNoLocalAbsolutePath) + ",");
        builder.AppendLine("  \"checkCount\": " + audit.checkCount + ",");
        builder.AppendLine("  \"passedCheckCount\": " + audit.passedCheckCount + ",");
        builder.AppendLine("  \"blockerCount\": " + audit.blockerCount + ",");
        builder.AppendLine("  \"checks\": [");
        for (int i = 0; i < audit.checks.Count; i++)
        {
            CourseSubmissionCheck check = audit.checks[i];
            builder.AppendLine("    {");
            builder.AppendLine("      \"label\": \"" + EscapeJson(check.label) + "\",");
            builder.AppendLine("      \"passed\": " + BoolJson(check.passed) + ",");
            builder.AppendLine("      \"required\": " + BoolJson(check.required) + ",");
            builder.AppendLine("      \"evidence\": \"" + EscapeJson(check.evidence) + "\"");
            builder.Append("    }");
            builder.AppendLine(i == audit.checks.Count - 1 ? "" : ",");
        }
        builder.AppendLine("  ]");
        builder.AppendLine("}");
        return builder.ToString();
    }

    private static string BuildCourseSubmissionAuditCsv(CourseSubmissionAudit audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("label,passed,required,evidence");
        foreach (CourseSubmissionCheck check in audit.checks)
        {
            builder.Append(EscapeCsv(check.label)).Append(',')
                .Append(check.passed ? "true" : "false").Append(',')
                .Append(check.required ? "true" : "false").Append(',')
                .AppendLine(EscapeCsv(check.evidence));
        }
        return builder.ToString();
    }

    private static string BuildCourseSubmissionAuditMarkdown(CourseSubmissionAudit audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("# 최종 제출 패키지 감사");
        builder.AppendLine();
        builder.AppendLine("- 생성 시각: " + audit.generatedAt);
        builder.AppendLine("- 버전: " + audit.version);
        builder.AppendLine("- 루트: `" + audit.rootPath + "`");
        builder.AppendLine("- Markdown 제출 준비: `" + (audit.packageReadyForMarkdownSubmission ? "ready" : "not_ready") + "`");
        builder.AppendLine("- PDF 포함 완전 준비: `" + (audit.finalSubmissionFullyReady ? "ready" : "not_ready") + "`");
        builder.AppendLine("- 체크: `" + audit.passedCheckCount + "/" + audit.checkCount + "`");
        builder.AppendLine("- 필수 누락: `" + audit.blockerCount + "`");
        builder.AppendLine();
        builder.AppendLine("## 상태");
        builder.AppendLine();
        builder.AppendLine("- 실행본: `" + BoolJson(audit.hasGameBuild) + "`");
        builder.AppendLine("- 스크린샷: `" + BoolJson(audit.hasScreenshots) + "`");
        builder.AppendLine("- 플레이어 로그: `" + BoolJson(audit.hasPlayerLogs) + "`");
        builder.AppendLine("- 에이전트 로그: `" + BoolJson(audit.hasAgentLogs) + "`");
        builder.AppendLine("- 대시보드: `" + BoolJson(audit.hasDashboard) + "`");
        builder.AppendLine("- 보고서 Markdown: `" + BoolJson(audit.hasReportMarkdown) + "`");
        builder.AppendLine("- 보고서 PDF: `" + BoolJson(audit.hasReportPdf) + "`");
        builder.AppendLine("- 발표자료: `" + BoolJson(audit.hasPresentationDeck) + "`");
        builder.AppendLine("- 발표자료 PDF: `" + BoolJson(audit.hasPresentationPdf) + "`");
        builder.AppendLine("- GOAL 완료 감사: `" + BoolJson(audit.hasGoalCompletionAudit) + "`");
        builder.AppendLine("- AI 사용 로그: `" + BoolJson(audit.hasAiUsageLog) + "`");
        builder.AppendLine("- 윤리 문서: `" + BoolJson(audit.hasEthicsDocs) + "`");
        builder.AppendLine("- QA 증거: `" + BoolJson(audit.hasQaEvidence) + "`");
        builder.AppendLine("- 문서 로컬 절대경로 없음: `" + BoolJson(audit.filesHaveNoLocalAbsolutePath) + "`");
        builder.AppendLine();
        builder.AppendLine("## 체크 목록");
        builder.AppendLine();
        foreach (CourseSubmissionCheck check in audit.checks)
        {
            builder.AppendLine("- [" + (check.passed ? "x" : " ") + "] " + check.label + " - `" + check.evidence + "`" + (check.required ? "" : " (optional)"));
        }
        return builder.ToString();
    }

    private static void CopyStorePageDocument(string sourcePath, string storeFileName)
    {
        if (!File.Exists(sourcePath))
        {
            Debug.LogWarning("Steamworks store page source missing: " + sourcePath);
            return;
        }

        Directory.CreateDirectory(SteamworksStorePagePath);
        File.Copy(sourcePath, Path.Combine(SteamworksStorePagePath, storeFileName), true);
    }

    private static void CopyStorePageCandidateScreenshots()
    {
        if (Directory.Exists(SteamworksStorePageCandidateScreenshotsPath))
        {
            Directory.Delete(SteamworksStorePageCandidateScreenshotsPath, true);
        }

        Directory.CreateDirectory(SteamworksStorePageCandidateScreenshotsPath);

        foreach (string candidateFile in StorePageCandidateScreenshotFiles)
        {
            CopyStorePageCandidateScreenshot(candidateFile);
        }

        string sourceManifestPath = Path.Combine(MarketingRootPath, "screenshots", "store_screenshots_manifest.txt");
        if (File.Exists(sourceManifestPath))
        {
            File.Copy(sourceManifestPath, Path.Combine(SteamworksStorePageCandidateScreenshotsPath, "STORE_SCREENSHOTS_SOURCE_MANIFEST.txt"), true);
        }
        else
        {
            Debug.LogWarning("Steamworks store page screenshot manifest missing: " + sourceManifestPath);
        }

        string sourceHashManifestPath = Path.Combine(MarketingRootPath, "screenshots", "store_candidate_capture_sync_hashes.sha256");
        if (File.Exists(sourceHashManifestPath))
        {
            File.Copy(sourceHashManifestPath, Path.Combine(SteamworksStorePageCandidateScreenshotsPath, "STORE_CANDIDATE_CAPTURE_SYNC_HASHES.sha256"), true);
        }
        else
        {
            Debug.LogWarning("Steamworks store page candidate hash manifest missing: " + sourceHashManifestPath);
        }

        File.WriteAllText(Path.Combine(SteamworksStorePagePath, "SCREENSHOT_CANDIDATES_KO.md"), BuildStorePageScreenshotCandidateManifest(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksStorePagePath, "SCREENSHOT_CANDIDATE_DECISION_MATRIX_KO.md"), BuildStorePageScreenshotCandidateDecisionMatrix(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksStorePagePath, "SCREENSHOT_CANDIDATE_AB_TEST_KO.md"), BuildStorePageScreenshotCandidateAbTestManifest(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksStorePagePath, "SCREENSHOT_UPLOAD_SELECTION_KO.md"), BuildStorePageScreenshotUploadSelectionManifest(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksStorePagePath, "SCREENSHOT_UPLOAD_APPLICATION_KO.md"), BuildStorePageScreenshotUploadApplicationManifest(), new UTF8Encoding(false));
    }

    private static void CopyStoreCandidateCaptureHashManifest(string destinationPath)
    {
        string steamworksHashManifestPath = Path.Combine(SteamworksStorePageCandidateScreenshotsPath, "STORE_CANDIDATE_CAPTURE_SYNC_HASHES.sha256");
        string marketingHashManifestPath = Path.Combine(MarketingRootPath, "screenshots", "store_candidate_capture_sync_hashes.sha256");
        string sourcePath = File.Exists(steamworksHashManifestPath)
            ? steamworksHashManifestPath
            : marketingHashManifestPath;
        Directory.CreateDirectory(Path.GetDirectoryName(destinationPath));
        if (File.Exists(sourcePath))
        {
            File.Copy(sourcePath, destinationPath, true);
            return;
        }

        File.WriteAllText(
            destinationPath,
            "# STORE_CANDIDATE_CAPTURE_SYNC_HASHES.sha256 missing\nRun capture_store_candidate_screenshots_graphics_sync.ps1 before external handoff.\n",
            new UTF8Encoding(false));
    }

    private static void CopyStorePageCandidateScreenshot(string fileName)
    {
        string sourcePath = Path.Combine(MarketingRootPath, "screenshots", fileName);
        string targetPath = Path.Combine(SteamworksStorePageCandidateScreenshotsPath, fileName);
        if (!File.Exists(sourcePath))
        {
            Debug.LogWarning("Steamworks store page candidate screenshot missing: " + sourcePath);
            return;
        }

        File.Copy(sourcePath, targetPath, true);
    }

    private static bool StorePageCandidateScreenshotsReady()
    {
        if (!Directory.Exists(SteamworksStorePageCandidateScreenshotsPath))
        {
            return false;
        }

        foreach (string candidateFile in StorePageCandidateScreenshotFiles)
        {
            string path = Path.Combine(SteamworksStorePageCandidateScreenshotsPath, candidateFile);
            if (!File.Exists(path) || !PngDimensionsMatch(path, 1920, 1080))
            {
                return false;
            }
        }

        return true;
    }

    private static bool StorePageCandidateSourceManifestReady()
    {
        string sourceManifestCopy = Path.Combine(SteamworksStorePageCandidateScreenshotsPath, "STORE_SCREENSHOTS_SOURCE_MANIFEST.txt");
        if (!File.Exists(sourceManifestCopy))
        {
            return false;
        }

        foreach (string candidateFile in StorePageCandidateScreenshotFiles)
        {
            if (!FileContainsAll(sourceManifestCopy, candidateFile))
            {
                return false;
            }
        }

        return FileContainsAll(
            sourceManifestCopy,
            "10_achievement_next_goal.png",
            "achievement reward loop summary",
            "achievement record link hint visual check",
            "12_career_record_next_objective.png",
            "career record action hint visual check");
    }

    private static void WriteStoreCandidateCaptureSyncAssets()
    {
        Directory.CreateDirectory(MarketingScriptsPath);
        Directory.CreateDirectory(SteamworksStorePagePath);

        string script = BuildStoreCandidateCaptureSyncScript();
        string manifest = BuildStoreCandidateCaptureSyncManifest();
        string scriptPath = Path.Combine(MarketingScriptsPath, "capture_store_candidate_screenshots_graphics_sync.ps1");
        string manifestPath = Path.Combine(MarketingScriptsPath, "STORE_CANDIDATE_CAPTURE_SYNC_MANIFEST.md");
        File.WriteAllText(scriptPath, script, new UTF8Encoding(false));
        File.WriteAllText(manifestPath, manifest, new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksStorePagePath, "capture_store_candidate_screenshots_graphics_sync.ps1"), script, new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(SteamworksStorePagePath, "STORE_CANDIDATE_CAPTURE_SYNC_MANIFEST.md"), manifest, new UTF8Encoding(false));
    }

    private static string BuildStoreCandidateCaptureSyncScript()
    {
        StringBuilder builder = new();
        builder.AppendLine("param(");
        builder.AppendLine("    [string]$ProjectRoot = (Resolve-Path (Join-Path $PSScriptRoot '..\\..\\..\\..')).Path,");
        builder.AppendLine("    [string]$PlayerPath = (Join-Path $ProjectRoot 'Builds\\Release\\CareReviewOffice_Windows_v0.3.0\\CareReviewOffice.exe')");
        builder.AppendLine(")");
        builder.AppendLine("$ErrorActionPreference = 'Stop'");
        builder.AppendLine("$candidateFiles = @(");
        for (int i = 0; i < StorePageCandidateScreenshotFiles.Length; i++)
        {
            string suffix = i == StorePageCandidateScreenshotFiles.Length - 1 ? "" : ",";
            builder.AppendLine("    '" + StorePageCandidateScreenshotFiles[i] + "'" + suffix);
        }
        builder.AppendLine(")");
        builder.AppendLine("$officialRefreshFiles = @('08_career_record_filter.png')");
        builder.AppendLine("if (!(Test-Path $PlayerPath)) { throw ('Player build missing: ' + $PlayerPath) }");
        builder.AppendLine("$logPath = Join-Path $ProjectRoot 'Logs\\runtime_store_candidate_graphics_capture_sync.log'");
        builder.AppendLine("New-Item -ItemType Directory -Force -Path (Split-Path $logPath) | Out-Null");
        builder.AppendLine("& $PlayerPath -screen-width 1920 -screen-height 1080 -careReviewCaptureStoreScreenshots -logFile $logPath");
        builder.AppendLine("if ($null -ne $LASTEXITCODE -and $LASTEXITCODE -ne 0) { throw ('Store screenshot capture failed with exit code ' + $LASTEXITCODE) }");
        builder.AppendLine("$logBody = Get-Content $logPath -Raw");
        builder.AppendLine("$captureMatch = [regex]::Match($logBody, 'CARE_REVIEW_STORE_SCREENSHOTS_DONE path=(.+)')");
        builder.AppendLine("if (!$captureMatch.Success) { throw 'Capture log did not include CARE_REVIEW_STORE_SCREENSHOTS_DONE path.' }");
        builder.AppendLine("$sourceDir = $captureMatch.Groups[1].Value.Trim()");
        builder.AppendLine("if (!(Test-Path $sourceDir)) { throw ('Captured screenshot directory missing: ' + $sourceDir) }");
        builder.AppendLine("$marketingDir = Join-Path $ProjectRoot 'Builds\\Marketing\\v0.3.0\\screenshots'");
        builder.AppendLine("$steamworksDir = Join-Path $ProjectRoot 'Builds\\Steamworks\\v0.3.0\\store_page\\screenshot_candidates'");
        builder.AppendLine("New-Item -ItemType Directory -Force -Path $marketingDir | Out-Null");
        builder.AppendLine("New-Item -ItemType Directory -Force -Path $steamworksDir | Out-Null");
        builder.AppendLine("$syncedFiles = @()");
        builder.AppendLine("foreach ($officialFile in $officialRefreshFiles) {");
        builder.AppendLine("    $sourcePath = Join-Path $sourceDir $officialFile");
        builder.AppendLine("    if (!(Test-Path $sourcePath)) { throw ('Captured official screenshot missing: ' + $officialFile) }");
        builder.AppendLine("    Copy-Item -LiteralPath $sourcePath -Destination (Join-Path $marketingDir $officialFile) -Force");
        builder.AppendLine("    $syncedFiles += $officialFile");
        builder.AppendLine("}");
        builder.AppendLine("foreach ($candidateFile in $candidateFiles) {");
        builder.AppendLine("    $sourcePath = Join-Path $sourceDir $candidateFile");
        builder.AppendLine("    if (!(Test-Path $sourcePath)) { throw ('Captured candidate missing: ' + $candidateFile) }");
        builder.AppendLine("    Copy-Item -LiteralPath $sourcePath -Destination (Join-Path $marketingDir $candidateFile) -Force");
        builder.AppendLine("    Copy-Item -LiteralPath $sourcePath -Destination (Join-Path $steamworksDir $candidateFile) -Force");
        builder.AppendLine("    $syncedFiles += $candidateFile");
        builder.AppendLine("}");
        builder.AppendLine("$hashManifestPath = Join-Path $marketingDir 'store_candidate_capture_sync_hashes.sha256'");
        builder.AppendLine("$hashLines = foreach ($fileName in $syncedFiles) {");
        builder.AppendLine("    $filePath = Join-Path $marketingDir $fileName");
        builder.AppendLine("    $hash = (Get-FileHash -Algorithm SHA256 -LiteralPath $filePath).Hash.ToLowerInvariant()");
        builder.AppendLine("    $hash + '  ' + $fileName");
        builder.AppendLine("}");
        builder.AppendLine("$hashLines | Set-Content -LiteralPath $hashManifestPath -Encoding utf8");
        builder.AppendLine("Copy-Item -LiteralPath $hashManifestPath -Destination (Join-Path $steamworksDir 'STORE_CANDIDATE_CAPTURE_SYNC_HASHES.sha256') -Force");
        builder.AppendLine("$sourceManifest = Join-Path $sourceDir 'store_screenshots_manifest.txt'");
        builder.AppendLine("$requiredManifestTokens = @('achievement reward loop summary', 'achievement record link hint visual check', 'career record action hint visual check')");
        builder.AppendLine("$sourceManifestReady = $false");
        builder.AppendLine("for ($attempt = 0; $attempt -lt 20; $attempt++) {");
        builder.AppendLine("    if (Test-Path $sourceManifest) {");
        builder.AppendLine("        $sourceManifestBody = Get-Content $sourceManifest -Raw");
        builder.AppendLine("        $sourceManifestReady = $true");
        builder.AppendLine("        foreach ($token in $requiredManifestTokens) {");
        builder.AppendLine("            if (!$sourceManifestBody.Contains($token)) { $sourceManifestReady = $false; break }");
        builder.AppendLine("        }");
        builder.AppendLine("        if ($sourceManifestReady) { break }");
        builder.AppendLine("    }");
        builder.AppendLine("    Start-Sleep -Milliseconds 250");
        builder.AppendLine("}");
        builder.AppendLine("if (!$sourceManifestReady) { throw 'Captured source manifest did not include required UI hint QA tokens.' }");
        builder.AppendLine("if (Test-Path $sourceManifest) {");
        builder.AppendLine("    Copy-Item -LiteralPath $sourceManifest -Destination (Join-Path $marketingDir 'store_screenshots_manifest.txt') -Force");
        builder.AppendLine("    Copy-Item -LiteralPath $sourceManifest -Destination (Join-Path $steamworksDir 'STORE_SCREENSHOTS_SOURCE_MANIFEST.txt') -Force");
        builder.AppendLine("}");
        builder.AppendLine("Write-Host ('Synced ' + $candidateFiles.Count + ' store candidate screenshots and ' + $officialRefreshFiles.Count + ' official screenshot from ' + $sourceDir)");
        return builder.ToString();
    }

    private static string BuildStoreCandidateCaptureSyncManifest()
    {
        StringBuilder builder = new();
        builder.AppendLine("# Store Candidate Capture Sync");
        builder.AppendLine();
        builder.AppendLine("- Command: `scripts/capture_store_candidate_screenshots_graphics_sync.ps1`");
        builder.AppendLine("- Runtime arg: `-careReviewCaptureStoreScreenshots`");
        builder.AppendLine("- Capture mode: graphics/windowed 1920x1080");
        builder.AppendLine("- Runtime log: `Logs/runtime_store_candidate_graphics_capture_sync.log`");
        builder.AppendLine("- Marketing target: `Builds/Marketing/v0.3.0/screenshots`");
        builder.AppendLine("- Steamworks target: `Builds/Steamworks/v0.3.0/store_page/screenshot_candidates`");
        builder.AppendLine("- Official refresh: `08_career_record_filter.png`");
        builder.AppendLine("- Candidate count: " + StorePageCandidateScreenshotFiles.Length);
        builder.AppendLine("- Hash manifest: `store_candidate_capture_sync_hashes.sha256`");
        builder.AppendLine("- Manifest QA tokens: `achievement reward loop summary`, `achievement record link hint visual check`, `career record action hint visual check`");
        builder.AppendLine();
        builder.AppendLine("## Candidate Files");
        builder.AppendLine();
        foreach (string candidateFile in StorePageCandidateScreenshotFiles)
        {
            builder.AppendLine("- `" + candidateFile + "`");
        }

        return builder.ToString();
    }

    private static void CopyDirectory(string sourcePath, string targetPath)
    {
        Directory.CreateDirectory(targetPath);

        foreach (string filePath in Directory.GetFiles(sourcePath))
        {
            string targetFilePath = Path.Combine(targetPath, Path.GetFileName(filePath));
            File.Copy(filePath, targetFilePath, true);
        }

        foreach (string directoryPath in Directory.GetDirectories(sourcePath))
        {
            string targetDirectoryPath = Path.Combine(targetPath, Path.GetFileName(directoryPath));
            CopyDirectory(directoryPath, targetDirectoryPath);
        }
    }

