            new AchievementCandidate("CARE_RISK_SHIELD", "누락 위험 방어", "최종 누락 위험을 25 이하로 유지했습니다.", "finalMissedRisk <= 25"),
            new AchievementCandidate("CARE_EQUITY_GUARDIAN", "형평성 우선", "최종 형평성 지표를 90 이상으로 끌어올렸습니다.", "finalEquity >= 90"),
