            new AchievementCandidate("CARE_DECISION_PRACTICE_OBJECTIVE", "판단 비교 훈련", "사례 자료실 판단 비교표에서 비교 연습 회차를 시작해 완료했습니다.", "decisionPracticeObjectiveCompleted == true"),
            new AchievementCandidate("CARE_INVESTIGATION_FOLLOW_UP", "조사 후속 처리", "해금된 조사 메모가 다음 날 위험 완화로 반영된 캠페인을 완료했습니다.", "investigationFollowUpCount > 0"),
