    private static string BuildSteamUploadPreviewScript()
    {
        return
            "$ErrorActionPreference = 'Stop'\n" +
            "$steamCmd = 'C:\\steamcmd\\steamcmd.exe'\n" +
            "$scriptPath = Join-Path $PSScriptRoot 'app_build_" + PlaceholderSteamAppId + ".vdf'\n" +
            "Write-Host 'Replace placeholder AppID/DepotID in the VDF files before a real upload.'\n" +
            "Write-Host 'Preview mode is enabled by default: \"Preview\" \"1\".'\n" +
            "if (!(Test-Path $steamCmd)) { throw 'SteamCMD was not found at C:\\steamcmd\\steamcmd.exe. Update $steamCmd before running.' }\n" +
            "& $steamCmd +login STEAM_USERNAME +run_app_build_http $scriptPath +quit\n";
    }

    private static string BuildSteamConfigureIdsScript()
    {
        return
            "param(\n" +
            "    [Parameter(Mandatory=$true)][string]$AppId,\n" +
            "    [Parameter(Mandatory=$true)][string]$DepotId,\n" +
            "    [string]$SteamUsername = 'STEAM_USERNAME',\n" +
            "    [string]$SteamCmdPath = 'C:\\steamcmd\\steamcmd.exe',\n" +
            "    [switch]$DryRun\n" +
            ")\n" +
            "$ErrorActionPreference = 'Stop'\n" +
            "if ($AppId -notmatch '^\\d+$' -or $AppId -eq '" + PlaceholderSteamAppId + "') { throw 'AppId must be a real numeric Steam App ID.' }\n" +
            "if ($DepotId -notmatch '^\\d+$' -or $DepotId -eq '" + PlaceholderSteamDepotId + "') { throw 'DepotId must be a real numeric Windows Depot ID.' }\n" +
            "$appPath = Join-Path $PSScriptRoot 'app_build_" + PlaceholderSteamAppId + ".vdf'\n" +
            "$depotPath = Join-Path $PSScriptRoot 'depot_build_" + PlaceholderSteamDepotId + ".vdf'\n" +
            "$uploadPath = Join-Path $PSScriptRoot 'upload_preview_steamcmd.ps1'\n" +
            "foreach ($path in @($appPath, $depotPath, $uploadPath)) { if (!(Test-Path -LiteralPath $path)) { throw \"Required Steamworks script missing: $path\" } }\n" +
            "$newAppPath = Join-Path $PSScriptRoot ('app_build_' + $AppId + '.vdf')\n" +
            "$newDepotPath = Join-Path $PSScriptRoot ('depot_build_' + $DepotId + '.vdf')\n" +
            "$app = Get-Content -LiteralPath $appPath -Raw\n" +
            "$app = $app.Replace('\"AppID\" \"" + PlaceholderSteamAppId + "\"', ('\"AppID\" \"' + $AppId + '\"'))\n" +
            "$app = $app.Replace('\"" + PlaceholderSteamDepotId + "\" \"depot_build_" + PlaceholderSteamDepotId + ".vdf\"', ('\"' + $DepotId + '\" \"depot_build_' + $DepotId + '.vdf\"'))\n" +
            "$depot = Get-Content -LiteralPath $depotPath -Raw\n" +
            "$depot = $depot.Replace('\"DepotID\" \"" + PlaceholderSteamDepotId + "\"', ('\"DepotID\" \"' + $DepotId + '\"'))\n" +
            "$upload = Get-Content -LiteralPath $uploadPath -Raw\n" +
            "$upload = $upload.Replace(\"'app_build_" + PlaceholderSteamAppId + ".vdf'\", (\"'app_build_\" + $AppId + \".vdf'\"))\n" +
            "$upload = $upload.Replace('+login STEAM_USERNAME', ('+login ' + $SteamUsername))\n" +
            "$escapedSteamCmdPath = $SteamCmdPath.Replace(\"'\", \"''\")\n" +
            "$upload = $upload.Replace('$steamCmd = ''C:\\steamcmd\\steamcmd.exe''', ('$steamCmd = ''' + $escapedSteamCmdPath + ''''))\n" +
            "if ($DryRun) {\n" +
            "    Write-Host ('Dry run OK. Would write ' + (Split-Path -Leaf $newAppPath) + ' and ' + (Split-Path -Leaf $newDepotPath) + '.')\n" +
            "    exit 0\n" +
            "}\n" +
            "Set-Content -LiteralPath $newAppPath -Value $app -Encoding UTF8\n" +
            "Set-Content -LiteralPath $newDepotPath -Value $depot -Encoding UTF8\n" +
            "Set-Content -LiteralPath $uploadPath -Value $upload -Encoding UTF8\n" +
            "if ($newAppPath -ne $appPath) { Remove-Item -LiteralPath $appPath -Force }\n" +
            "if ($newDepotPath -ne $depotPath) { Remove-Item -LiteralPath $depotPath -Force }\n" +
            "Write-Host ('Steamworks VDF IDs configured. AppID=' + $AppId + ', DepotID=' + $DepotId + '.')\n" +
            "Write-Host ('Next: run upload_preview_steamcmd.ps1 and keep Preview set to 1 for the first SteamPipe check.')\n";
    }

