    private static string BuildTrailerUploadSelectionManifest()
    {
        string switchPath = Path.Combine(MarketingRootPath, "trailer", "trailer_remaster_upload_switch.md");
        string switchText = SafeReadAllText(switchPath);
        string submissionDraftPath = Path.Combine(SteamworksStorePagePath, "STORE_PAGE_SUBMISSION_DRAFT_KO.md");
        string submissionDraftText = SafeReadAllText(submissionDraftPath);
        return BuildTrailerUploadSelectionManifest(switchText, submissionDraftText);
    }

    private static string BuildTrailerUploadSelectionManifest(string switchText, string submissionDraftText)
    {
        string currentSelection = FirstNonEmpty(ExtractMarkdownField(switchText, "current_selection"), "current_upload");
        string currentFile = FirstNonEmpty(ExtractMarkdownField(switchText, "current_file"), "care_review_office_trailer_steam_upload_v0.3.0.mp4");
        string candidateFile = FirstNonEmpty(ExtractMarkdownField(switchText, "candidate_file"), "care_review_office_trailer_steam_upload_v0.3.0_remaster_upload.mp4");
        string rollbackFile = FirstNonEmpty(ExtractMarkdownField(switchText, "rollback_file"), currentFile);
        string candidateValidation = FirstNonEmpty(ExtractMarkdownField(switchText, "candidate_validation"), "unknown");
        bool candidateSelected = string.Equals(currentSelection, "remaster_upload_candidate", StringComparison.OrdinalIgnoreCase);
        string selectedFile = candidateSelected ? candidateFile : currentFile;
        string selectedRole = candidateSelected ? "remaster_upload_candidate" : "current_steam_upload";
        string selectedPath = Path.Combine(MarketingRootPath, "trailer", selectedFile);
        bool selectedFileExists = File.Exists(selectedPath);
        bool submissionSelectedFileMatch = ContainsOrdinalIgnoreCase(submissionDraftText, selectedFile);
        bool switchSelectionValid =
            string.Equals(currentSelection, "current_upload", StringComparison.OrdinalIgnoreCase) ||
            string.Equals(currentSelection, "remaster_upload_candidate", StringComparison.OrdinalIgnoreCase);
        bool candidateReadyForSelection = !candidateSelected || string.Equals(candidateValidation, "passed", StringComparison.OrdinalIgnoreCase);
        bool readyForSteamStoreUpload = switchSelectionValid && selectedFileExists && submissionSelectedFileMatch && candidateReadyForSelection;

        StringBuilder builder = new();
        builder.AppendLine("# 트레일러 업로드 선택 manifest");
        builder.AppendLine();
        builder.AppendLine("selection_source: trailer_remaster_upload_switch.md");
        builder.AppendLine("current_selection: " + currentSelection);
        builder.AppendLine("selected_role: " + selectedRole);
        builder.AppendLine("selected_file: " + selectedFile);
        builder.AppendLine("selected_bytes: " + (selectedFileExists ? new FileInfo(selectedPath).Length : 0L));
        builder.AppendLine("selected_sha256: " + (selectedFileExists ? ComputeSha256(selectedPath) : ""));
        builder.AppendLine("candidate_file: " + candidateFile);
        builder.AppendLine("candidate_validation: " + candidateValidation);
        builder.AppendLine("rollback_file: " + rollbackFile);
        builder.AppendLine("switch_selection_valid: " + (switchSelectionValid ? "yes" : "no"));
        builder.AppendLine("selected_file_exists: " + (selectedFileExists ? "yes" : "no"));
        builder.AppendLine("submission_selected_file_match: " + (submissionSelectedFileMatch ? "yes" : "no"));
        builder.AppendLine("ready_for_steam_store_upload: " + (readyForSteamStoreUpload ? "yes" : "no"));
        builder.AppendLine();
        builder.AppendLine("- `current_selection`이 `current_upload`이면 현재 고비트레이트 Steam 업로드 후보를 유지한다.");
        builder.AppendLine("- `current_selection`이 `remaster_upload_candidate`이면 리마스터 업로드 후보가 `candidate_validation: passed`이고 상점 제출안 파일명도 같은 후보로 바뀌어야 한다.");
        builder.AppendLine("- `submission_selected_file_match: no`이면 Store Presence 입력 전에 제출안과 switch를 먼저 맞춘다.");
        builder.AppendLine("- `rollback_file`은 전환 실패 시 복구 기준 파일이다.");
        return builder.ToString();
    }

    private static string WriteTrailerUploadSelectionRegressionSmoke()
    {
        Directory.CreateDirectory(StorePageQaPath);
        string currentFile = "care_review_office_trailer_steam_upload_v0.3.0.mp4";
        string candidateFile = "care_review_office_trailer_steam_upload_v0.3.0_remaster_upload.mp4";
        string currentSubmission = "업로드 후보 파일: `" + currentFile + "`";
        string candidateSubmission = "업로드 후보 파일: `" + candidateFile + "`";
        string currentSwitch = BuildTrailerUploadSelectionSwitchScenario("current_upload", "passed");
        string candidateSwitch = BuildTrailerUploadSelectionSwitchScenario("remaster_upload_candidate", "passed");
        string failedCandidateSwitch = BuildTrailerUploadSelectionSwitchScenario("remaster_upload_candidate", "failed");

        string currentManifest = BuildTrailerUploadSelectionManifest(currentSwitch, currentSubmission);
        string mismatchManifest = BuildTrailerUploadSelectionManifest(candidateSwitch, currentSubmission);
        string candidateManifest = BuildTrailerUploadSelectionManifest(candidateSwitch, candidateSubmission);
        string failedCandidateManifest = BuildTrailerUploadSelectionManifest(failedCandidateSwitch, candidateSubmission);
        string rollbackManifest = BuildTrailerUploadSelectionManifest(currentSwitch, currentSubmission);

        bool currentUploadReady =
            FileContainsAllText(currentManifest, "current_selection: current_upload", "selected_file: " + currentFile, "submission_selected_file_match: yes", "ready_for_steam_store_upload: yes");
        bool remasterMismatchBlocked =
            FileContainsAllText(mismatchManifest, "current_selection: remaster_upload_candidate", "selected_file: " + candidateFile, "submission_selected_file_match: no", "ready_for_steam_store_upload: no");
        bool remasterSyncedReady =
            FileContainsAllText(candidateManifest, "current_selection: remaster_upload_candidate", "selected_file: " + candidateFile, "candidate_validation: passed", "submission_selected_file_match: yes", "ready_for_steam_store_upload: yes");
        bool failedCandidateBlocked =
            FileContainsAllText(failedCandidateManifest, "current_selection: remaster_upload_candidate", "candidate_validation: failed", "submission_selected_file_match: yes", "ready_for_steam_store_upload: no");
        bool rollbackReady =
            FileContainsAllText(rollbackManifest, "current_selection: current_upload", "selected_file: " + currentFile, "rollback_file: " + currentFile, "ready_for_steam_store_upload: yes");
        bool filesHaveNoLocalAbsolutePath = !ContainsLocalAbsolutePath(currentManifest + mismatchManifest + candidateManifest + failedCandidateManifest + rollbackManifest);
        bool completed = currentUploadReady && remasterMismatchBlocked && remasterSyncedReady && failedCandidateBlocked && rollbackReady && filesHaveNoLocalAbsolutePath;
        string path = Path.Combine(StorePageQaPath, "care_review_trailer_upload_selection_regression.json");

        StringBuilder builder = new();
        builder.AppendLine("{");
        builder.AppendLine("  \"completed\": " + BoolJson(completed) + ",");
        builder.AppendLine("  \"scenarioCount\": 5,");
        builder.AppendLine("  \"currentUploadReady\": " + BoolJson(currentUploadReady) + ",");
        builder.AppendLine("  \"remasterMismatchBlocked\": " + BoolJson(remasterMismatchBlocked) + ",");
        builder.AppendLine("  \"remasterSyncedReady\": " + BoolJson(remasterSyncedReady) + ",");
        builder.AppendLine("  \"failedCandidateBlocked\": " + BoolJson(failedCandidateBlocked) + ",");
        builder.AppendLine("  \"rollbackReady\": " + BoolJson(rollbackReady) + ",");
        builder.AppendLine("  \"filesHaveNoLocalAbsolutePath\": " + BoolJson(filesHaveNoLocalAbsolutePath) + ",");
        builder.AppendLine("  \"currentFile\": \"" + EscapeJson(currentFile) + "\",");
        builder.AppendLine("  \"candidateFile\": \"" + EscapeJson(candidateFile) + "\"");
        builder.AppendLine("}");
        File.WriteAllText(path, builder.ToString(), new UTF8Encoding(false));
        return path;
    }

    private static string BuildTrailerUploadSelectionSwitchScenario(string currentSelection, string candidateValidation)
    {
        return
            "switch_id: trailer_remaster_upload_v0.3.0\n" +
            "current_selection: " + currentSelection + "\n" +
            "switch_state: ready_not_applied\n" +
            "current_file: care_review_office_trailer_steam_upload_v0.3.0.mp4\n" +
            "candidate_file: care_review_office_trailer_steam_upload_v0.3.0_remaster_upload.mp4\n" +
            "rollback_file: care_review_office_trailer_steam_upload_v0.3.0.mp4\n" +
            "candidate_validation: " + candidateValidation + "\n";
    }

    private static bool FileContainsAllText(string text, params string[] requiredTokens)
    {
        if (string.IsNullOrEmpty(text))
        {
            return false;
        }

        foreach (string token in requiredTokens)
        {
            if (!text.Contains(token))
            {
                return false;
            }
        }

        return true;
    }

    private static string ExtractMarkdownSection(string text, string startMarker, string endMarker)
    {
        if (string.IsNullOrEmpty(text))
        {
            return "";
        }

        int startIndex = text.IndexOf(startMarker, StringComparison.OrdinalIgnoreCase);
        if (startIndex < 0)
        {
            return "";
        }

        int endIndex = text.IndexOf(endMarker, startIndex + startMarker.Length, StringComparison.OrdinalIgnoreCase);
        if (endIndex < 0)
        {
            endIndex = text.Length;
        }

        return text.Substring(startIndex, endIndex - startIndex);
    }

    private static bool ContainsTokensInOrder(string text, params string[] tokens)
    {
        if (string.IsNullOrEmpty(text))
        {
            return false;
        }

        int searchIndex = 0;
        foreach (string token in tokens)
        {
            int tokenIndex = text.IndexOf(token, searchIndex, StringComparison.OrdinalIgnoreCase);
            if (tokenIndex < 0)
            {
                return false;
            }

            searchIndex = tokenIndex + token.Length;
        }

        return true;
    }

