            "이 폴더는 공식 상점 업로드 8장과 별도로, 실제 플레이테스터 피드백을 받은 뒤 공식 스크린샷 교체 후보로 비교할 내부 QA 자료를 보관한다. Steamworks 웹 콘솔에 바로 업로드하지 않고, Store Presence 검수 전 후보 판정에 사용한다.\n\n" +
            "## 후보 파일\n\n" +
            "| 파일 | 용도 | 판정 기준 |\n" +
            "| --- | --- | --- |\n" +
            "| `screenshot_candidates/10_achievement_next_goal.png` | 성과 다음 목표 로드맵/실행 버튼 후보 | 성과-캠페인 루프의 목표 실행 -> 캠페인 기록 -> 2/4/6 보상 누적 흐름이 한 화면에서 읽히는지 판정 |\n" +
            "| `screenshot_candidates/11_growth_follow_up_menu.png` | 성장 후속 목표 메인 메뉴 후보 | 후속 심사 버튼과 H 단축키가 상점 첫 장면에서도 반복 목표를 설명하는지 판정 |\n" +
            "| `screenshot_candidates/12_career_record_next_objective.png` | 캠페인 기록 목표 재시작/동일 사례 회고 후보 | 상세 줄바꿈 상태에서 캠페인 기록의 목표 재시작 -> 성과 기록 보상 누적 왕복 루프, 동일 사례 판단 변화, 브리핑 회고의 예고 위험/보상 대비 실제 결과가 선명한지 판정 |\n" +
            "| `screenshot_candidates/13_case_archive_appeal_remedy_history.png` | 사례 자료실 보정 이력 후보 | 원 사례에서 보정 완료 횟수, 성공률, 다음 재도전 목표가 한 화면에 읽히는지 판정 |\n" +
            "| `screenshot_candidates/14_case_archive_decision_audit_coaching_focus.png` | 사례 자료실 판단 복기 사례 버튼/기록 복귀/HUD 후보 | `복기 W-207`, `기록 복귀`, `판단 복기 진행 HUD`, `복기 왕복 힌트`, `reviewHudUpdatesAfterDecision=true`가 한 화면에서 읽히는지 판정 |\n\n" +
            "## 사용 규칙\n\n" +
            "- 공식 8장 업로드 세트는 `Builds/Marketing/v0.3.0/screenshots/01`-`08` 흐름을 기본으로 유지한다.\n" +
            "- `10_achievement_next_goal.png`, `11_growth_follow_up_menu.png`, `12_career_record_next_objective.png`, `13_case_archive_appeal_remedy_history.png`, `14_case_archive_decision_audit_coaching_focus.png`는 후보 스크린샷 5장으로 보관한다.\n" +
            "- `10_achievement_next_goal.png`와 `12_career_record_next_objective.png`는 성과 기록의 목표 실행과 캠페인 기록의 목표 재시작이 같은 성과-캠페인 루프인지 함께 판정한다.\n" +
            "- `14_case_archive_decision_audit_coaching_focus.png`는 복기 사례 버튼, 기록 복귀 왕복, 판단 복기 진행 HUD를 확인하는 보조 후보로, 상점 첫 장면보다 반복 목표/자료실 깊이를 보여 줄 때만 공식 8장 교체 후보로 판정한다.\n" +
            "- 후보 승격은 실제 플레이테스터 설문, 상점 캡처 가독성, Steam 캡슐/트레일러와의 중복 여부를 확인한 뒤 결정한다.\n" +
            "- 원본 캡처 manifest 사본은 `screenshot_candidates/STORE_SCREENSHOTS_SOURCE_MANIFEST.txt`에 둔다.\n";
    }

    private static string BuildStorePageScreenshotCandidateDecisionMatrix()
    {
        string aggregateJson = SafeReadAllText("Builds/QA/v0.3.0/playtest_packet/care_review_playtest_aggregate.json");
        string commercialTriageJson = SafeReadAllText(Path.Combine(PlaytestCollectionAuditPath, "care_review_playtest_commercial_triage.json"));
        string collectionAuditJson = SafeReadAllText(Path.Combine(PlaytestCollectionAuditPath, "care_review_playtest_collection_audit_summary.json"));
        return BuildStorePageScreenshotCandidateDecisionMatrix(aggregateJson, commercialTriageJson, collectionAuditJson);
    }

    private static string BuildStorePageScreenshotCandidateAbTestManifest()
    {
        string commercialTriageJson = SafeReadAllText(Path.Combine(PlaytestCollectionAuditPath, "care_review_playtest_commercial_triage.json"));
        string collectionAuditJson = SafeReadAllText(Path.Combine(PlaytestCollectionAuditPath, "care_review_playtest_collection_audit_summary.json"));
        return BuildStorePageScreenshotCandidateAbTestManifest(commercialTriageJson, collectionAuditJson);
    }

    private static string BuildStorePageScreenshotCandidateAbTestManifest(string commercialTriageJson, string collectionAuditJson)
    {
        int externalCompleteSessionCount = FirstNonZero(ExtractJsonInt(commercialTriageJson, "completeHumanSessionCount"), ExtractJsonInt(collectionAuditJson, "externalCompleteSessionCount"));
        int recommendedHumanMinimum = FirstNonZero(ExtractJsonInt(commercialTriageJson, "recommendedHumanMinimum"), ExtractJsonInt(collectionAuditJson, "recommendedHumanMinimum"));
        int abTestSessionCount = FirstNonZero(ExtractJsonInt(commercialTriageJson, "screenshotAbTestSessionCount"), ExtractJsonInt(collectionAuditJson, "screenshotAbTestSessionCount"));
        int careerRestartPreferenceCount = FirstNonZero(ExtractJsonInt(commercialTriageJson, "careerRecordRestartCandidatePreferenceCount"), ExtractJsonInt(collectionAuditJson, "careerRecordRestartCandidatePreferenceCount"));
        int appealHistoryPreferenceCount = FirstNonZero(ExtractJsonInt(commercialTriageJson, "appealRemedyHistoryCandidatePreferenceCount"), ExtractJsonInt(collectionAuditJson, "appealRemedyHistoryCandidatePreferenceCount"));
        bool screenshotAbLoopSummaryReady = ExtractJsonBool(collectionAuditJson, "screenshotAbLoopAggregateSummaryReady");
        int screenshotAbLoopQuestionIdCount = ExtractJsonInt(collectionAuditJson, "screenshotAbLoopQuestionIdCount");
        int screenshotAbLoopResponseCount = ExtractJsonInt(collectionAuditJson, "screenshotAbLoopResponseCount");
        int screenshotAbLoopNotCollectedCount = ExtractJsonInt(collectionAuditJson, "screenshotAbLoopNotCollectedCount");
        int screenshotAbLoopAchievementPreferenceCount = ExtractJsonInt(collectionAuditJson, "screenshotAbLoopAchievementNextGoalPreferenceCount");
        int screenshotAbLoopCareerPreferenceCount = ExtractJsonInt(collectionAuditJson, "screenshotAbLoopCareerRecordPreferenceCount");
        int screenshotAbLoopBothClearPreferenceCount = ExtractJsonInt(collectionAuditJson, "screenshotAbLoopBothClearPreferenceCount");
        int screenshotAbLoopBothUnclearPreferenceCount = ExtractJsonInt(collectionAuditJson, "screenshotAbLoopBothUnclearPreferenceCount");
        int screenshotAbLoopUnderstandingCommentCount = ExtractJsonInt(collectionAuditJson, "screenshotAbLoopUnderstandingCommentCount");
        bool enoughExternalSignal = recommendedHumanMinimum > 0 && externalCompleteSessionCount >= recommendedHumanMinimum;
        bool enoughAbTestSignal = recommendedHumanMinimum > 0 && abTestSessionCount >= recommendedHumanMinimum;
        bool abTestReady = enoughExternalSignal && enoughAbTestSignal;
        bool loopUnderstandingReady = screenshotAbLoopSummaryReady && recommendedHumanMinimum > 0 && screenshotAbLoopResponseCount >= recommendedHumanMinimum;
        string defaultCandidate = "12_career_record_next_objective.png";
        string comparisonCandidate = "13_case_archive_appeal_remedy_history.png";
        string recommendedCandidate = abTestReady && appealHistoryPreferenceCount > careerRestartPreferenceCount
            ? comparisonCandidate
            : defaultCandidate;
        string recommendationReason = abTestReady
            ? "외부 A/B " + abTestSessionCount + "/" + recommendedHumanMinimum + "명, 목표 재시작 선호 " + careerRestartPreferenceCount + ", 보정 이력 선호 " + appealHistoryPreferenceCount
            : "외부 A/B 회수 " + abTestSessionCount + "/" + recommendedHumanMinimum + " 또는 실제 사람 완전 회수 " + externalCompleteSessionCount + "/" + recommendedHumanMinimum + " 기준 미충족";
        string loopCollectionStatus = loopUnderstandingReady
            ? "ready_for_loop_understanding_review"
            : "waiting_for_screenshot_ab_loop_responses";

        StringBuilder builder = new();
        builder.AppendLine("# 상점 후보 스크린샷 A/B 판정 manifest");
        builder.AppendLine();
        builder.AppendLine("selection_source: SCREENSHOT_CANDIDATE_DECISION_MATRIX_KO.md");
        builder.AppendLine("default_candidate: " + defaultCandidate);
        builder.AppendLine("comparison_candidate: " + comparisonCandidate);
        builder.AppendLine("main_menu_baseline_candidate: 01_main_menu.png");
        builder.AppendLine("main_menu_baseline_question_id: main_menu_loop_entry");
        builder.AppendLine("copy_alignment_question_id: achievement_career_copy_alignment");
        builder.AppendLine("menu_briefing_weakness_candidate: 01_main_menu.png");
        builder.AppendLine("menu_briefing_weakness_question_id: menu_campaign_briefing_weakness");
        builder.AppendLine("external_complete_sessions: " + externalCompleteSessionCount);
        builder.AppendLine("recommended_human_minimum: " + recommendedHumanMinimum);
        builder.AppendLine("screenshot_ab_test_sessions: " + abTestSessionCount);
        builder.AppendLine("career_restart_preference_count: " + careerRestartPreferenceCount);
        builder.AppendLine("appeal_history_preference_count: " + appealHistoryPreferenceCount);
        builder.AppendLine("ab_test_ready: " + (abTestReady ? "yes" : "no_requires_external_feedback"));
        builder.AppendLine("recommended_candidate: " + recommendedCandidate);
        builder.AppendLine("recommendation_reason: " + recommendationReason);
        builder.AppendLine("screenshot_ab_loop_summary_ready: " + (screenshotAbLoopSummaryReady ? "yes" : "no"));
        builder.AppendLine("screenshot_ab_loop_question_rows: " + screenshotAbLoopQuestionIdCount);
        builder.AppendLine("screenshot_ab_loop_response_count: " + screenshotAbLoopResponseCount);
        builder.AppendLine("screenshot_ab_loop_not_collected_count: " + screenshotAbLoopNotCollectedCount);
        builder.AppendLine("screenshot_ab_loop_achievement_preference_count: " + screenshotAbLoopAchievementPreferenceCount);
        builder.AppendLine("screenshot_ab_loop_career_preference_count: " + screenshotAbLoopCareerPreferenceCount);
        builder.AppendLine("screenshot_ab_loop_both_clear_preference_count: " + screenshotAbLoopBothClearPreferenceCount);
        builder.AppendLine("screenshot_ab_loop_both_unclear_preference_count: " + screenshotAbLoopBothUnclearPreferenceCount);
        builder.AppendLine("screenshot_ab_loop_understanding_comment_count: " + screenshotAbLoopUnderstandingCommentCount);
        builder.AppendLine("screenshot_ab_loop_collection_status: " + loopCollectionStatus);
        builder.AppendLine();
        builder.AppendLine("## 비교 기준");
        builder.AppendLine();
        builder.AppendLine("- `12_career_record_next_objective.png`는 완료 기록에서 다음 목표를 다시 시작하는 장기 반복 루프와 `브리핑 회고`의 예고 위험/보상 대비 실제 결과를 보여주는 기본 승격 후보로 유지한다.");
        builder.AppendLine("- `13_case_archive_appeal_remedy_history.png`는 원 사례에서 보정 이력, 성공률, 다음 재도전 목표가 더 잘 읽힌다는 외부 피드백이 쌓일 때 교체 후보로 올린다.");
        builder.AppendLine("- `01_main_menu.png`는 메인 메뉴 성과 배지, `성과 보기` 버튼, 추천 회차 브리핑, `직전 약점 · 보정 초점` 줄, 다음 목표 힌트가 첫 화면에서 장기 반복 루프 진입점으로 읽히는지 확인하는 기준 화면으로 유지한다.");
        builder.AppendLine("- 공식 8장 교체는 `ab_test_ready: yes` 이후에만 검토하며, 준비 전에는 `SCREENSHOT_UPLOAD_SELECTION_KO.md`의 현재 공식 8장 유지를 우선한다.");
        builder.AppendLine();
        builder.AppendLine("## 성과-캠페인 루프 이해도 질문");
        builder.AppendLine();
        builder.AppendLine("- A/B 질문: `10_achievement_next_goal.png`와 `12_career_record_next_objective.png`를 비교했을 때 목표 실행 -> 캠페인 기록 -> 2/4/6 보상 누적 흐름이 어느 쪽에서 더 빨리 이해되는가?");
        builder.AppendLine("- 선택지: `10_achievement_next_goal.png`, `12_career_record_next_objective.png`, `둘 다 이해됨`, `둘 다 불명확`");
        builder.AppendLine("- 기록 기준: 실제 플레이테스터 코멘트에 성과 기록, 캠페인 기록, 다음 목표 재시작, 보상 누적 중 2개 이상이 함께 언급되면 루프 이해 코멘트로 집계한다.");
        builder.AppendLine("- 판정 적용: 루프 이해 코멘트가 " + recommendedHumanMinimum + "명 이상 쌓이면 `SCREENSHOT_CANDIDATE_DECISION_MATRIX_KO.md`의 승격 우선순위와 함께 다시 검토한다.");
        builder.AppendLine();
        builder.AppendLine("## 메인 메뉴 기준 화면 이해도 질문");
        builder.AppendLine();
        builder.AppendLine("- 질문 ID: `main_menu_loop_entry`");
        builder.AppendLine("- A/B 질문: `01_main_menu.png`와 `12_career_record_next_objective.png`를 비교했을 때 메인 메뉴의 성과 배지, `성과 보기` 버튼, 다음 목표 힌트가 장기 반복 루프 진입점으로 먼저 이해되는가?");
        builder.AppendLine("- 선택지: `01_main_menu.png`, `12_career_record_next_objective.png`, `둘 다 이해됨`, `둘 다 불명확`");
        builder.AppendLine("- 기록 기준: 실제 플레이테스터 코멘트에 메인 메뉴 성과 보기, 다음 목표 힌트, 캠페인 기록 재시작 중 2개 이상이 함께 언급되면 메인 메뉴 기준 화면 이해 코멘트로 집계한다.");
        builder.AppendLine("- 판정 적용: `01_main_menu.png`가 이해도에서 밀리면 공식 기준 화면 유지 조건을 다시 검토하고, 유지하려면 메인 메뉴 성과 힌트/상태 박스를 추가 보강한다.");
        builder.AppendLine();
        builder.AppendLine("## 메인 메뉴 추천 회차 브리핑/직전 약점 보정 초점 질문");
        builder.AppendLine();
        builder.AppendLine("- 질문 ID: `menu_campaign_briefing_weakness`");
        builder.AppendLine("- A/B 질문: `01_main_menu.png`의 추천 회차 브리핑과 `직전 약점 · 보정 초점` 줄이 다음 회차 목표, 위험, 보상 이유를 먼저 이해시키는가?");
        builder.AppendLine("- 선택지: `명확함`, `보정 초점은 좋지만 목표가 불명확`, `목표는 보이지만 보정 초점이 불명확`, `둘 다 불명확`");
        builder.AppendLine("- 집계 연결: `care_review_playtest_aggregate_smoke_result.json`의 `csvHasMenuBriefingWeaknessQuestion=true`와 메인 메뉴 스모크의 `briefingMentionsPreviousWeakness=true`, `briefingUsesCoachingWeaknessTerms=true`, `briefingWeaknessFocusCaptionReadable=true`, `briefingContrastEffectApplied=true`, `changedBriefingKeepsPreviousWeakness=true`, `changedBriefingKeepsCoachingWeaknessTerms=true`, `changedBriefingKeepsWeaknessFocusCaption=true`를 Store Presence 입력 전 대조한다.");
        builder.AppendLine("- 보강 조건: 플레이테스터가 `직전 약점 · 보정 초점`을 다음 목표 추천 근거로 읽지 못하면 메인 메뉴 브리핑 문구, 상점 캡션, `12_career_record_next_objective.png` 설명을 함께 보정한다.");
        builder.AppendLine();
        builder.AppendLine("## 성과 목표 힌트/기록 다음 목표 문구 일치");
        builder.AppendLine();
        builder.AppendLine("- 질문 ID: `achievement_career_copy_alignment`");
        builder.AppendLine("- 수동 확인: 메인 메뉴 `성과 보기 목표` 힌트, 성과 기록의 다음 목표 안내, 캠페인 기록 `다음 목표`/`목표 재시작` 버튼이 같은 장기 반복 행동으로 읽히는지 확인한다.");
        builder.AppendLine("- 집계 연결: `care_review_playtest_aggregate_smoke_result.json`의 `csvHasAchievementCareerCopyAlignmentQuestion=true`와 메인 메뉴 스모크의 `menuAchievementHintCareerNextGoalCopyAligned=true`를 Store Presence 입력 전 대조한다.");
        builder.AppendLine("- 보강 조건: 플레이테스터가 성과 힌트와 캠페인 기록 다음 목표를 서로 다른 행동으로 이해하면, `성과 보기` 버튼 라벨/힌트와 `12_career_record_next_objective.png` 캡션을 함께 보정한다.");
        builder.AppendLine();
        builder.AppendLine("## 성과-캠페인 루프 A/B 회수 집계");
        builder.AppendLine();
        builder.AppendLine("- 회수 감사 출처: `care_review_playtest_collection_audit_summary.json`");
        builder.AppendLine("- 질문 ID 행: " + screenshotAbLoopQuestionIdCount + "건");
        builder.AppendLine("- 응답 회수: " + screenshotAbLoopResponseCount + "/" + recommendedHumanMinimum + "건");
        builder.AppendLine("- 미회수: " + screenshotAbLoopNotCollectedCount + "건");
        builder.AppendLine("- 선호 후보: `10_achievement_next_goal.png` " + screenshotAbLoopAchievementPreferenceCount + "건, `12_career_record_next_objective.png` " + screenshotAbLoopCareerPreferenceCount + "건, 둘 다 이해됨 " + screenshotAbLoopBothClearPreferenceCount + "건, 둘 다 불명확 " + screenshotAbLoopBothUnclearPreferenceCount + "건");
        builder.AppendLine("- 이해 코멘트: " + screenshotAbLoopUnderstandingCommentCount + "건");
        builder.AppendLine("- 판정 상태: " + loopCollectionStatus);
        return builder.ToString();
    }

    private static string BuildStorePageScreenshotUploadSelectionManifest()
    {
        string aggregateJson = SafeReadAllText("Builds/QA/v0.3.0/playtest_packet/care_review_playtest_aggregate.json");
        string commercialTriageJson = SafeReadAllText(Path.Combine(PlaytestCollectionAuditPath, "care_review_playtest_commercial_triage.json"));
        string collectionAuditJson = SafeReadAllText(Path.Combine(PlaytestCollectionAuditPath, "care_review_playtest_collection_audit_summary.json"));
        return BuildStorePageScreenshotUploadSelectionManifest(aggregateJson, commercialTriageJson, collectionAuditJson);
    }

    private static string BuildStorePageScreenshotUploadSelectionManifest(string aggregateJson, string commercialTriageJson, string collectionAuditJson)
    {
        int externalCompleteSessionCount = FirstNonZero(ExtractJsonInt(commercialTriageJson, "completeHumanSessionCount"), ExtractJsonInt(collectionAuditJson, "externalCompleteSessionCount"));
        int recommendedHumanMinimum = FirstNonZero(ExtractJsonInt(commercialTriageJson, "recommendedHumanMinimum"), ExtractJsonInt(collectionAuditJson, "recommendedHumanMinimum"));
        int recommendedCommercialMinimum = FirstNonZero(ExtractJsonInt(commercialTriageJson, "recommendedCommercialMinimum"), ExtractJsonInt(collectionAuditJson, "recommendedCommercialMinimum"));
        int surveySessionCount = ExtractJsonInt(aggregateJson, "surveySessionCount");
        float averageReplayRewardValueRating = ExtractJsonFloat(aggregateJson, "averageReplayRewardValueRating");
        float averageUiReadabilityRating = ExtractJsonFloat(aggregateJson, "averageUiReadabilityRating");
        bool balanceReady = recommendedHumanMinimum > 0 && externalCompleteSessionCount >= recommendedHumanMinimum;
        bool commercialReady = recommendedCommercialMinimum > 0 && externalCompleteSessionCount >= recommendedCommercialMinimum;
        bool feedbackSupportsPromotion = averageReplayRewardValueRating >= 3.7f && averageUiReadabilityRating >= 3.5f;
        bool promotionReady = balanceReady && feedbackSupportsPromotion;
        string promotionStatus = commercialReady
            ? "commercial_ready_candidate"
            : promotionReady
                ? "balance_ready_candidate"
                : "not_promoted";
        string selectedUploadSet = promotionReady ? "promoted_candidate_set" : "current_official_8";
        string replacementTarget = promotionReady ? "01_main_menu.png" : "";
        string promotedCandidate = promotionReady ? "12_career_record_next_objective.png" : "";
        string promotionReason = promotionReady
            ? "외부 완전 회수 " + externalCompleteSessionCount + "/" + recommendedHumanMinimum + ", 반복 가치 " + FormatFloat(averageReplayRewardValueRating) + "/5, UI " + FormatFloat(averageUiReadabilityRating) + "/5 기준 충족"
            : "외부 완전 회수 " + externalCompleteSessionCount + "/" + recommendedHumanMinimum + " 기준 미충족 또는 반복/UI 신호 부족";

        StringBuilder builder = new();
        builder.AppendLine("# 상점 스크린샷 업로드 선택 manifest");
        builder.AppendLine();
        builder.AppendLine("selection_source: SCREENSHOT_CANDIDATE_DECISION_MATRIX_KO.md");
        builder.AppendLine("current_official_count: 8");
        builder.AppendLine("candidate_count: 5");
        builder.AppendLine("survey_session_count: " + surveySessionCount);
        builder.AppendLine("external_complete_sessions: " + externalCompleteSessionCount);
        builder.AppendLine("recommended_human_minimum: " + recommendedHumanMinimum);
        builder.AppendLine("recommended_commercial_minimum: " + recommendedCommercialMinimum);
        builder.AppendLine("promotion_status: " + promotionStatus);
        builder.AppendLine("selected_upload_set: " + selectedUploadSet);
        builder.AppendLine("promoted_candidate: " + promotedCandidate);
        builder.AppendLine("replacement_target: " + replacementTarget);
        builder.AppendLine("promotion_reason: " + promotionReason);
        builder.AppendLine("submission_update_required: " + (promotionReady ? "yes" : "no"));
        builder.AppendLine("ready_for_store_presence_upload: " + (promotionReady ? "yes_after_submission_update" : "yes_current_official_8"));
        builder.AppendLine();
        builder.AppendLine("## 현재 공식 8장");
        builder.AppendLine();
        builder.AppendLine("1. `02_case_review.png`");
        builder.AppendLine("2. `03_decision_feedback.png`");
        builder.AppendLine("3. `04_day_transition.png`");
        builder.AppendLine("4. `05_final_report.png`");
        builder.AppendLine("5. `08_career_record_filter.png`");
        builder.AppendLine("6. `07_agent_analysis.png`");
        builder.AppendLine("7. `06_ending_gallery.png`");
        builder.AppendLine("8. `01_main_menu.png`");
        builder.AppendLine();
        builder.AppendLine("## 승격 시 공식 8장 후보");
        builder.AppendLine();
        builder.AppendLine("1. `02_case_review.png`");
        builder.AppendLine("2. `03_decision_feedback.png`");
        builder.AppendLine("3. `04_day_transition.png`");
        builder.AppendLine("4. `05_final_report.png`");
        builder.AppendLine("5. `12_career_record_next_objective.png`");
        builder.AppendLine("6. `08_career_record_filter.png`");
        builder.AppendLine("7. `07_agent_analysis.png`");
        builder.AppendLine("8. `06_ending_gallery.png`");
        builder.AppendLine();
        builder.AppendLine("- `not_promoted` 상태에서는 현재 공식 8장을 유지하고 후보 5장은 내부 비교 자료로 둔다.");
        builder.AppendLine("- `balance_ready_candidate` 이상이면 `12_career_record_next_objective.png`를 `01_main_menu.png` 대신 넣는 상점 제출안 갱신이 필요하다.");
        builder.AppendLine("- `commercial_ready_candidate`는 10명 이상 외부 완전 회수 후 같은 승격 후보를 상용화 판단 자료로 사용할 수 있음을 뜻한다.");
        return builder.ToString();
    }

    private static string BuildStorePageScreenshotUploadApplicationManifest()
    {
        string selectionManifest = SafeReadAllText(Path.Combine(SteamworksStorePagePath, "SCREENSHOT_UPLOAD_SELECTION_KO.md"));
        string submissionDraft = SafeReadAllText(Path.Combine(SteamworksStorePagePath, "STORE_PAGE_SUBMISSION_DRAFT_KO.md"));
        return BuildStorePageScreenshotUploadApplicationManifest(selectionManifest, submissionDraft);
    }

    private static string BuildStorePageScreenshotUploadApplicationManifest(string selectionManifest, string submissionDraft)
    {
        string selectedUploadSet = FirstNonEmpty(ExtractMarkdownField(selectionManifest, "selected_upload_set"), "current_official_8");
        string promotionStatus = FirstNonEmpty(ExtractMarkdownField(selectionManifest, "promotion_status"), "not_promoted");
        string promotedCandidate = ExtractMarkdownField(selectionManifest, "promoted_candidate");
        string replacementTarget = ExtractMarkdownField(selectionManifest, "replacement_target");
        string submissionUpdateRequired = FirstNonEmpty(ExtractMarkdownField(selectionManifest, "submission_update_required"), "no");
        string officialSection = ExtractMarkdownSection(submissionDraft, "## 11. 스크린샷 업로드 순서", "### QA 후보 스크린샷");
        string[] currentOfficialSet = new[]
        {
            "02_case_review.png",
            "03_decision_feedback.png",
            "04_day_transition.png",
            "05_final_report.png",
            "08_career_record_filter.png",
            "07_agent_analysis.png",
            "06_ending_gallery.png",
            "01_main_menu.png"
        };
        string[] promotedSet = new[]
        {
            "02_case_review.png",
            "03_decision_feedback.png",
            "04_day_transition.png",
            "05_final_report.png",
            "12_career_record_next_objective.png",
            "08_career_record_filter.png",
            "07_agent_analysis.png",
            "06_ending_gallery.png"
        };
        bool currentOrderMatches = ContainsTokensInOrder(officialSection, currentOfficialSet);
        bool promotedOrderMatches = ContainsTokensInOrder(officialSection, promotedSet);
        bool selectedRequiresPromotedSet = string.Equals(selectedUploadSet, "promoted_candidate_set", StringComparison.OrdinalIgnoreCase);
        bool submissionMatchesSelectedSet = selectedRequiresPromotedSet ? promotedOrderMatches : currentOrderMatches;
        bool promotedCandidateApplied = !selectedRequiresPromotedSet || officialSection.Contains("12_career_record_next_objective.png");
        bool replacementRemoved = !selectedRequiresPromotedSet || !officialSection.Contains("01_main_menu.png");
        bool rollbackMatchesCurrentSet = currentOrderMatches && !selectedRequiresPromotedSet;
        bool readyForStorePresenceUpload = submissionMatchesSelectedSet && promotedCandidateApplied && replacementRemoved;

        StringBuilder builder = new();
        builder.AppendLine("# 상점 스크린샷 업로드 적용 manifest");
        builder.AppendLine();
        builder.AppendLine("application_source: STORE_PAGE_SUBMISSION_DRAFT_KO.md");
        builder.AppendLine("selection_source: SCREENSHOT_UPLOAD_SELECTION_KO.md");
        builder.AppendLine("promotion_status: " + promotionStatus);
        builder.AppendLine("selected_upload_set: " + selectedUploadSet);
        builder.AppendLine("promoted_candidate: " + promotedCandidate);
        builder.AppendLine("replacement_target: " + replacementTarget);
        builder.AppendLine("submission_update_required: " + submissionUpdateRequired);
        builder.AppendLine("current_official_order_matches: " + (currentOrderMatches ? "yes" : "no"));
        builder.AppendLine("promoted_order_matches: " + (promotedOrderMatches ? "yes" : "no"));
        builder.AppendLine("submission_matches_selected_set: " + (submissionMatchesSelectedSet ? "yes" : "no"));
        builder.AppendLine("promoted_candidate_applied: " + (promotedCandidateApplied ? "yes" : "no"));
        builder.AppendLine("replacement_removed: " + (replacementRemoved ? "yes" : "no"));
        builder.AppendLine("rollback_matches_current_set: " + (rollbackMatchesCurrentSet ? "yes" : "no"));
        builder.AppendLine("ready_for_store_presence_upload: " + (readyForStorePresenceUpload ? "yes" : "no"));
        builder.AppendLine();
        builder.AppendLine("- 현재 선택이 `current_official_8`이면 제출안의 공식 업로드 순서는 기존 8장과 일치해야 한다.");
        builder.AppendLine("- 선택이 `promoted_candidate_set`이면 제출안 공식 업로드 순서에 `12_career_record_next_objective.png`가 포함되고 `01_main_menu.png`는 제거되어야 한다.");
        builder.AppendLine("- 후보 섹션은 검사 대상이 아니며, `## 11. 스크린샷 업로드 순서`의 공식 8장 구간만 판정한다.");
        return builder.ToString();
    }

    private static string BuildStorePageScreenshotCandidateDecisionMatrix(string aggregateJson, string commercialTriageJson, string collectionAuditJson)
    {
        int surveySessionCount = ExtractJsonInt(aggregateJson, "surveySessionCount");
        int sessionCount = ExtractJsonInt(aggregateJson, "sessionCount");
        int replayIntentCount = ExtractJsonInt(aggregateJson, "replayIntentCount");
        float averagePriceValueRating = ExtractJsonFloat(aggregateJson, "averagePriceValueRating");
        float averageReplayRewardValueRating = ExtractJsonFloat(aggregateJson, "averageReplayRewardValueRating");
        float averageUiReadabilityRating = ExtractJsonFloat(aggregateJson, "averageUiReadabilityRating");
        float replayIntentPercent = surveySessionCount > 0 ? replayIntentCount * 100f / surveySessionCount : 0f;
        int externalCompleteSessionCount = FirstNonZero(ExtractJsonInt(commercialTriageJson, "completeHumanSessionCount"), ExtractJsonInt(collectionAuditJson, "externalCompleteSessionCount"));
        int externalSurveySessionCount = ExtractJsonInt(commercialTriageJson, "externalSurveySessionCount");
        int qaSurveySessionCount = ExtractJsonInt(commercialTriageJson, "qaSurveySessionCount");
        int totalTriageSurveySessionCount = FirstNonZero(ExtractJsonInt(commercialTriageJson, "totalSurveySessionCount"), ExtractJsonInt(collectionAuditJson, "surveySessionCount"));
        int recommendedHumanMinimum = FirstNonZero(ExtractJsonInt(commercialTriageJson, "recommendedHumanMinimum"), ExtractJsonInt(collectionAuditJson, "recommendedHumanMinimum"));
        int recommendedCommercialMinimum = FirstNonZero(ExtractJsonInt(commercialTriageJson, "recommendedCommercialMinimum"), ExtractJsonInt(collectionAuditJson, "recommendedCommercialMinimum"));
        int screenshotAbLoopResponseCount = ExtractJsonInt(collectionAuditJson, "screenshotAbLoopResponseCount");
        int screenshotAbLoopUnderstandingCommentCount = ExtractJsonInt(collectionAuditJson, "screenshotAbLoopUnderstandingCommentCount");
        int screenshotAbLoopCareerPreferenceCount = ExtractJsonInt(collectionAuditJson, "screenshotAbLoopCareerRecordPreferenceCount");
        int screenshotAbLoopBothClearPreferenceCount = ExtractJsonInt(collectionAuditJson, "screenshotAbLoopBothClearPreferenceCount");
        string triageEvidenceScope = FirstNonEmpty(ExtractJsonString(commercialTriageJson, "evidenceScope"), "unknown");
        string readinessStatus = FirstNonEmpty(ExtractJsonString(commercialTriageJson, "readinessStatus"), "상용화 트리아지 산출물 미확인");
        bool hasFeedbackSignal = surveySessionCount > 0;
        bool replayLoopSignalStrong = averageReplayRewardValueRating >= 3.7f || replayIntentPercent >= 50f;
        bool valueSignalStrong = averagePriceValueRating >= 3.7f;
        bool uiSignalStrong = averageUiReadabilityRating >= 3.5f;
        bool hasEnoughExternalHumanSignal = recommendedHumanMinimum > 0 && externalCompleteSessionCount >= recommendedHumanMinimum;
        bool hasEnoughExternalCommercialSignal = recommendedCommercialMinimum > 0 && externalCompleteSessionCount >= recommendedCommercialMinimum;
        bool hasEnoughLoopResponses = recommendedHumanMinimum > 0 && screenshotAbLoopResponseCount >= recommendedHumanMinimum;
        bool hasEnoughLoopUnderstandingComments = recommendedHumanMinimum > 0 && screenshotAbLoopUnderstandingCommentCount >= recommendedHumanMinimum;
        string evidenceScope = hasFeedbackSignal
            ? "설문 회수 " + surveySessionCount + "/" + sessionCount + ", 반복 가치 " + FormatFloat(averageReplayRewardValueRating) + "/5, 10달러 가치감 " + FormatFloat(averagePriceValueRating) + "/5, UI " + FormatFloat(averageUiReadabilityRating) + "/5, 재플레이 " + replayIntentCount + "/" + surveySessionCount + " (" + FormatFloat(replayIntentPercent) + "%)"
            : "설문 회수 없음, 기본 내부 QA 우선순위 적용";
        string confidenceLabel = hasEnoughExternalCommercialSignal
            ? "외부 회수 기반 상용화 판정"
            : hasEnoughExternalHumanSignal
                ? "외부 회수 기반 균형 판정"
                : externalCompleteSessionCount > 0
                    ? "외부 회수 부족 임시 판정"
                    : "QA 샘플 기반 임시 판정";
        string primaryDecision = replayLoopSignalStrong && uiSignalStrong
            ? "`12_career_record_next_objective.png` 1차 승격 후보 유지"
            : "`12_career_record_next_objective.png`는 보류하고 가독성/반복 가치 피드백 추가 회수";
        string secondaryDecision = valueSignalStrong
            ? "`10_achievement_next_goal.png` 보조 후보 유지"
            : "`10_achievement_next_goal.png`는 보상/가격 가치감 문구 보강 후 재평가";
        string postExternalPromotionStatus = hasEnoughExternalHumanSignal && hasEnoughLoopResponses && hasEnoughLoopUnderstandingComments
            ? "ready_for_store_candidate_promotion_review"
            : "waiting_for_external_5_and_ab_loop_responses";
        string postExternalPromotionDecision = hasEnoughExternalHumanSignal && hasEnoughLoopResponses && hasEnoughLoopUnderstandingComments && replayLoopSignalStrong && uiSignalStrong
            ? "`12_career_record_next_objective.png`를 `01_main_menu.png` 교체 후보로 승격 검토"
            : "공식 8장은 유지하고 `01_main_menu.png` 기준 화면과 `12_career_record_next_objective.png` 후보를 계속 비교";
        string loopCandidatePriorityBadge = hasEnoughExternalHumanSignal && hasEnoughLoopResponses && hasEnoughLoopUnderstandingComments
            ? "P0_READY_PROMOTION_REVIEW"
            : "P0_WAIT_EXTERNAL_AB";
        string mainMenuPriorityBadge = hasEnoughLoopResponses
            ? "P1_BASELINE_DECIDE"
            : "P1_BASELINE_GUARD";
        string copyAlignmentPriorityBadge = hasEnoughLoopUnderstandingComments
            ? "P1_COPY_ALIGNMENT_DECIDE"
            : "P1_COPY_ALIGNMENT_COLLECT";

        return
            "# 상점 후보 스크린샷 승격 기준표\n\n" +
            "생성 기준: v" + ReleaseVersion + " Steamworks store_page 패키징\n\n" +
            "공식 8장 업로드 세트는 유지하되, 실제 플레이테스터 피드백과 Store Presence 검수에서 아래 후보를 비교해 교체 여부를 결정한다. 점수는 내부 우선순위이며 Steamworks에 자동 업로드하지 않는다.\n\n" +
            "## 플레이테스트 피드백 신호\n\n" +
            "- 설문 회수 세션: " + surveySessionCount + "/" + sessionCount + " (QA 포함 집계)\n" +
            "- 평균 10달러 가치감: " + FormatFloat(averagePriceValueRating) + "/5\n" +
            "- 평균 반복 보상/장기 기록 가치감: " + FormatFloat(averageReplayRewardValueRating) + "/5\n" +
            "- 평균 UI 가독성: " + FormatFloat(averageUiReadabilityRating) + "/5\n" +
            "- 재플레이 의향: " + replayIntentCount + "/" + surveySessionCount + " (" + FormatFloat(replayIntentPercent) + "%)\n" +
            "- 자동 판정 근거: " + evidenceScope + "\n" +
            "- 자동 판정(QA 포함 집계): " + primaryDecision + "; " + secondaryDecision + "\n\n" +
            "## 외부 회수 신뢰도\n\n" +
            "- 판정 범위: " + confidenceLabel + "\n" +
            "- 실제 사람 완전 회수 세션: " + externalCompleteSessionCount + "/" + recommendedHumanMinimum + " (상용 최소 " + recommendedCommercialMinimum + ")\n" +
            "- 외부 설문 회수: " + externalSurveySessionCount + ", QA 설문 회수: " + qaSurveySessionCount + ", 트리아지 설문 회수: " + totalTriageSurveySessionCount + "\n" +
            "- 트리아지 evidenceScope: `" + triageEvidenceScope + "`\n" +
            "- 상용화 준비 상태: " + readinessStatus + "\n" +
            "- 적용 원칙: QA 포함 집계는 후보 정렬에만 사용하고, 공식 승격 확정은 외부 완전 회수 기준 충족 후 결정한다.\n\n" +
            "## 외부 5명 이후 승격 판정 요약\n\n" +
            "| summary_id | 외부 완전 회수 | A/B 응답 | 루프 이해 코멘트 | 판정 상태 | 적용 |\n" +
            "| --- | ---: | ---: | ---: | --- | --- |\n" +
            "| `post_external_collection_promotion_summary` | " + externalCompleteSessionCount + "/" + recommendedHumanMinimum + " | " + screenshotAbLoopResponseCount + "/" + recommendedHumanMinimum + " | " + screenshotAbLoopUnderstandingCommentCount + "/" + recommendedHumanMinimum + " | `" + postExternalPromotionStatus + "` | " + postExternalPromotionDecision + " |\n\n" +
            "- 질문 연결: `main_menu_loop_entry`는 `01_main_menu.png` 기준 화면 유지 여부를, `menu_campaign_briefing_weakness`는 추천 회차 브리핑/직전 약점 보정 초점 줄이 다음 회차 목표 근거로 읽히는지를, `achievement_career_copy_alignment`는 성과 목표 힌트와 캠페인 기록 다음 목표 문구 일치를, `reward_loop_understanding`은 `10_achievement_next_goal.png`와 `12_career_record_next_objective.png`의 보상 누적 루프 이해도를 판정한다.\n" +
            "- 승격 조건: 실제 사람 완전 회수 " + recommendedHumanMinimum + "명 이상, `screenshot_ab_loop_response_count` " + recommendedHumanMinimum + "건 이상, `screenshot_ab_loop_understanding_comment_count` " + recommendedHumanMinimum + "건 이상이면 `SCREENSHOT_UPLOAD_SELECTION_KO.md`의 승격 후보 세트를 검토한다.\n" +
            "- 보류 조건: `main_menu_loop_entry`에서 메인 메뉴 기준 화면이 밀리거나 `menu_campaign_briefing_weakness`에서 직전 약점 보정 초점 줄이 목표 추천 근거로 읽히지 않거나 `achievement_career_copy_alignment`가 불명확하면 공식 8장 교체보다 메인 메뉴/성과 기록 문구 보강을 먼저 배정한다.\n" +
            "- 현재 선호 신호: `12_career_record_next_objective.png` " + screenshotAbLoopCareerPreferenceCount + "건, `둘 다 이해됨` " + screenshotAbLoopBothClearPreferenceCount + "건.\n\n" +
            "## 트리아지 세부 행별 우선순위 배지\n\n" +
            "| badge_id | priority_badge | 트리아지/질문 축 | 담당 후보 | 증거 | 다음 처리 |\n" +
            "| --- | --- | --- | --- | --- | --- |\n" +
            "| `triage_priority_badge_reward_loop_candidate` | `" + loopCandidatePriorityBadge + "` | `반복 가치 세부: 상점 후보 루프 이해`; `reward_loop_understanding`; `post_external_collection_promotion_summary` | `12_career_record_next_objective.png`, `10_achievement_next_goal.png` | `screenshot_ab_loop_response_count=" + screenshotAbLoopResponseCount + "`, `screenshot_ab_loop_understanding_comment_count=" + screenshotAbLoopUnderstandingCommentCount + "` | 외부 " + recommendedHumanMinimum + "명/A-B " + recommendedHumanMinimum + "건 전까지 후보 유지, 충족 후 승격 검토 |\n" +
            "| `triage_priority_badge_main_menu_baseline` | `" + mainMenuPriorityBadge + "` | `main_menu_loop_entry`; `menu_campaign_briefing_weakness`; 메인 메뉴 기준 화면 이해/추천 회차 브리핑 직전 약점 보정 초점 | `01_main_menu.png` | `menuMentionsAchievementBadge=true`, `mainMenuAchievementBadgeReadable=true`, `mainMenuBriefingWeaknessFocusReadable=true`, `briefingMentionsPreviousWeakness=true`, `briefingUsesCoachingWeaknessTerms=true`, `briefingWeaknessFocusCaptionReadable=true`, `briefingContrastEffectApplied=true`, `changedBriefingKeepsPreviousWeakness=true`, `changedBriefingKeepsCoachingWeaknessTerms=true`, `changedBriefingKeepsWeaknessFocusCaption=true` | 기준 화면 유지/교체 판단과 직전 약점 보정 초점 브리핑 이해도를 A/B 응답과 대조 |\n" +
            "| `triage_priority_badge_copy_alignment` | `" + copyAlignmentPriorityBadge + "` | `반복 가치 세부: 캠페인 기록 다음 목표`; `achievement_career_copy_alignment`; `브리핑 회고 상점 후보 근거` | `12_career_record_next_objective.png`, `10_achievement_next_goal.png` | `lowResolutionReleaseCopyAlignmentReadable=true`, `careerRecordActionHintReadable=true`, `storeCandidateMentionsBriefingRetrospective=true` | 성과 목표 힌트와 캠페인 기록 다음 목표/브리핑 회고 문구가 같은 반복 행동으로 읽히는지 확인 |\n" +
            "| `triage_priority_badge_career_reward_record` | `P2_REWARD_RECORD_COPY` | `반복 가치 세부: 성과 기록 보상` | `10_achievement_next_goal.png` | `achievementReplayRewardPanelMentionsRecordLinkHint=true`, `achievementStatusMentionsRewardLoop` | 성과 기록 보상 누적 설명을 보강한 뒤 보조 후보로 유지 |\n" +
            "| `triage_priority_badge_appeal_remedy` | `P2_APPEAL_REMEDY_LOOP` | 보정 이력/이의제기 루프 | `13_case_archive_appeal_remedy_history.png` | `appealTriageQueueButtonLabel`, `achievementCardMentionsAppealTriageResult=true` | 반복 가치보다 보정 이력 선호 코멘트가 많을 때 보조 후보 승격 |\n" +
            "| `triage_priority_badge_decision_coaching` | `P3_DECISION_COACHING_DEPTH` | 판단 복기 왕복/진행 HUD | `14_case_archive_decision_audit_coaching_focus.png` | `caseArchiveDecisionAuditCoachingButtonOpensFirstUseCase=true`, `caseArchiveDecisionAuditCoachingReturnOpensCareerRecord=true`, `coachingStateApplied=true`, `reviewHudMentionsCoachingObjective=true`, `reviewHudUpdatesAfterDecision=true` | 상점 첫 화면보다 장기 자료실 깊이와 심사 중 목표 추적을 강조할 때 후보 비교 |\n\n" +
            "## 후보 결과 QA 증거\n\n" +
            "- 캠페인 기록 후보 필터: `care_review_career_record_smoke_result.json`의 `bodyMentionsAppealTriageFilter`, `appealTriageFilterAppliesToRecord`, `appealTriageQueueButtonLabel`\n" +
            "- 성과 기록 후보 진행도: `care_review_achievement_smoke_result.json`의 `achievementCardMentionsAppealTriageResult`, `achievementStatusMentionsAppealTriageResult`, `achievementReplayRewardPanelMentionsAppealTriageResult`\n" +
            "- 성과-캠페인 루프 증거: `care_review_achievement_smoke_result.json`의 `achievementStatusMentionsRewardLoop`, `achievementRecordLinkHintReadable`, `care_review_focus_navigation_smoke_result.json`의 `achievementTopActionNavigationMatchesRewardLoop`, `achievementRecordButtonFocusOrderMatchesRewardLoop`, `care_review_career_record_smoke_result.json`의 `storeCandidateMentionsBriefingRetrospective=true`, `low_resolution_ui/care_review_low_resolution_ui_smoke_result.json`의 `careerRecordActionHintReadable`, `lowResolutionReleaseCopyAlignmentReadable`\n" +
            "- 메인 메뉴 성과 배지/직전 약점 보정 초점 증거: `care_review_main_menu_case_objective_smoke_result.json`의 `menuMentionsAchievementBadge=true`, `menuAchievementBadgeMentionsReplayProgress=true`, `care_review_main_menu_mandate_smoke_result.json`의 `briefingMentionsPreviousWeakness=true`, `briefingUsesCoachingWeaknessTerms=true`, `briefingWeaknessFocusCaptionReadable=true`, `briefingContrastEffectApplied=true`, `changedBriefingKeepsPreviousWeakness=true`, `changedBriefingKeepsCoachingWeaknessTerms=true`, `changedBriefingKeepsWeaknessFocusCaption=true`, `low_resolution_ui/care_review_low_resolution_ui_smoke_result.json`의 `mainMenuAchievementBadgeReadable=true`, `mainMenuBriefingWeaknessFocusReadable=true`\n" +
            "- 판단 복기 후보 증거: `care_review_focus_navigation_smoke_result.json`의 `achievementRecordLinkHintMentionsCoachingFirstUse`, `caseArchiveDecisionAuditCoachingButtonOpensFirstUseCase`, `caseArchiveDecisionAuditCoachingReturnOpensCareerRecord`, `care_review_decision_audit_coaching_hud_smoke_result.json`의 `coachingStateApplied=true`, `reviewHudMentionsCoachingObjective=true`, `reviewHudUpdatesAfterDecision=true`\n" +
            "- 상점 후보 캡처 무결성: `STORE_CANDIDATE_CAPTURE_SYNC_HASHES.sha256`\n" +
            "- 판정 연결: `01_main_menu.png`는 메인 메뉴 성과 배지와 성과 보기 진입이 첫 화면에서 읽히는지 기준 화면으로 유지하고, `08_career_record_filter.png`는 보정 후보 필터/후보별 회차 결과를, `10_achievement_next_goal.png`와 `12_career_record_next_objective.png`는 목표 실행 -> 캠페인 기록 -> 2/4/6 보상 누적 왕복 루프를, `13_case_archive_appeal_remedy_history.png`는 보정 이력 루프를, `14_case_archive_decision_audit_coaching_focus.png`는 `복기 W-207` 첫 사용 왕복과 판단 복기 진행 HUD를 보조 증거로 비교한다.\n\n" +
            "## 승격 우선순위\n\n" +
            "| Rank | 후보 파일 | 반복 플레이 전달력 | UI 가독성 | 기존 8장과 중복 | 권장 판정 |\n" +
            "| --- | --- | --- | --- | --- | --- |\n" +
            "| 1 | `12_career_record_next_objective.png` | 5 | 4 | 낮음 | 권장 후보: 캠페인 기록에서 다음 목표를 재시작하고 성과 기록 보상 누적으로 되돌아가는 성과-캠페인 루프와 브리핑 회고의 예고 위험/보상 및 실제 결과 대비를 가장 직접적으로 보여준다. 피드백 연동 판정: " + primaryDecision + " / 신뢰도: " + confidenceLabel + " |\n" +
            "| 2 | `13_case_archive_appeal_remedy_history.png` | 5 | 4 | 낮음 | 보조 후보: 원 사례에서 보정 이력, 성공률, 다음 재도전 목표를 함께 보여준다. 이의제기 루프 이해도 피드백 회수 후 A/B 비교 |\n" +
            "| 3 | `10_achievement_next_goal.png` | 5 | 4 | 중간 | 보조 후보: 성과 기록에서 목표 실행 -> 캠페인 기록 -> 2/4/6 보상 누적 연결을 보여준다. 피드백 연동 판정: " + secondaryDecision + " / 신뢰도: " + confidenceLabel + " |\n" +
            "| 4 | `01_main_menu.png` | 4 | 4 | 기준 화면 | 공식 기준 화면: 메인 메뉴 성과 배지, 다음 성과 목표, `A/성과 보기`가 첫 화면에서 읽히면 유지한다. 반복 루프 전달이 약하면 `12_career_record_next_objective.png`와 교체 비교 |\n" +
            "| 5 | `11_growth_follow_up_menu.png` | 4 | 4 | 중간 | 보조 후보: 메인 메뉴에서 성장 후속 진입점을 보여준다. UI 신호 " + (uiSignalStrong ? "양호" : "추가 검증") + " |\n" +
            "| 6 | `14_case_archive_decision_audit_coaching_focus.png` | 4 | 4 | 낮음 | 보조 후보: 사례 자료실 `복기 W-207` 버튼, 첫 사용 안내, 기록 복귀 왕복, 판단 복기 진행 HUD가 한 화면에서 읽히는지 확인한다. 상점 첫 장면보다 반복 자료실 깊이 강조용 |\n" +
            "## 적용 규칙\n\n" +
            "- 공식 업로드 8장 중 교체가 필요하면 먼저 `01_main_menu.png` 또는 중복이 큰 정적 화면과 비교한다.\n" +
            "- `01_main_menu.png`는 `menuMentionsAchievementBadge=true`와 `mainMenuAchievementBadgeReadable=true`가 유지되는 동안 공식 기준 화면으로 남긴다.\n" +
            "- 실제 플레이테스터가 반복 목표를 이해했다는 코멘트가 " + recommendedHumanMinimum + "명 회수 증거에 포함되면 `12_career_record_next_objective.png`를 1차 승격 후보로 둔다.\n" +
            "- 이의제기 보정 루프가 상점 첫인상에서 더 선명하다는 피드백이 나오면 `13_case_archive_appeal_remedy_history.png`를 보조 후보로 비교한다.\n" +
            "- 판단 복기/기록 복귀 왕복/진행 HUD가 장기 플레이 가치를 더 잘 설명한다는 피드백이 나오면 `14_case_archive_decision_audit_coaching_focus.png`를 보조 후보로 비교한다.\n" +
            "- 성과/보상 구조 이해도가 낮다는 피드백이 나오면 `10_achievement_next_goal.png`를 `12_career_record_next_objective.png`와 함께 A/B 비교한다.\n" +
            "- 설문 화면은 제품 기능보다 QA 회수 성격이 강하므로 공식 업로드가 아니라 내부 비교 자료로 유지한다.\n";
    }

    private static string WriteScreenshotCandidateDecisionMatrixRegressionSmoke()
    {
        Directory.CreateDirectory(StorePageQaPath);
        string aggregateJson =
            "{\n" +
            "  \"surveySessionCount\": 7,\n" +
            "  \"sessionCount\": 169,\n" +
            "  \"replayIntentCount\": 4,\n" +
            "  \"averagePriceValueRating\": 3.9,\n" +
            "  \"averageReplayRewardValueRating\": 3.7,\n" +
            "  \"averageUiReadabilityRating\": 3.6\n" +
            "}";
        string qaTriageJson = BuildScreenshotCandidateDecisionMatrixScenarioJson(0, 5, 10, 0, 0, 3, "qa_or_incomplete_survey_sessions", "실제 사람 완전 회수 세션이 아직 없어 10달러 판매 후보 판단은 보류한다.");
        string balanceTriageJson = BuildScreenshotCandidateDecisionMatrixScenarioJson(5, 5, 10, 5, 0, 5, "external_complete_sessions", "실제 사람 5명 완전 회수로 균형 판정은 가능하지만 상용화 판정은 보류한다.");
        string commercialTriageJson = BuildScreenshotCandidateDecisionMatrixScenarioJson(10, 5, 10, 10, 0, 10, "external_complete_sessions", "실제 사람 10명 완전 회수로 상용화 판정 후보를 검토할 수 있다.");
        string auditSummaryJson = "{ \"externalCompleteSessionCount\": 0, \"recommendedHumanMinimum\": 5, \"recommendedCommercialMinimum\": 10, \"surveySessionCount\": 3, \"screenshotAbLoopResponseCount\": 0, \"screenshotAbLoopUnderstandingCommentCount\": 0, \"screenshotAbLoopCareerRecordPreferenceCount\": 0, \"screenshotAbLoopBothClearPreferenceCount\": 0 }";
        string qaMatrix = BuildStorePageScreenshotCandidateDecisionMatrix(aggregateJson, qaTriageJson, auditSummaryJson);
        string balanceMatrix = BuildStorePageScreenshotCandidateDecisionMatrix(aggregateJson, balanceTriageJson, auditSummaryJson);
        string commercialMatrix = BuildStorePageScreenshotCandidateDecisionMatrix(aggregateJson, commercialTriageJson, auditSummaryJson);

        bool qaTemporaryDetected = qaMatrix.Contains("QA 샘플 기반 임시 판정");
        bool balanceDetected = balanceMatrix.Contains("외부 회수 기반 균형 판정");
        bool commercialDetected = commercialMatrix.Contains("외부 회수 기반 상용화 판정");
        bool currentScenarioRetainsCandidate =
            qaMatrix.Contains("12_career_record_next_objective.png") &&
            qaMatrix.Contains("1차 승격 후보 유지");
        bool postExternalPromotionSummaryReady = FileContainsAllText(
            qaMatrix,
            "외부 5명 이후 승격 판정 요약",
            "post_external_collection_promotion_summary",
            "waiting_for_external_5_and_ab_loop_responses",
            "main_menu_loop_entry",
            "menu_campaign_briefing_weakness",
            "achievement_career_copy_alignment",
            "reward_loop_understanding",
            "screenshot_ab_loop_response_count",
            "screenshot_ab_loop_understanding_comment_count");
        bool triagePriorityBadgeReady = FileContainsAllText(
            qaMatrix,
            "트리아지 세부 행별 우선순위 배지",
            "triage_priority_badge_reward_loop_candidate",
            "P0_WAIT_EXTERNAL_AB",
            "triage_priority_badge_main_menu_baseline",
            "P1_BASELINE_GUARD",
            "triage_priority_badge_copy_alignment",
            "achievement_career_copy_alignment",
            "반복 가치 세부: 성과 기록 보상",
            "반복 가치 세부: 캠페인 기록 다음 목표",
            "반복 가치 세부: 상점 후보 루프 이해",
            "reward_loop_understanding",
            "main_menu_loop_entry",
            "menu_campaign_briefing_weakness",
            "briefingMentionsPreviousWeakness=true",
            "briefingUsesCoachingWeaknessTerms=true",
            "briefingWeaknessFocusCaptionReadable=true",
            "briefingContrastEffectApplied=true",
            "changedBriefingKeepsPreviousWeakness=true",
            "changedBriefingKeepsCoachingWeaknessTerms=true",
            "changedBriefingKeepsWeaknessFocusCaption=true",
            "12_career_record_next_objective.png",
            "01_main_menu.png");
        bool filesHaveNoLocalAbsolutePath = !ContainsLocalAbsolutePath(qaMatrix + balanceMatrix + commercialMatrix);
        bool completed = qaTemporaryDetected && balanceDetected && commercialDetected && currentScenarioRetainsCandidate && postExternalPromotionSummaryReady && triagePriorityBadgeReady && filesHaveNoLocalAbsolutePath;
        string path = Path.Combine(StorePageQaPath, "care_review_screenshot_candidate_decision_matrix_regression.json");

        StringBuilder builder = new();
        builder.AppendLine("{");
        builder.AppendLine("  \"completed\": " + BoolJson(completed) + ",");
        builder.AppendLine("  \"scenarioCount\": 3,");
        builder.AppendLine("  \"qaTemporaryDetected\": " + BoolJson(qaTemporaryDetected) + ",");
        builder.AppendLine("  \"balanceDetected\": " + BoolJson(balanceDetected) + ",");
        builder.AppendLine("  \"commercialDetected\": " + BoolJson(commercialDetected) + ",");
        builder.AppendLine("  \"currentScenarioRetainsCandidate\": " + BoolJson(currentScenarioRetainsCandidate) + ",");
        builder.AppendLine("  \"postExternalPromotionSummaryReady\": " + BoolJson(postExternalPromotionSummaryReady) + ",");
        builder.AppendLine("  \"triagePriorityBadgeReady\": " + BoolJson(triagePriorityBadgeReady) + ",");
        builder.AppendLine("  \"filesHaveNoLocalAbsolutePath\": " + BoolJson(filesHaveNoLocalAbsolutePath) + ",");
        builder.AppendLine("  \"qaScenarioLabel\": \"" + EscapeJson("QA 샘플 기반 임시 판정") + "\",");
        builder.AppendLine("  \"balanceScenarioLabel\": \"" + EscapeJson("외부 회수 기반 균형 판정") + "\",");
        builder.AppendLine("  \"commercialScenarioLabel\": \"" + EscapeJson("외부 회수 기반 상용화 판정") + "\"");
        builder.AppendLine("}");
        File.WriteAllText(path, builder.ToString(), new UTF8Encoding(false));
        return path;
    }

