        builder.AppendLine("  \"replacementTarget\": \"" + EscapeJson("01_main_menu.png") + "\"");
        builder.AppendLine("}");
        File.WriteAllText(path, builder.ToString(), new UTF8Encoding(false));
        return path;
    }

    private static string WriteScreenshotUploadApplicationRegressionSmoke()
    {
        Directory.CreateDirectory(StorePageQaPath);
