        string promotedMismatchApplication = BuildStorePageScreenshotUploadApplicationManifest(promotedSelection, currentSubmission);
        string promotedApplication = BuildStorePageScreenshotUploadApplicationManifest(promotedSelection, promotedSubmission);
        string rollbackMismatchApplication = BuildStorePageScreenshotUploadApplicationManifest(currentSelection, promotedSubmission);
        string rollbackApplication = BuildStorePageScreenshotUploadApplicationManifest(currentSelection, currentSubmission);

        bool currentSubmissionMatches = FileContainsAllText(currentApplication, "selected_upload_set: current_official_8", "submission_matches_selected_set: yes", "rollback_matches_current_set: yes", "ready_for_store_presence_upload: yes");
        bool promotedMismatchBlocked = FileContainsAllText(promotedMismatchApplication, "selected_upload_set: promoted_candidate_set", "submission_matches_selected_set: no", "promoted_candidate_applied: no", "replacement_removed: no", "ready_for_store_presence_upload: no");
        bool promotedSubmissionMatches = FileContainsAllText(promotedApplication, "selected_upload_set: promoted_candidate_set", "submission_matches_selected_set: yes", "promoted_candidate_applied: yes", "replacement_removed: yes", "ready_for_store_presence_upload: yes");
        bool rollbackMismatchBlocked = FileContainsAllText(rollbackMismatchApplication, "selected_upload_set: current_official_8", "submission_matches_selected_set: no", "rollback_matches_current_set: no", "ready_for_store_presence_upload: no");
        bool rollbackSubmissionMatches = FileContainsAllText(rollbackApplication, "selected_upload_set: current_official_8", "submission_matches_selected_set: yes", "rollback_matches_current_set: yes", "ready_for_store_presence_upload: yes");
        bool filesHaveNoLocalAbsolutePath = !ContainsLocalAbsolutePath(currentApplication + promotedMismatchApplication + promotedApplication + rollbackMismatchApplication + rollbackApplication);
        bool completed = currentSubmissionMatches && promotedMismatchBlocked && promotedSubmissionMatches && rollbackMismatchBlocked && rollbackSubmissionMatches && filesHaveNoLocalAbsolutePath;
