        builder.AppendLine("  \"promotedMismatchBlocked\": " + BoolJson(promotedMismatchBlocked) + ",");
        builder.AppendLine("  \"promotedSubmissionMatches\": " + BoolJson(promotedSubmissionMatches) + ",");
        builder.AppendLine("  \"rollbackMismatchBlocked\": " + BoolJson(rollbackMismatchBlocked) + ",");
        builder.AppendLine("  \"rollbackSubmissionMatches\": " + BoolJson(rollbackSubmissionMatches) + ",");
        builder.AppendLine("  \"filesHaveNoLocalAbsolutePath\": " + BoolJson(filesHaveNoLocalAbsolutePath) + ",");
        builder.AppendLine("  \"promotedCandidate\": \"" + EscapeJson("12_career_record_next_objective.png") + "\",");
        builder.AppendLine("  \"replacementTarget\": \"" + EscapeJson("01_main_menu.png") + "\"");
        builder.AppendLine("}");
        File.WriteAllText(path, builder.ToString(), new UTF8Encoding(false));
        return path;
    }

