    private static string BuildStorePresenceSelectionManifest()
    {
        string screenshotApplicationManifest = SafeReadAllText(Path.Combine(SteamworksStorePagePath, "SCREENSHOT_UPLOAD_APPLICATION_KO.md"));
        string trailerUploadSelectionManifest = SafeReadAllText(Path.Combine(SteamworksStorePagePath, "TRAILER_UPLOAD_SELECTION_KO.md"));
        string submissionDraft = SafeReadAllText(Path.Combine(SteamworksStorePagePath, "STORE_PAGE_SUBMISSION_DRAFT_KO.md"));
        string screenshotCandidateAbTestManifest = SafeReadAllText(Path.Combine(SteamworksStorePagePath, "SCREENSHOT_CANDIDATE_AB_TEST_KO.md"));
        return BuildStorePresenceSelectionManifest(screenshotApplicationManifest, trailerUploadSelectionManifest, submissionDraft, screenshotCandidateAbTestManifest);
    }

    private static string BuildStorePresenceSelectionManifest(string screenshotApplicationManifest, string trailerUploadSelectionManifest, string submissionDraft)
    {
        return BuildStorePresenceSelectionManifest(
            screenshotApplicationManifest,
            trailerUploadSelectionManifest,
            submissionDraft,
            BuildScreenshotCandidateAbTestScenarioManifest("no_requires_external_feedback", "12_career_record_next_objective.png", "13_case_archive_appeal_remedy_history.png", "12_career_record_next_objective.png"));
    }

    private static string BuildStorePresenceSelectionManifest(string screenshotApplicationManifest, string trailerUploadSelectionManifest, string submissionDraft, string screenshotCandidateAbTestManifest)
    {
        string screenshotPromotionStatus = FirstNonEmpty(ExtractMarkdownField(screenshotApplicationManifest, "promotion_status"), "unknown");
        string screenshotSelectedUploadSet = FirstNonEmpty(ExtractMarkdownField(screenshotApplicationManifest, "selected_upload_set"), "unknown");
        string screenshotSubmissionUpdateRequired = FirstNonEmpty(ExtractMarkdownField(screenshotApplicationManifest, "submission_update_required"), "unknown");
        bool screenshotApplicationReady = string.Equals(ExtractMarkdownField(screenshotApplicationManifest, "ready_for_store_presence_upload"), "yes", StringComparison.OrdinalIgnoreCase);
        bool screenshotSubmissionMatches = string.Equals(ExtractMarkdownField(screenshotApplicationManifest, "submission_matches_selected_set"), "yes", StringComparison.OrdinalIgnoreCase);
        bool screenshotRollbackMatchesCurrent = string.Equals(ExtractMarkdownField(screenshotApplicationManifest, "rollback_matches_current_set"), "yes", StringComparison.OrdinalIgnoreCase);

        string trailerCurrentSelection = FirstNonEmpty(ExtractMarkdownField(trailerUploadSelectionManifest, "current_selection"), "unknown");
        string trailerSelectedFile = FirstNonEmpty(ExtractMarkdownField(trailerUploadSelectionManifest, "selected_file"), "unknown");
        bool trailerSubmissionMatch = string.Equals(ExtractMarkdownField(trailerUploadSelectionManifest, "submission_selected_file_match"), "yes", StringComparison.OrdinalIgnoreCase);
        bool trailerReady = string.Equals(ExtractMarkdownField(trailerUploadSelectionManifest, "ready_for_steam_store_upload"), "yes", StringComparison.OrdinalIgnoreCase);
        bool submissionDraftMentionsTrailer = !string.Equals(trailerSelectedFile, "unknown", StringComparison.OrdinalIgnoreCase) && ContainsOrdinalIgnoreCase(submissionDraft, trailerSelectedFile);
        string screenshotAbTestReady = FirstNonEmpty(ExtractMarkdownField(screenshotCandidateAbTestManifest, "ab_test_ready"), "unknown");
        string screenshotAbDefaultCandidate = FirstNonEmpty(ExtractMarkdownField(screenshotCandidateAbTestManifest, "default_candidate"), "unknown");
        string screenshotAbComparisonCandidate = FirstNonEmpty(ExtractMarkdownField(screenshotCandidateAbTestManifest, "comparison_candidate"), "unknown");
        string screenshotAbRecommendedCandidate = FirstNonEmpty(ExtractMarkdownField(screenshotCandidateAbTestManifest, "recommended_candidate"), "unknown");
        string screenshotAbRecommendationReason = FirstNonEmpty(ExtractMarkdownField(screenshotCandidateAbTestManifest, "recommendation_reason"), "unknown");
        bool storeCandidateHashReady = FileContainsAll(
            Path.Combine(SteamworksStorePageCandidateScreenshotsPath, "STORE_CANDIDATE_CAPTURE_SYNC_HASHES.sha256"),
            "08_career_record_filter.png",
            "12_career_record_next_objective.png",
            "13_case_archive_appeal_remedy_history.png",
            "14_case_archive_decision_audit_coaching_focus.png");

        bool screenshotNeedsSubmissionUpdate =
            string.Equals(screenshotSubmissionUpdateRequired, "yes", StringComparison.OrdinalIgnoreCase) &&
            (!screenshotApplicationReady || !screenshotSubmissionMatches);
        bool trailerNeedsSubmissionUpdate = !trailerSubmissionMatch || !submissionDraftMentionsTrailer;
        bool storePresenceNeedsSubmissionUpdate = screenshotNeedsSubmissionUpdate || trailerNeedsSubmissionUpdate;
        int blockerCount = 0;
        if (!screenshotApplicationReady)
        {
            blockerCount++;
        }

        if (!trailerReady)
        {
            blockerCount++;
        }

        if (storePresenceNeedsSubmissionUpdate)
        {
            blockerCount++;
        }

        if (!storeCandidateHashReady)
        {
            blockerCount++;
        }

        bool readyForManualInput =
            screenshotApplicationReady &&
            screenshotSubmissionMatches &&
            trailerReady &&
            trailerSubmissionMatch &&
            submissionDraftMentionsTrailer &&
            storeCandidateHashReady &&
            !storePresenceNeedsSubmissionUpdate;

        StringBuilder builder = new();
        builder.AppendLine("# Store Presence 제출 선택 통합 manifest");
        builder.AppendLine();
        builder.AppendLine("screenshot_application_source: SCREENSHOT_UPLOAD_APPLICATION_KO.md");
        builder.AppendLine("screenshot_ab_test_source: SCREENSHOT_CANDIDATE_AB_TEST_KO.md");
        builder.AppendLine("trailer_selection_source: TRAILER_UPLOAD_SELECTION_KO.md");
        builder.AppendLine("submission_source: STORE_PAGE_SUBMISSION_DRAFT_KO.md");
        builder.AppendLine("screenshot_promotion_status: " + screenshotPromotionStatus);
        builder.AppendLine("screenshot_selected_upload_set: " + screenshotSelectedUploadSet);
        builder.AppendLine("screenshot_submission_update_required: " + screenshotSubmissionUpdateRequired);
        builder.AppendLine("screenshot_application_ready: " + (screenshotApplicationReady ? "yes" : "no"));
        builder.AppendLine("screenshot_submission_matches: " + (screenshotSubmissionMatches ? "yes" : "no"));
        builder.AppendLine("screenshot_rollback_matches_current: " + (screenshotRollbackMatchesCurrent ? "yes" : "no"));
        builder.AppendLine("screenshot_ab_test_ready: " + screenshotAbTestReady);
        builder.AppendLine("screenshot_ab_default_candidate: " + screenshotAbDefaultCandidate);
        builder.AppendLine("screenshot_ab_comparison_candidate: " + screenshotAbComparisonCandidate);
        builder.AppendLine("screenshot_ab_recommended_candidate: " + screenshotAbRecommendedCandidate);
        builder.AppendLine("screenshot_ab_recommendation_reason: " + screenshotAbRecommendationReason);
        builder.AppendLine("trailer_current_selection: " + trailerCurrentSelection);
        builder.AppendLine("trailer_selected_file: " + trailerSelectedFile);
        builder.AppendLine("trailer_submission_match: " + (trailerSubmissionMatch ? "yes" : "no"));
        builder.AppendLine("trailer_ready: " + (trailerReady ? "yes" : "no"));
        builder.AppendLine("submission_draft_mentions_trailer: " + (submissionDraftMentionsTrailer ? "yes" : "no"));
        builder.AppendLine("store_candidate_hash_manifest: STORE_CANDIDATE_CAPTURE_SYNC_HASHES.sha256");
        builder.AppendLine("store_candidate_hash_ready: " + (storeCandidateHashReady ? "yes" : "no"));
        builder.AppendLine("appeal_triage_qa_evidence: appealTriageQueueReturnOpensCareerRecord=true; achievementCardMentionsAppealTriageResult=true; 보정 후보 결과");
        builder.AppendLine("decision_audit_coaching_candidate_evidence: 14_case_archive_decision_audit_coaching_focus.png; 복기 W-207; caseArchiveDecisionAuditCoachingButtonOpensFirstUseCase=true; caseArchiveDecisionAuditCoachingReturnOpensCareerRecord=true; " + DecisionAuditCoachingHudStoreCandidateSummary);
        builder.AppendLine("store_presence_needs_submission_update: " + (storePresenceNeedsSubmissionUpdate ? "yes" : "no"));
        builder.AppendLine("store_presence_manual_blocker_count: " + blockerCount);
        builder.AppendLine("store_presence_ready_for_manual_input: " + (readyForManualInput ? "yes" : "no"));
        builder.AppendLine();
        builder.AppendLine("- Steamworks Store Presence 수동 입력 직전에는 스크린샷 공식 8장 적용 manifest와 트레일러 업로드 선택 manifest가 모두 `yes`여야 한다.");
        builder.AppendLine("- 후보 스크린샷 A/B 판정 결과는 Store Presence 선택 manifest에 요약하되, `screenshot_ab_test_ready: yes` 전에는 공식 8장 유지가 기본이다.");
        builder.AppendLine("- 상점 후보 SHA manifest와 보정 후보 QA 증거가 연결되어야 후보 캡처 세트가 Store Presence 입력 직전 검수 자료로 인정된다.");
        builder.AppendLine("- 스크린샷 후보 승격이나 트레일러 리마스터 후보 전환 중 하나라도 제출안에 반영되지 않으면 `store_presence_ready_for_manual_input: no`로 막는다.");
        builder.AppendLine("- 현재 롤백 기준은 `current_official_8` 스크린샷 세트와 `current_upload` 트레일러 파일이다.");
        return builder.ToString();
    }

