        bool abSummaryReady = FileContainsAllText(currentManifest, "screenshot_ab_test_source: SCREENSHOT_CANDIDATE_AB_TEST_KO.md", "screenshot_ab_test_ready: no_requires_external_feedback", "screenshot_ab_default_candidate: 12_career_record_next_objective.png", "screenshot_ab_comparison_candidate: 13_case_archive_appeal_remedy_history.png", "screenshot_ab_recommended_candidate: 12_career_record_next_objective.png");
        bool promotedScreenshotMismatchBlocked = FileContainsAllText(promotedScreenshotMismatchManifest, "screenshot_selected_upload_set: promoted_candidate_set", "screenshot_application_ready: no", "store_presence_ready_for_manual_input: no", "store_presence_needs_submission_update: yes");
        bool remasterTrailerMismatchBlocked = FileContainsAllText(remasterTrailerMismatchManifest, "trailer_current_selection: remaster_upload_candidate", "trailer_selected_file: " + candidateFile, "trailer_submission_match: no", "store_presence_ready_for_manual_input: no", "store_presence_needs_submission_update: yes");
