        bool rollbackReady = FileContainsAllText(rollbackManifest, "screenshot_selected_upload_set: current_official_8", "screenshot_rollback_matches_current: yes", "trailer_current_selection: current_upload", "store_presence_ready_for_manual_input: yes");
        bool filesHaveNoLocalAbsolutePath = !ContainsLocalAbsolutePath(currentManifest + promotedScreenshotMismatchManifest + remasterTrailerMismatchManifest + promotedAndRemasterSyncedManifest + rollbackManifest);
