    private static string BuildStoreValuePositioningManifest()
    {
        string metadataText = SafeReadAllText(Path.Combine(SteamworksStorePagePath, "STORE_PAGE_METADATA_KO.md"));
        string submissionDraftText = SafeReadAllText(Path.Combine(SteamworksStorePagePath, "STORE_PAGE_SUBMISSION_DRAFT_KO.md"));
        string aggregateJson = SafeReadAllText("Builds/QA/v0.3.0/playtest_packet/care_review_playtest_aggregate.json");
        string releaseManifestText = SafeReadAllText(Path.Combine(SteamworksContentPath, "RELEASE_MANIFEST.txt"));
        return BuildStoreValuePositioningManifest(metadataText, submissionDraftText, aggregateJson, releaseManifestText);
    }

    private static string BuildStoreValuePositioningManifest(string metadataText, string submissionDraftText, string aggregateJson, string releaseManifestText)
    {
        string combinedStoreCopy = metadataText + "\n" + submissionDraftText;
        string combinedEvidence = combinedStoreCopy + "\n" + releaseManifestText;
        float averagePriceValueRating = ExtractJsonFloat(aggregateJson, "averagePriceValueRating");
        bool priceAssumptionPresent = ContainsOrdinalIgnoreCase(combinedStoreCopy, "USD 9.99");
        bool noTwentyDollarPriceClaim =
            !ContainsOrdinalIgnoreCase(combinedStoreCopy, "USD 19.99") &&
            !ContainsOrdinalIgnoreCase(combinedStoreCopy, "USD 20") &&
            !ContainsOrdinalIgnoreCase(combinedStoreCopy, "20달러 가격") &&
            !ContainsOrdinalIgnoreCase(combinedStoreCopy, "20달러로 판매");
        bool caseVolumePillar = ContainsOrdinalIgnoreCase(combinedEvidence, "40개") && ContainsOrdinalIgnoreCase(combinedEvidence, "5일");
        bool replayPillar = ContainsOrdinalIgnoreCase(combinedEvidence, "3종 운영 기준") && (ContainsOrdinalIgnoreCase(combinedEvidence, "반복") || ContainsOrdinalIgnoreCase(combinedEvidence, "다음 캠페인"));
        bool analyticsPillar = ContainsOrdinalIgnoreCase(combinedEvidence, "HTML 분석 대시보드") && (ContainsOrdinalIgnoreCase(combinedEvidence, "CSV") || ContainsOrdinalIgnoreCase(combinedEvidence, "JSON"));
        bool accessibilityPillar = ContainsOrdinalIgnoreCase(combinedEvidence, "큰 글자") && ContainsOrdinalIgnoreCase(combinedEvidence, "고대비") && ContainsOrdinalIgnoreCase(combinedEvidence, "키보드");
        bool storeAssetPillar = ContainsOrdinalIgnoreCase(combinedEvidence, "스크린샷") && ContainsOrdinalIgnoreCase(combinedEvidence, "트레일러") && ContainsOrdinalIgnoreCase(combinedEvidence, "캡슐");
        bool transparencyPillar = ContainsOrdinalIgnoreCase(combinedEvidence, "합성 사례") && ContainsOrdinalIgnoreCase(combinedEvidence, "실제 개인정보") && ContainsOrdinalIgnoreCase(combinedEvidence, "로컬");
        int valuePillarCount = 0;
        if (caseVolumePillar)
        {
            valuePillarCount++;
        }

        if (replayPillar)
        {
            valuePillarCount++;
        }

        if (analyticsPillar)
        {
            valuePillarCount++;
        }

        if (accessibilityPillar)
        {
            valuePillarCount++;
        }

        if (storeAssetPillar)
        {
            valuePillarCount++;
        }

        if (transparencyPillar)
        {
            valuePillarCount++;
        }

        bool playtestValueSignalReady = averagePriceValueRating >= 3.5f;
        bool twentyDollarQualityBenchmarkReady = priceAssumptionPresent && noTwentyDollarPriceClaim && valuePillarCount >= 5 && playtestValueSignalReady;

        StringBuilder builder = new();
        builder.AppendLine("# Store Value 포지셔닝 manifest");
        builder.AppendLine();
        builder.AppendLine("metadata_source: STORE_PAGE_METADATA_KO.md");
        builder.AppendLine("submission_source: STORE_PAGE_SUBMISSION_DRAFT_KO.md");
        builder.AppendLine("actual_price_assumption_usd: 9.99");
        builder.AppendLine("quality_benchmark_usd: 20.00");
        builder.AppendLine("price_assumption_present: " + (priceAssumptionPresent ? "yes" : "no"));
        builder.AppendLine("no_twenty_dollar_price_claim: " + (noTwentyDollarPriceClaim ? "yes" : "no"));
        builder.AppendLine("average_price_value_rating: " + FormatFloat(averagePriceValueRating));
        builder.AppendLine("playtest_value_signal_ready: " + (playtestValueSignalReady ? "yes" : "no"));
        builder.AppendLine("value_pillar_case_volume: " + (caseVolumePillar ? "yes" : "no"));
        builder.AppendLine("value_pillar_replay_structure: " + (replayPillar ? "yes" : "no"));
        builder.AppendLine("value_pillar_analysis_exports: " + (analyticsPillar ? "yes" : "no"));
        builder.AppendLine("value_pillar_accessibility: " + (accessibilityPillar ? "yes" : "no"));
        builder.AppendLine("value_pillar_store_assets: " + (storeAssetPillar ? "yes" : "no"));
        builder.AppendLine("value_pillar_transparency: " + (transparencyPillar ? "yes" : "no"));
        builder.AppendLine("value_pillar_count: " + valuePillarCount);
        builder.AppendLine("twenty_dollar_quality_benchmark_ready: " + (twentyDollarQualityBenchmarkReady ? "yes" : "no"));
        builder.AppendLine("actual_price_change_ready: no_requires_external_validation");
        builder.AppendLine();
        builder.AppendLine("- 이 manifest는 실제 가격 변경을 승인하지 않는다. 현재 상점 기준 가격은 `USD 9.99`로 유지한다.");
        builder.AppendLine("- `quality_benchmark_usd: 20.00`은 사용자가 요구한 품질 목표를 내부 검증 기준으로 둔 값이다.");
        builder.AppendLine("- 실제 20달러대 가격 변경은 외부 완전 회수, 경쟁작 비교, 환불 리스크 검토 후 별도 결정한다.");
        return builder.ToString();
    }

    private static string WriteStoreValuePositioningRegressionSmoke()
    {
        Directory.CreateDirectory(StorePageQaPath);
        string strongAggregateJson = "{ \"averagePriceValueRating\": 3.9 }";
        string weakAggregateJson = "{ \"averagePriceValueRating\": 2.9 }";
        string fullCopy =
            "가격 기준: USD 9.99\n" +
            "5일 캠페인과 40개 돌봄지원 신청 사례\n" +
            "3종 운영 기준과 반복 플레이, 다음 캠페인 목표\n" +
            "HTML 분석 대시보드와 CSV/JSON 로그\n" +
            "큰 글자, 고대비, 키보드 조작\n" +
            "스크린샷, 트레일러, 캡슐 이미지\n" +
            "합성 사례, 실제 개인정보 미사용, 로컬 로그 저장\n";
        string thinCopy =
            "가격 기준: USD 9.99\n" +
            "5일 캠페인과 40개 사례\n";
        string priceClaimCopy = fullCopy + "출시 가격은 USD 19.99입니다.\n";
        string releaseEvidence = fullCopy + "Steamworks depot template\n";

        string readyManifest = BuildStoreValuePositioningManifest(fullCopy, fullCopy, strongAggregateJson, releaseEvidence);
        string thinManifest = BuildStoreValuePositioningManifest(thinCopy, thinCopy, strongAggregateJson, thinCopy);
        string priceClaimManifest = BuildStoreValuePositioningManifest(priceClaimCopy, priceClaimCopy, strongAggregateJson, releaseEvidence);
        string weakValueManifest = BuildStoreValuePositioningManifest(fullCopy, fullCopy, weakAggregateJson, releaseEvidence);

        bool fullCopyReady = FileContainsAllText(readyManifest, "value_pillar_count: 6", "playtest_value_signal_ready: yes", "no_twenty_dollar_price_claim: yes", "twenty_dollar_quality_benchmark_ready: yes");
        bool thinCopyBlocked = FileContainsAllText(thinManifest, "twenty_dollar_quality_benchmark_ready: no");
        bool priceClaimBlocked = FileContainsAllText(priceClaimManifest, "no_twenty_dollar_price_claim: no", "twenty_dollar_quality_benchmark_ready: no");
        bool weakValueSignalBlocked = FileContainsAllText(weakValueManifest, "playtest_value_signal_ready: no", "twenty_dollar_quality_benchmark_ready: no");
        bool filesHaveNoLocalAbsolutePath = !ContainsLocalAbsolutePath(readyManifest + thinManifest + priceClaimManifest + weakValueManifest);
        bool completed = fullCopyReady && thinCopyBlocked && priceClaimBlocked && weakValueSignalBlocked && filesHaveNoLocalAbsolutePath;
        string path = Path.Combine(StorePageQaPath, "care_review_store_value_positioning_regression.json");

        StringBuilder builder = new();
        builder.AppendLine("{");
        builder.AppendLine("  \"completed\": " + BoolJson(completed) + ",");
        builder.AppendLine("  \"scenarioCount\": 4,");
        builder.AppendLine("  \"fullCopyReady\": " + BoolJson(fullCopyReady) + ",");
        builder.AppendLine("  \"thinCopyBlocked\": " + BoolJson(thinCopyBlocked) + ",");
        builder.AppendLine("  \"priceClaimBlocked\": " + BoolJson(priceClaimBlocked) + ",");
        builder.AppendLine("  \"weakValueSignalBlocked\": " + BoolJson(weakValueSignalBlocked) + ",");
        builder.AppendLine("  \"filesHaveNoLocalAbsolutePath\": " + BoolJson(filesHaveNoLocalAbsolutePath) + ",");
        builder.AppendLine("  \"actualPriceAssumptionUsd\": \"9.99\",");
        builder.AppendLine("  \"qualityBenchmarkUsd\": \"20.00\"");
        builder.AppendLine("}");
        File.WriteAllText(path, builder.ToString(), new UTF8Encoding(false));
        return path;
    }

    private static string BuildScreenshotCandidateDecisionMatrixScenarioJson(int completeHumanSessionCount, int recommendedHumanMinimum, int recommendedCommercialMinimum, int externalSurveySessionCount, int qaSurveySessionCount, int totalSurveySessionCount, string evidenceScope, string readinessStatus)
    {
        return
            "{\n" +
            "  \"completeHumanSessionCount\": " + completeHumanSessionCount + ",\n" +
            "  \"recommendedHumanMinimum\": " + recommendedHumanMinimum + ",\n" +
            "  \"recommendedCommercialMinimum\": " + recommendedCommercialMinimum + ",\n" +
            "  \"externalSurveySessionCount\": " + externalSurveySessionCount + ",\n" +
            "  \"qaSurveySessionCount\": " + qaSurveySessionCount + ",\n" +
            "  \"totalSurveySessionCount\": " + totalSurveySessionCount + ",\n" +
            "  \"evidenceScope\": \"" + EscapeJson(evidenceScope) + "\",\n" +
            "  \"readinessStatus\": \"" + EscapeJson(readinessStatus) + "\"\n" +
            "}";
    }

