    private static void AppendPreflightTopDecisionSummary(StringBuilder builder)
    {
        string auditJsonPath = Path.Combine(ReleaseCandidateAuditPath, "care_review_release_candidate_audit.json");
        string auditJson = SafeReadAllText(auditJsonPath);
        bool localReady = auditJson.Contains("\"localReleaseCandidateReady\": true", StringComparison.Ordinal);
        bool publicReady = auditJson.Contains("\"steamPublicReleaseReady\": true", StringComparison.Ordinal);
        string localBlockers = FirstNonEmpty(ExtractJsonNumber(auditJson, "localBlockerCount"), "unknown");
        string externalActions = FirstNonEmpty(ExtractJsonNumber(auditJson, "externalActionCount"), "unknown");
        bool storePresenceBundleReady = PreflightStorePresenceEvidenceBundleTopSummaryReady();
        string storePresenceStatus = storePresenceBundleReady ? "allPassed" : "needs_release_candidate_audit";

        builder.AppendLine("## 최상단 판정 요약");
        builder.AppendLine("- 로컬 릴리즈 후보: `" + (localReady ? "ready" : "needs_audit") + "`; `localBlockerCount=" + localBlockers + "`");
        builder.AppendLine("- Steam 공개 출시: `" + (publicReady ? "ready" : "not_ready_external_actions") + "`; `externalActionCount=" + externalActions + "`");
        builder.AppendLine("- Paperlogy 폰트 evidence: `" + (SteamworksUploadManifestPaperlogyFontEvidenceReady() ? "ready" : "missing") + "`; `Paperlogy font evidence`; `STEAMWORKS_UPLOAD_MANIFEST.txt`; `content_windows/RELEASE_MANIFEST.txt`; `content_windows/README_KR.txt`; `Docs/THIRD_PARTY_FONTS.md`; `care_review_ui_cleanup_smoke_result.json`; `paperlogyTextMismatchCount=0`");
        builder.AppendLine("- upload manifest Paperlogy README top cross-check: `STEAMWORKS_UPLOAD_MANIFEST.txt`; `Paperlogy README top cross-check`; `README_STEAMWORKS_KR.txt`; `Store Presence 증거 묶음 상태`; `Paperlogy 폰트 evidence`; `paperlogyTextMismatchCount=0`");
        builder.AppendLine("- Store Presence 증거 묶음: `" + storePresenceStatus + "`; `checkCount=11`; `passedCheckCount=" + (storePresenceBundleReady ? "11" : "unknown") + "`; `allPassed=" + BoolJson(storePresenceBundleReady) + "`; `STORE_PRESENCE_EVIDENCE_BUNDLE_SUMMARY`");
        builder.AppendLine("- Store Presence 실제 입력 증거: `pending_external`; `Evidence/STORE_PRESENCE.md`; `status: draft_not_evidence`; 실제 Steamworks URL/화면 캡처 입력 후에만 통과 처리");
        builder.AppendLine("- Store Presence 외부 액션 연결: `STORE_PRESENCE`; `externalActionCount=" + externalActions + "`; `actual_status=pending_external`; `storePresenceDraftStatusSummary`; `store_presence_draft_status_summary`; `draft=Evidence/STORE_PRESENCE.md`; `draft_status=status: draft_not_evidence`; `release candidate JSON memberSummary 확인`; `care_review_release_candidate_audit.json`; `memberSummary=storePresenceEvidenceBundle.checks.memberSummary`; `screenshot_ab_loop_response_count=0`; `screenshot_ab_loop_not_collected_count=221`; `screenshot_ab_loop_collection_status=waiting_for_screenshot_ab_loop_responses`");
        builder.AppendLine("- Store Presence after_collection 입력란: `storePresenceAfterCollectionInputSummary`; `store_presence_after_collection_input_summary`; `after_collection_inputs=store_presence_priority_badge_after_collection_input`; `after_collection_status_reward_loop_candidate`; `completion_gate_main_menu_baseline`; `completion_gate_copy_alignment`");
        builder.AppendLine("- Store Presence 자체점검 TODO 요약: `completion_todo=작성 완료 전 자체점검 TODO`; `completion_todo_items=Steamworks URL/화면 캡처|SHA 확인|14번 복기 후보|브리핑 회고 후보|A/B 응답 회수`; `Evidence/STORE_PRESENCE.md`; `외부 검증 Store Presence 자체점검 TODO 요약`");
        builder.AppendLine("- 성과-캠페인 루프 A/B 응답 회수 보류: `screenshot_ab_loop_response_count=0`; `screenshot_ab_loop_not_collected_count=221`; `screenshot_ab_loop_collection_status=waiting_for_screenshot_ab_loop_responses`");
        builder.AppendLine("- Store Presence 외부 게이트 스모크 상호참조: `care_review_external_gate_audit_smoke_result.json`; `storePresencePreflightTopCrossReference`; `hasStorePresenceDraftStatusTrackerAuditCrossReference`; `hasScreenshotAbLoopResponseTrackerAuditCrossReference`");
        builder.AppendLine("- 외부 게이트 smoke zip SHA: `care_review_external_gate_audit_smoke_result.json`; `handoffZipSha256`; `handoffZipBytes`; `handoffZipHashFileMatches=true`; `steamworksZipSha256`; `steamworksZipBytes`; `steamworksZipHashFileMatches=true`");
    }

    private static string BuildReleaseCandidateAuditNote(ReleaseCandidateAudit audit)
    {
        string auditJsonPath = Path.Combine(ReleaseCandidateAuditPath, "care_review_release_candidate_audit.json");
        string auditCsvPath = Path.Combine(ReleaseCandidateAuditPath, "care_review_release_candidate_audit.csv");
        string auditMarkdownPath = Path.Combine(ReleaseCandidateAuditPath, "care_review_release_candidate_audit.md");
        string auditJson = SafeReadAllText(auditJsonPath);
        bool localReady = audit != null ? audit.localReleaseCandidateReady : auditJson.Contains("\"localReleaseCandidateReady\": true");
        bool publicReady = audit != null ? audit.steamPublicReleaseReady : auditJson.Contains("\"steamPublicReleaseReady\": true");
        string externalActionCount = audit != null ? audit.externalActionCount.ToString(CultureInfo.InvariantCulture) : ExtractJsonNumber(auditJson, "externalActionCount");
        string localBlockerCount = audit != null ? audit.localBlockerCount.ToString(CultureInfo.InvariantCulture) : ExtractJsonNumber(auditJson, "localBlockerCount");
        int storePresenceCheckCount = StorePresenceEvidenceBundleLabels().Length;
        int storePresencePassedCount = audit != null
            ? StorePresenceEvidenceBundlePassedCount(audit)
            : (auditJson.Contains("\"storePresenceEvidenceBundle\"") && auditJson.Contains("\"allPassed\": true") ? storePresenceCheckCount : 0);
        bool storePresenceAllPassed = storePresencePassedCount == storePresenceCheckCount;

        return
            "# 릴리즈 후보 감사 안내\n\n" +
            "- 최신 감사 JSON: `" + auditJsonPath + "`\n" +
            "- 최신 감사 CSV: `" + auditCsvPath + "`\n" +
            "- 최신 감사 Markdown: `" + auditMarkdownPath + "`\n" +
            "- 재생성 메뉴: Unity `Care Review Office/Audit Release Candidate`\n" +
            "- 배치 실행: `CareReviewProjectBuilder.AuditReleaseCandidate`\n\n" +
            "## 최신 판정\n\n" +
            "- 로컬 릴리즈 후보 준비: `" + BoolJson(localReady) + "`\n" +
            "- Steam 공개 출시 준비: `" + BoolJson(publicReady) + "`\n" +
            "- 로컬 미해결 항목: `" + (string.IsNullOrEmpty(localBlockerCount) ? "unknown" : localBlockerCount) + "`\n" +
            "- 외부 필수 항목: `" + (string.IsNullOrEmpty(externalActionCount) ? "unknown" : externalActionCount) + "`\n\n" +
            "## Store Presence 실제 증거 초안 상태\n\n" +
            "- 실제 입력 상태: `pending_external`\n" +
            "- 초안 파일: `Evidence/STORE_PRESENCE.md`; `status: draft_not_evidence`\n" +
            "- 예시 파일: `Evidence/STORE_PRESENCE_EXAMPLE.md`; `status: example_not_evidence`; 통과 증거가 아님\n" +
            "- 증거 템플릿: `Evidence/_templates/STORE_PRESENCE.md`; `자체점검 TODO 요약 템플릿`; `Evidence/STORE_PRESENCE_EXAMPLE.md`; `Evidence/STORE_PRESENCE.md`\n" +
            "- 외부 게이트 row: `storePresenceDraftStatusSummary`, `store_presence_draft_status_summary`, `actual_status=pending_external`\n" +
            "- 자체점검 TODO 요약: `completion_todo=작성 완료 전 자체점검 TODO`; `completion_todo_items=Steamworks URL/화면 캡처|SHA 확인|14번 복기 후보|브리핑 회고 후보|A/B 응답 회수`; `Evidence/STORE_PRESENCE.md`\n" +
            "- A/B 응답 회수 입력란: `screenshot_ab_loop_response_count=0`; `screenshot_ab_loop_not_collected_count=221`; `screenshot_ab_loop_collection_status=waiting_for_screenshot_ab_loop_responses`; `screenshot_ab_loop_understanding_comment_count=0`\n" +
            "- A/B TODO 직접 매핑: `store_presence_ab_todo_mapping`; `post_external_collection_promotion_summary`; `main_menu_loop_entry`; `menu_campaign_briefing_weakness`; `achievement_career_copy_alignment`; `reward_loop_understanding`\n" +
            "- upload manifest memberSummary 대조: `STEAMWORKS_UPLOAD_MANIFEST.txt`; `Store Presence evidence draft`; `memberSummary=storePresenceEvidenceBundle.checks.memberSummary`\n" +
            "- 릴리즈 후보 감사 Markdown 상호참조: `care_review_release_candidate_audit.md`; `Store Presence 실제 증거 초안 상태`; `tracker 힌트`\n" +
            "- 외부 게이트 스모크 상호참조: `care_review_external_gate_audit_smoke_result.json`; `storePresenceAuditNoteCrossReference`; `hasStorePresenceDraftStatusJsonRow`; `screenshot_ab_loop_response_count=0`\n" +
            "- 실제 Steamworks URL/화면 캡처와 `STORE_PRESENCE_EVIDENCE_BUNDLE_SUMMARY`를 채운 뒤에만 status 값을 passed로 바꾼다.\n\n" +
            "## Store Presence 우선순위 배지 회수 후 입력란\n\n" +
            "- 외부 게이트 row 필드: `storePresenceAfterCollectionInputSummary`, `store_presence_after_collection_input_summary`\n" +
            "- tracker 원본: `EXTERNAL_RELEASE_GATE_TRACKER.csv`; `after_collection_inputs=store_presence_priority_badge_after_collection_input,store_presence_main_menu_baseline_after_collection_input,store_presence_copy_alignment_after_collection_input`\n" +
            "- 입력란: `after_collection_status_reward_loop_candidate`, `manual_update_target_reward_loop_candidate`, `completion_gate_reward_loop_candidate`, `after_collection_status_main_menu_baseline`, `completion_gate_main_menu_baseline`, `after_collection_status_copy_alignment`, `completion_gate_copy_alignment`\n" +
            "- 완료 조건: `external_5_and_ab_loop_5_and_understanding_5`, `main_menu_loop_entry_response_collected`, `copy_alignment_comment_collected`\n\n" +
            "## 보정 후보 / Store Presence 증거 묶음\n\n" +
            "- JSON 묶음: `storePresenceEvidenceBundle`, `checkCount=" + storePresenceCheckCount + "`, `passedCheckCount=" + storePresencePassedCount + "`, `allPassed=" + BoolJson(storePresenceAllPassed) + "`\n" +
            "- JSON memberSummary: `care_review_release_candidate_audit.json`; `memberSummary=storePresenceEvidenceBundle.checks.memberSummary`; `screenshot_ab_loop_response_count`; `screenshot_ab_loop_not_collected_count`; `screenshot_ab_loop_collection_status`; `screenshot_ab_loop_understanding_comment_count`; `store_presence_ab_todo_mapping`; `store_presence_priority_badge_backreference`; `triage_priority_badge_reward_loop_candidate`; `P0_WAIT_EXTERNAL_AB`\n" +
            "- upload manifest 상호참조: `STEAMWORKS_UPLOAD_MANIFEST.txt`; `Store Presence evidence bundle`; `memberSummary=storePresenceEvidenceBundle.checks.memberSummary`\n" +
            "- CSV 요약: `care_review_release_candidate_audit.csv`, `store_presence_bundle_member`, `store_presence_bundle_summary`, `STORE_PRESENCE_EVIDENCE_BUNDLE_SUMMARY`\n" +
            "- handoff 순서: `README_KO.txt`의 `Store Presence/A-B/보정 후보 증거 작성 순서`, `STORE_PRESENCE_QA_CARD_KO.md`, `Evidence/_templates/STORE_PRESENCE.md`, `Evidence/STORE_PRESENCE.md`\n\n" +
            "Steam 공개 제출 전에는 최신 릴리즈 zip/Steamworks zip/플레이테스트 kit zip을 만든 뒤 이 감사를 다시 실행한다.\n";
    }

