            File.WriteAllText(Path.Combine(SteamworksRootPath, "RELEASE_CANDIDATE_AUDIT_NOTE_KO.md"), BuildReleaseCandidateAuditNote(audit), new UTF8Encoding(false));
        }
        AssetDatabase.Refresh();
        return audit;
    }

    private static ExternalReleaseGateAudit BuildExternalReleaseGateAudit()
    {
        Directory.CreateDirectory(ExternalGateAuditPath);
        Directory.CreateDirectory(ExternalGateEvidencePath);
        BuildExternalGateEvidenceTemplates();

        List<ExternalReleaseGateAuditRow> rows = new();
        string playtestAuditPath = Path.Combine(PlaytestCollectionAuditPath, "care_review_playtest_collection_audit_summary.json");
        string playtestAuditJson = SafeReadAllText(playtestAuditPath);
        int externalCompleteSessionCount = ExtractJsonInt(playtestAuditJson, "externalCompleteSessionCount");

        AddExternalReleaseGateRow(
            rows,
            "HUMAN_5_PLAYTEST",
            "playtest",
            ExtractJsonBool(playtestAuditJson, "readyForBalanceTuning") && externalCompleteSessionCount >= 5,
            playtestAuditPath,
            "externalCompleteSessionCount=" + externalCompleteSessionCount + "/5",
            "실제 사람 플레이테스트 5명 이상 완전 회수 후 밸런스 조정");

        AddExternalReleaseGateRow(
            rows,
            "HUMAN_10_COMMERCIAL",
            "playtest",
            ExtractJsonBool(playtestAuditJson, "readyForCommercialTuning") && externalCompleteSessionCount >= 10,
            playtestAuditPath,
            "externalCompleteSessionCount=" + externalCompleteSessionCount + "/10",
            "실제 사람 플레이테스트 10명 이상 완전 회수 후 판매 후보 밸런스 판단");

        bool appIdConfigured = SteamAppIdConfigured(out string appIdEvidence);
        AddExternalReleaseGateRow(
            rows,
            "STEAM_APPID",
            "steamworks",
            appIdConfigured,
            SteamworksScriptsPath,
            appIdEvidence,
            "실제 AppID 교체 - 현재 placeholder " + PlaceholderSteamAppId + " 사용 중. Steamworks 앱 생성 후 configure_steamworks_ids.ps1로 교체 필요");

        bool depotIdConfigured = SteamDepotIdConfigured(out string depotIdEvidence);
        AddExternalReleaseGateRow(
            rows,
            "STEAM_DEPOTID",
            "steamworks",
            depotIdConfigured,
            SteamworksScriptsPath,
            depotIdEvidence,
            "실제 DepotID 교체 - 현재 placeholder " + PlaceholderSteamDepotId + " 사용 중. Windows depot 생성 후 configure_steamworks_ids.ps1로 교체 필요");

        bool steamCmdPreviewPassed = SteamCmdPreviewPassed(out string steamCmdEvidence);
        if (!steamCmdPreviewPassed && ExternalGateEvidenceNotePassed("STEAMCMD_PREVIEW", out string steamCmdNoteEvidence, "SteamCMD", "Preview", "통과"))
        {
            steamCmdPreviewPassed = true;
            steamCmdEvidence = steamCmdNoteEvidence;
        }
        AddExternalReleaseGateRow(
            rows,
            "STEAMCMD_PREVIEW",
            "steamworks",
            steamCmdPreviewPassed,
            SteamworksOutputPath,
            steamCmdEvidence,
            "SteamCMD preview run - Steamworks 계정/Steam Guard가 필요한 외부 작업");

        bool privateBranchPassed = ExternalGateEvidenceNotePassed("PRIVATE_BRANCH", out string privateBranchEvidence, "Steam", "비공개", "실행");
        AddExternalReleaseGateRow(
            rows,
            "PRIVATE_BRANCH",
            "steamworks",
            privateBranchPassed,
            Path.Combine(ExternalGateEvidencePath, "PRIVATE_BRANCH.md"),
            privateBranchEvidence,
            "Steamworks 비공개 테스트 브랜치 생성 - preview 통과 후 Steamworks 웹에서 기본 공개 대신 비공개 테스트 브랜치로 먼저 배포 필요");

        bool reinstallPassed = ExternalGateEvidenceNotePassed("STEAM_CLIENT_REINSTALL", out string reinstallEvidence, "설치", "재설치", "실행");
        AddExternalReleaseGateRow(
            rows,
            "STEAM_CLIENT_REINSTALL",
            "steamworks",
            reinstallPassed,
            Path.Combine(ExternalGateEvidencePath, "STEAM_CLIENT_REINSTALL.md"),
            reinstallEvidence,
            "Steam 클라이언트 설치/재설치 QA - 비공개 브랜치에서 설치, 실행, 삭제, 재설치를 실제 Steam 클라이언트로 확인 필요");

        bool storePresencePassed = ExternalGateEvidenceNotePassed("STORE_PRESENCE", out string storePresenceEvidence, "상점", "스크린샷", "캡슐", "트레일러", "SHA", "A/B", "selected_upload_set", "promoted_candidate", "briefing_retrospective_candidate_evidence", "storeCandidateMentionsBriefingRetrospective=true", "브리핑 회고");
        AddExternalReleaseGateRow(
            rows,
            "STORE_PRESENCE",
            "steamworks",
            storePresencePassed,
            Path.Combine(ExternalGateEvidencePath, "STORE_PRESENCE.md"),
            storePresenceEvidence,
            "Steamworks Store Presence 입력 - 상점 문구와 이미지 업로드는 웹 콘솔에서 수동 입력 필요");

        bool achievementsPassed = ExternalGateEvidenceNotePassed("ACHIEVEMENTS", out string achievementsEvidence, "12", "API");
        AddExternalReleaseGateRow(
            rows,
            "ACHIEVEMENTS",
            "steamworks",
            achievementsPassed,
            Path.Combine(ExternalGateEvidencePath, "ACHIEVEMENTS.md"),
            achievementsEvidence,
            "Steamworks Achievements 입력 - ACHIEVEMENT_CANDIDATES.csv의 API Name을 Steamworks Achievements에 수동 입력 필요");

        bool lowSpecPassed = ExternalGateEvidenceNotePassed("LOW_SPEC_PC", out string lowSpecEvidence, "저사양", "환경 진단", "지원 번들");
        AddExternalReleaseGateRow(
            rows,
            "LOW_SPEC_PC",
            "external_qa",
            lowSpecPassed,
            Path.Combine(ExternalGateEvidencePath, "LOW_SPEC_PC.md"),
            lowSpecEvidence,
            "외부 저사양 PC 검증 - 실제 내장 그래픽 노트북/저사양 PC에서 설치 실행 확인 필요");

        ExternalReleaseGateAudit audit = new()
        {
            generatedAt = DateTime.Now.ToString("s"),
            version = ReleaseVersion,
            auditCompleted = true,
            hasAuditOutputs = true,
            evidenceRoot = ExternalGateEvidencePath,
            rows = rows,
            gateCount = rows.Count,
            passedGateCount = 0,
            pendingGateCount = 0
        };

        foreach (ExternalReleaseGateAuditRow row in rows)
        {
            if (row.passed)
            {
                audit.passedGateCount++;
            }
            else
            {
                audit.pendingGateCount++;
            }
        }

        audit.steamPublicReleaseReady = audit.pendingGateCount == 0;

        string summaryPath = Path.Combine(ExternalGateAuditPath, "care_review_external_gate_audit_summary.json");
        string csvPath = Path.Combine(ExternalGateAuditPath, "care_review_external_gate_audit.csv");
        string markdownPath = Path.Combine(ExternalGateAuditPath, "care_review_external_gate_audit.md");
        string smokePath = Path.Combine(ExternalGateAuditPath, "care_review_external_gate_audit_smoke_result.json");
        File.WriteAllText(summaryPath, BuildExternalReleaseGateAuditJson(audit), new UTF8Encoding(false));
        File.WriteAllText(csvPath, BuildExternalReleaseGateAuditCsv(audit), new UTF8Encoding(false));
        File.WriteAllText(markdownPath, BuildExternalReleaseGateAuditMarkdown(audit), new UTF8Encoding(false));
        File.WriteAllText(smokePath, BuildExternalReleaseGateAuditSmokeJson(audit), new UTF8Encoding(false));
        AssetDatabase.Refresh();
        return audit;
    }

    private static void AddExternalReleaseGateRow(List<ExternalReleaseGateAuditRow> rows, string gateId, string category, bool passed, string evidencePath, string evidenceSummary, string nextAction)
    {
        rows.Add(new ExternalReleaseGateAuditRow
        {
            gateId = gateId,
            category = category,
            status = passed ? "passed" : "pending_external",
            passed = passed,
            evidencePath = evidencePath.Replace("\\", "/"),
            evidenceSummary = BuildExternalGateEvidenceSummary(gateId, evidenceSummary),
            ownerScreenEvidenceSummary = BuildExternalGateOwnerScreenEvidenceSummary(gateId),
            priorityBadgeOwnerScreenSummary = BuildExternalGatePriorityBadgeOwnerScreenSummary(gateId),
            storePresenceDraftStatusSummary = BuildExternalGateStorePresenceDraftStatusSummary(gateId),
            storePresenceAfterCollectionInputSummary = BuildExternalGateStorePresenceAfterCollectionInputSummary(gateId),
            screenshotAbLoopResponseSummary = BuildExternalGateScreenshotAbLoopResponseSummary(gateId),
            nextAction = nextAction
        });
    }

    private static string BuildExternalGateEvidenceSummary(string gateId, string evidenceSummary)
    {
        if (gateId == "STORE_PRESENCE")
        {
            return evidenceSummary + "; completion_todo=작성 완료 전 자체점검 TODO; completion_todo_items=Steamworks URL/화면 캡처|SHA 확인|14번 복기 후보|브리핑 회고 후보|A/B 응답 회수; upload_manifest=STEAMWORKS_UPLOAD_MANIFEST.txt; upload_manifest_memberSummary=storePresenceEvidenceBundle.checks.memberSummary; " + StorePresenceBriefingRetrospectiveCandidateSummary + "; ab_loop_inputs=screenshot_ab_loop_response_count=0,screenshot_ab_loop_not_collected_count=221,screenshot_ab_loop_collection_status=waiting_for_screenshot_ab_loop_responses";
        }

        return evidenceSummary;
    }

    private static void AddExternalGatePendingActions(ReleaseCandidateAudit audit, ExternalReleaseGateAudit gateAudit)
    {
        foreach (ExternalReleaseGateAuditRow row in gateAudit.rows)
        {
            if (!row.passed)
            {
                AddExternalAction(audit, row.nextAction);
            }
        }
    }

    private static string BuildExternalReleaseGateAuditJson(ExternalReleaseGateAudit audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("{");
        builder.AppendLine("  \"auditCompleted\": " + BoolJson(audit.auditCompleted) + ",");
        builder.AppendLine("  \"hasAuditOutputs\": " + BoolJson(audit.hasAuditOutputs) + ",");
        builder.AppendLine("  \"generatedAt\": \"" + EscapeJson(audit.generatedAt) + "\",");
        builder.AppendLine("  \"version\": \"" + EscapeJson(audit.version) + "\",");
        builder.AppendLine("  \"evidenceRoot\": \"" + EscapeJson(audit.evidenceRoot) + "\",");
        builder.AppendLine("  \"gateCount\": " + audit.gateCount + ",");
        builder.AppendLine("  \"passedGateCount\": " + audit.passedGateCount + ",");
        builder.AppendLine("  \"pendingGateCount\": " + audit.pendingGateCount + ",");
        builder.AppendLine("  \"steamPublicReleaseReady\": " + BoolJson(audit.steamPublicReleaseReady) + ",");
        builder.AppendLine("  \"storePresenceEvidenceBundleSummary\": \"" + EscapeJson(BuildExternalGateStorePresenceEvidenceBundleSummary()) + "\",");
        builder.AppendLine("  \"rows\": [");
        for (int i = 0; i < audit.rows.Count; i++)
        {
            ExternalReleaseGateAuditRow row = audit.rows[i];
            builder.AppendLine("    {");
            builder.AppendLine("      \"gateId\": \"" + EscapeJson(row.gateId) + "\",");
            builder.AppendLine("      \"category\": \"" + EscapeJson(row.category) + "\",");
            builder.AppendLine("      \"status\": \"" + EscapeJson(row.status) + "\",");
            builder.AppendLine("      \"passed\": " + BoolJson(row.passed) + ",");
            builder.AppendLine("      \"evidencePath\": \"" + EscapeJson(row.evidencePath) + "\",");
            builder.AppendLine("      \"evidenceSummary\": \"" + EscapeJson(row.evidenceSummary) + "\",");
            builder.AppendLine("      \"ownerScreenEvidenceSummary\": \"" + EscapeJson(row.ownerScreenEvidenceSummary) + "\",");
            builder.AppendLine("      \"priorityBadgeOwnerScreenSummary\": \"" + EscapeJson(row.priorityBadgeOwnerScreenSummary) + "\",");
            builder.AppendLine("      \"storePresenceDraftStatusSummary\": \"" + EscapeJson(row.storePresenceDraftStatusSummary) + "\",");
            builder.AppendLine("      \"storePresenceAfterCollectionInputSummary\": \"" + EscapeJson(row.storePresenceAfterCollectionInputSummary) + "\",");
            builder.AppendLine("      \"screenshotAbLoopResponseSummary\": \"" + EscapeJson(row.screenshotAbLoopResponseSummary) + "\",");
            builder.AppendLine("      \"nextAction\": \"" + EscapeJson(row.nextAction) + "\"");
            builder.Append("    }");
            builder.AppendLine(i == audit.rows.Count - 1 ? "" : ",");
        }
        builder.AppendLine("  ]");
        builder.AppendLine("}");
        return builder.ToString();
    }

    private static string BuildExternalReleaseGateAuditCsv(ExternalReleaseGateAudit audit)
    {
        StringBuilder builder = new();
        string storePresenceBundleSummary = BuildExternalGateStorePresenceEvidenceBundleSummary();
        builder.AppendLine("gate_id,category,status,passed,evidence_path,evidence_summary,owner_screen_evidence_summary,priority_badge_owner_screen_summary,store_presence_evidence_bundle_summary,store_presence_draft_status_summary,store_presence_after_collection_input_summary,screenshot_ab_loop_response_summary,next_action");
        foreach (ExternalReleaseGateAuditRow row in audit.rows)
        {
            builder.Append(EscapeCsv(row.gateId)).Append(',')
                .Append(EscapeCsv(row.category)).Append(',')
                .Append(EscapeCsv(row.status)).Append(',')
                .Append(row.passed ? "true" : "false").Append(',')
                .Append(EscapeCsv(row.evidencePath)).Append(',')
                .Append(EscapeCsv(row.evidenceSummary)).Append(',')
                .Append(EscapeCsv(row.ownerScreenEvidenceSummary)).Append(',')
                .Append(EscapeCsv(row.priorityBadgeOwnerScreenSummary)).Append(',')
                .Append(EscapeCsv(storePresenceBundleSummary)).Append(',')
                .Append(EscapeCsv(row.storePresenceDraftStatusSummary)).Append(',')
                .Append(EscapeCsv(row.storePresenceAfterCollectionInputSummary)).Append(',')
                .Append(EscapeCsv(row.screenshotAbLoopResponseSummary)).Append(',')
                .AppendLine(EscapeCsv(row.nextAction));
        }
        return builder.ToString();
    }

    private static string BuildExternalReleaseGateAuditMarkdown(ExternalReleaseGateAudit audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("# 외부 릴리즈 게이트 증거 감사");
        builder.AppendLine();
        builder.AppendLine("- 생성 시각: " + audit.generatedAt);
        builder.AppendLine("- 대상 버전: " + audit.version);
        builder.AppendLine("- 증거 루트: `" + audit.evidenceRoot + "`");
        builder.AppendLine("- 통과 게이트: " + audit.passedGateCount + " / " + audit.gateCount);
        builder.AppendLine("- 남은 게이트: " + audit.pendingGateCount);
        builder.AppendLine();
        builder.AppendLine(audit.steamPublicReleaseReady
            ? "- [x] Steam 공개 출시 외부 게이트가 모두 닫혔다."
            : "- [ ] Steam 공개 출시 외부 게이트가 남아 있다.");
        builder.AppendLine();
        builder.AppendLine("## 게이트별 판정");
        builder.AppendLine();
        builder.AppendLine("| Gate | Category | Status | Evidence | Priority Badge Owner Screen | Store Presence Draft | After Collection Inputs | Next Action |");
        builder.AppendLine("| --- | --- | --- | --- | --- | --- | --- | --- |");
        foreach (ExternalReleaseGateAuditRow row in audit.rows)
        {
            builder.Append("| `").Append(row.gateId).Append("` | ")
                .Append(row.category).Append(" | ")
                .Append(row.status).Append(" | ")
                .Append(row.evidenceSummary.Replace("|", "/")).Append(" | ")
                .Append(row.priorityBadgeOwnerScreenSummary.Replace("|", "/")).Append(" | ")
                .Append(row.storePresenceDraftStatusSummary.Replace("|", "/")).Append(" | ")
                .Append(row.storePresenceAfterCollectionInputSummary.Replace("|", "/")).Append(" | ")
                .Append(row.nextAction.Replace("|", "/")).AppendLine(" |");
        }

        string triageActionsPath = Path.Combine(ExternalValidationHandoffPath, "PLAYTEST_COMMERCIAL_TRIAGE_ACTIONS.csv").Replace("\\", "/");
        bool triageOwnerScreenEvidenceReady = FileContainsAll(
            triageActionsPath,
            "owner_screen",
            "owner_screen_evidence",
            "appealTriageQueueReturnOpensCareerRecord=true",
            "achievementCardMentionsAppealTriageResult=true",
            "STORE_CANDIDATE_CAPTURE_SYNC_HASHES.sha256",
            "보정 후보 결과",
            "성과 기록 / 캠페인 기록 / 상점 페이지");

        builder.AppendLine();
        builder.AppendLine("## 트리아지 담당 화면 증거");
        builder.AppendLine();
        builder.AppendLine("- 원본 작업표: `" + triageActionsPath + "`");
        builder.AppendLine("- 연결 상태: " + (triageOwnerScreenEvidenceReady ? "ready" : "missing"));
        builder.AppendLine("- 필수 열: `owner_screen`, `owner_screen_evidence`");
        builder.AppendLine("- HUMAN_10_COMMERCIAL 담당 화면: `성과 기록 / 캠페인 기록 / 상점 페이지`");
        builder.AppendLine("- 반복 보상/장기 기록 가치감 증거: `commercialChecklistMentionsSurfaceActions=true`, `commercialChecklistReadable=true`, `menuMentionsAchievementBadge=true`, `mainMenuAchievementBadgeReadable=true`, `appealTriageQueueReturnOpensCareerRecord=true`, `achievementCardMentionsAppealTriageResult=true`, `STORE_CANDIDATE_CAPTURE_SYNC_HASHES.sha256`, `보정 후보 결과`, `반복 가치 세부: 성과 기록 보상`, `반복 가치 세부: 캠페인 기록 다음 목표`, `반복 가치 세부: 상점 후보 루프 이해`");
        builder.AppendLine("- 이 요약은 외부 회수 10명 게이트가 단순 수치 확인을 넘어서, 실제 보강 담당 화면과 Store Presence 증거까지 연결됐는지 확인한다.");

        builder.AppendLine();
        builder.AppendLine("## HUMAN_10 우선순위 배지 owner_screen 힌트");
        builder.AppendLine();
        foreach (ExternalReleaseGateAuditRow row in audit.rows)
        {
            if (!string.IsNullOrWhiteSpace(row.priorityBadgeOwnerScreenSummary))
            {
                builder.AppendLine("- `" + row.gateId + "`: " + row.priorityBadgeOwnerScreenSummary);
            }
        }

        builder.AppendLine();
        builder.AppendLine("## 성과-캠페인 루프 A/B 응답 회수 힌트");
        builder.AppendLine();
        builder.AppendLine("- tracker: `EXTERNAL_RELEASE_GATE_TRACKER.csv`");
        foreach (ExternalReleaseGateAuditRow row in audit.rows)
        {
            if (!string.IsNullOrWhiteSpace(row.screenshotAbLoopResponseSummary))
            {
                builder.AppendLine("- `" + row.gateId + "`: " + row.screenshotAbLoopResponseSummary);
            }
        }

        builder.AppendLine();
        builder.AppendLine("## Store Presence 우선순위 배지 회수 후 입력란 감사 필드");
        builder.AppendLine();
        builder.AppendLine("- tracker: `EXTERNAL_RELEASE_GATE_TRACKER.csv`");
        foreach (ExternalReleaseGateAuditRow row in audit.rows)
        {
            if (!string.IsNullOrWhiteSpace(row.storePresenceAfterCollectionInputSummary))
            {
                builder.AppendLine("- `" + row.gateId + "`: " + row.storePresenceAfterCollectionInputSummary);
            }
        }

        builder.AppendLine();
        AppendExternalHandoffStorePresenceEvidenceBundle(builder);

        builder.AppendLine();
        builder.AppendLine("## 증거 작성 규칙");
        builder.AppendLine();
        builder.AppendLine("- Steamworks 웹 콘솔, Steam 클라이언트 설치, 실제 저사양 PC 검증처럼 자동으로 가져올 수 없는 항목은 `Builds/Handoff/v0.3.0/Evidence/<GATE_ID>.md`에 증거를 남긴다.");
        builder.AppendLine("- 해당 파일의 `status:` 값을 `passed`로 바꾸고, 템플릿의 필수 키워드를 실제 증거와 함께 채운 경우에만 통과로 판정한다.");
        builder.AppendLine("- 템플릿은 `Builds/Handoff/v0.3.0/Evidence/_templates` 아래에 있다.");
        return builder.ToString();
    }

    private static string BuildExternalReleaseGateAuditSmokeJson(ExternalReleaseGateAudit audit)
    {
        string handoffZipSha = File.Exists(ExternalValidationHandoffZipPath) ? ComputeSha256(ExternalValidationHandoffZipPath) : "missing";
        long handoffZipBytes = File.Exists(ExternalValidationHandoffZipPath) ? new FileInfo(ExternalValidationHandoffZipPath).Length : 0L;
        string handoffHashFile = SafeReadAllText(ExternalValidationHandoffHashPath).Trim();
        string steamworksZipPath = "Builds/Steamworks/CareReviewOffice_Steamworks_v0.3.0.zip";
        string steamworksHashPath = "Builds/Steamworks/CareReviewOffice_Steamworks_v0.3.0_SHA256.txt";
        string steamworksZipSha = File.Exists(steamworksZipPath) ? ComputeSha256(steamworksZipPath) : "missing";
        long steamworksZipBytes = File.Exists(steamworksZipPath) ? new FileInfo(steamworksZipPath).Length : 0L;
        string steamworksHashFile = SafeReadAllText(steamworksHashPath).Trim();
        return "{\n" +
            "  \"completed\": " + BoolJson(audit.auditCompleted) + ",\n" +
            "  \"hasAuditOutputs\": " + BoolJson(audit.hasAuditOutputs) + ",\n" +
            "  \"hasEvidenceTemplates\": " + BoolJson(Directory.Exists(Path.Combine(ExternalGateEvidencePath, "_templates"))) + ",\n" +
            "  \"handoffZipPath\": \"" + EscapeJson(ExternalValidationHandoffZipPath.Replace("\\", "/")) + "\",\n" +
            "  \"handoffZipSha256\": \"" + EscapeJson(handoffZipSha) + "\",\n" +
            "  \"handoffZipBytes\": " + handoffZipBytes + ",\n" +
            "  \"handoffZipHashFileMatches\": " + BoolJson(!string.IsNullOrWhiteSpace(handoffHashFile) && string.Equals(handoffZipSha, handoffHashFile, StringComparison.OrdinalIgnoreCase)) + ",\n" +
            "  \"steamworksZipPath\": \"" + EscapeJson(steamworksZipPath) + "\",\n" +
            "  \"steamworksZipSha256\": \"" + EscapeJson(steamworksZipSha) + "\",\n" +
            "  \"steamworksZipBytes\": " + steamworksZipBytes + ",\n" +
            "  \"steamworksZipHashFileMatches\": " + BoolJson(!string.IsNullOrWhiteSpace(steamworksHashFile) && string.Equals(steamworksZipSha, steamworksHashFile, StringComparison.OrdinalIgnoreCase)) + ",\n" +
            "  \"hasPlaytestHandoffShaTemplateLinks\": " + BoolJson(ExternalGateTemplatesMentionPlaytestHandoffSha()) + ",\n" +
            "  \"hasStorePresenceReadmeEvidenceOrderTemplateLink\": " + BoolJson(ExternalGateStorePresenceTemplateMentionsReadmeEvidenceOrder()) + ",\n" +
            "  \"hasStorePresenceExampleReadmeLink\": " + BoolJson(ExternalGateEvidenceReadmeMentionsStorePresenceExample()) + ",\n" +
            "  \"hasStorePresenceEvidenceBundleMarkdownSummary\": " + BoolJson(ExternalGateAuditMarkdownMentionsStorePresenceEvidenceBundle()) + ",\n" +
            "  \"hasStorePresenceEvidenceBundleCsvSummary\": " + BoolJson(ExternalGateAuditCsvMentionsStorePresenceEvidenceBundle()) + ",\n" +
            "  \"hasStorePresenceEvidenceBundleJsonSummary\": " + BoolJson(ExternalGateAuditJsonMentionsStorePresenceEvidenceBundle()) + ",\n" +
            "  \"hasStorePresenceToastUiCaptureEvidenceSummary\": " + BoolJson(ExternalGateAuditMentionsStorePresenceToastUiCaptureSummary()) + ",\n" +
            "  \"hasStorePresenceDraftEvidenceNote\": " + BoolJson(ExternalGateStorePresenceDraftEvidenceNoteReady()) + ",\n" +
            "  \"hasStorePresenceDraftStatusMarkdownTable\": " + BoolJson(ExternalGateAuditMarkdownMentionsStorePresenceDraftStatus()) + ",\n" +
            "  \"hasStorePresenceDraftStatusCsvRow\": " + BoolJson(ExternalGateAuditCsvMentionsStorePresenceDraftStatus()) + ",\n" +
            "  \"hasStorePresenceDraftStatusJsonRow\": " + BoolJson(ExternalGateAuditJsonMentionsStorePresenceDraftStatus()) + ",\n" +
            "  \"hasStorePresenceDraftStatusTrackerAuditCrossReference\": " + BoolJson(ExternalGateTrackerAndAuditStorePresenceDraftCrossReferenceReady()) + ",\n" +
