    private static string BuildStorePresenceToastUiCaptureEvidenceSummary()
    {
        string json = SafeReadAllText("Builds/QA/v0.3.0/achievement_toast/care_review_achievement_toast_ui_capture.json");
        bool ready = json.Contains("\"ready\": true", StringComparison.Ordinal);
        bool readable = json.Contains("\"readable\": true", StringComparison.Ordinal);
        bool bodyMentionsRecordLoop = json.Contains("성과 기록에서 다음 목표와 기록 보상 확인", StringComparison.Ordinal);
        string maxLineWidth = FirstNonEmpty(ExtractJsonNumber(json, "bodyMaxDisplayLineWidth"), "unknown");
        return "toastUiCaptureReady=" + BoolJson(ready) +
            "; toastUiCaptureReadable=" + BoolJson(readable) +
            "; toastUiCaptureBody=" + (bodyMentionsRecordLoop ? "성과 기록에서 다음 목표와 기록 보상 확인" : "missing") +
            "; toastUiCaptureMaxLineWidth=" + maxLineWidth +
            "; toastUiCaptureSource=achievement_toast/care_review_achievement_toast_ui_capture.json";
    }

