    private static bool SteamAppIdConfigured(out string evidence)
    {
        evidence = "Steamworks scripts directory missing";
        if (!Directory.Exists(SteamworksScriptsPath))
        {
            return false;
        }

        bool hasConfiguredAppBuild = false;
        bool hasPlaceholder = false;
        foreach (string filePath in Directory.GetFiles(SteamworksScriptsPath, "app_build_*.vdf"))
        {
            string fileName = Path.GetFileName(filePath);
            string content = SafeReadAllText(filePath);
            if (fileName.Contains(PlaceholderSteamAppId) || content.Contains("\"AppID\" \"" + PlaceholderSteamAppId + "\""))
            {
                hasPlaceholder = true;
            }
            else
            {
                hasConfiguredAppBuild = true;
            }
        }

        evidence = "hasConfiguredAppBuild=" + BoolJson(hasConfiguredAppBuild) + ", placeholderAppIdPresent=" + BoolJson(hasPlaceholder);
        return hasConfiguredAppBuild && !hasPlaceholder;
    }

    private static bool SteamDepotIdConfigured(out string evidence)
    {
        evidence = "Steamworks scripts directory missing";
        if (!Directory.Exists(SteamworksScriptsPath))
        {
            return false;
        }

        bool hasConfiguredDepotBuild = false;
        bool hasPlaceholder = false;
        foreach (string filePath in Directory.GetFiles(SteamworksScriptsPath, "*.vdf"))
        {
            string fileName = Path.GetFileName(filePath);
            string content = SafeReadAllText(filePath);
            if (fileName.Contains(PlaceholderSteamDepotId) || content.Contains("\"" + PlaceholderSteamDepotId + "\""))
            {
                hasPlaceholder = true;
            }

            if (fileName.StartsWith("depot_build_", StringComparison.OrdinalIgnoreCase) && !fileName.Contains(PlaceholderSteamDepotId))
            {
                hasConfiguredDepotBuild = true;
            }
        }

        evidence = "hasConfiguredDepotBuild=" + BoolJson(hasConfiguredDepotBuild) + ", placeholderDepotIdPresent=" + BoolJson(hasPlaceholder);
        return hasConfiguredDepotBuild && !hasPlaceholder;
    }

    private static bool SteamCmdPreviewPassed(out string evidence)
    {
        evidence = "SteamCMD output directory missing";
        if (!Directory.Exists(SteamworksOutputPath))
        {
            return false;
        }

        foreach (string filePath in Directory.GetFiles(SteamworksOutputPath, "*", SearchOption.AllDirectories))
        {
            if (new FileInfo(filePath).Length > 2_000_000L)
            {
                continue;
            }

            string content = SafeReadAllText(filePath);
            bool positive = ContainsAnyOrdinalIgnoreCase(content, "success", "completed", "complete", "finished", "no errors");
            bool context = ContainsAnyOrdinalIgnoreCase(content, "SteamCMD", "SteamPipe", "Preview", "AppBuild");
            bool negative = ContainsAnyOrdinalIgnoreCase(content, "error", "failed", "missing", "exception");
            if (positive && context && !negative)
            {
                evidence = filePath.Replace("\\", "/");
                return true;
            }
        }

        evidence = "No SteamCMD preview success log found in " + SteamworksOutputPath;
        return false;
    }

    private static bool ExternalGateEvidenceNotePassed(string gateId, out string evidence, params string[] requiredTokens)
    {
        string path = Path.Combine(ExternalGateEvidencePath, gateId + ".md");
        evidence = path.Replace("\\", "/") + " missing";
        if (!File.Exists(path))
        {
            return false;
        }

        string content = SafeReadAllText(path);
        bool statusPassed = ContainsOrdinalIgnoreCase(content, "status: passed");
        bool stillPending = ContainsOrdinalIgnoreCase(content, "status: pending") || ContainsOrdinalIgnoreCase(content, "TODO");
        bool tokensPresent = true;
        foreach (string token in requiredTokens)
        {
            if (!ContainsOrdinalIgnoreCase(content, token))
            {
                tokensPresent = false;
                break;
            }
        }

        evidence = path.Replace("\\", "/") + ", statusPassed=" + BoolJson(statusPassed) + ", requiredTokensPresent=" + BoolJson(tokensPresent);
        return statusPassed && !stillPending && tokensPresent && !ContainsLocalAbsolutePath(content);
    }

