        File.WriteAllText(jsonPath, BuildMarketingAssetAuditJson(audit), new UTF8Encoding(false));
        File.WriteAllText(csvPath, BuildMarketingAssetAuditCsv(audit), new UTF8Encoding(false));
        File.WriteAllText(markdownPath, BuildMarketingAssetAuditMarkdown(audit), new UTF8Encoding(false));
        File.WriteAllText(smokePath, BuildMarketingAssetSmokeJson(audit), new UTF8Encoding(false));
        AssetDatabase.Refresh();
        return audit;
    }

    private static string BuildTrailerRemasterPromotionGateMarkdown(string currentUploadPath, string remasterPath, string remasterProbePath, string blackdetectLogPath)
    {
        long currentBytes = File.Exists(currentUploadPath) ? new FileInfo(currentUploadPath).Length : 0L;
        long remasterBytes = File.Exists(remasterPath) ? new FileInfo(remasterPath).Length : 0L;
        bool remasterValid =
            File.Exists(remasterPath) &&
            remasterBytes > 1_000_000L &&
            FileContainsAll(remasterProbePath, "\"duration\": \"45.000000\"", "\"codec_name\": \"h264\"", "\"width\": 1920", "\"height\": 1080", "\"codec_name\": \"aac\"") &&
            File.Exists(Path.Combine(Path.GetDirectoryName(remasterPath), "trailer_steam_upload_remaster_contact_sheet.png")) &&
            File.Exists(Path.Combine(Path.GetDirectoryName(remasterPath), "trailer_remaster_43s_check.png")) &&
            !SafeReadAllText(blackdetectLogPath).Contains("black_start");

        StringBuilder builder = new();
        builder.AppendLine("# 트레일러 리마스터 승격 기준");
        builder.AppendLine();
        builder.AppendLine("promotion_decision: not_promoted");
        builder.AppendLine("current_steam_upload: care_review_office_trailer_steam_upload_v0.3.0.mp4");
        builder.AppendLine("remaster_candidate: care_review_office_trailer_steam_upload_v0.3.0_remaster.mp4");
        builder.AppendLine("candidate_validation: " + (remasterValid ? "passed" : "failed"));
        builder.AppendLine("promotion_requires: high_bitrate_upload_reencode_or_explicit_switch");
        builder.AppendLine();
        builder.AppendLine("- 현재 Steam 업로드 후보는 고비트레이트 파일을 유지한다.");
        builder.AppendLine("- 리마스터 후보는 13개 장면을 45.000초 타임라인에 재배치한 검증 후보이며, `trailer_013_career_record_filter.png`가 `41-45s` 마지막 구간에서 보정 후보 회차, 동일 사례 회고, 성장 비교를 노출한다.");
        builder.AppendLine("- 승격하려면 리마스터 컷을 업로드용 비트레이트로 재인코딩하거나, 상점 제출안에서 공식 업로드 후보 파일명을 명시적으로 교체해야 한다.");
        builder.AppendLine("- current_bytes: " + currentBytes);
        builder.AppendLine("- remaster_bytes: " + remasterBytes);
        builder.AppendLine("- current_sha256: " + ComputeSha256(currentUploadPath));
        builder.AppendLine("- remaster_sha256: " + ComputeSha256(remasterPath));
        return builder.ToString();
    }

    private static string BuildTrailerRemasterUploadSwitchMarkdown(string currentUploadPath, string remasterUploadPath, string remasterUploadProbePath)
    {
        long currentBytes = File.Exists(currentUploadPath) ? new FileInfo(currentUploadPath).Length : 0L;
        long candidateBytes = File.Exists(remasterUploadPath) ? new FileInfo(remasterUploadPath).Length : 0L;
        bool candidateReady =
            File.Exists(remasterUploadPath) &&
            candidateBytes > 10_000_000L &&
            FileContainsAll(remasterUploadProbePath, "\"duration\": \"45.000000\"", "\"codec_name\": \"h264\"", "\"width\": 1920", "\"height\": 1080", "\"codec_name\": \"aac\"") &&
            File.Exists(Path.Combine(Path.GetDirectoryName(remasterUploadPath), "trailer_steam_upload_remaster_upload_contact_sheet.png")) &&
            !SafeReadAllText("Logs/ffmpeg_trailer_steam_upload_remaster_upload_blackdetect.log").Contains("black_start");

        StringBuilder builder = new();
        builder.AppendLine("# 트레일러 리마스터 업로드 switch");
        builder.AppendLine();
        builder.AppendLine("switch_id: trailer_remaster_upload_v0.3.0");
        builder.AppendLine("current_selection: current_upload");
        builder.AppendLine("switch_state: ready_not_applied");
        builder.AppendLine("current_file: care_review_office_trailer_steam_upload_v0.3.0.mp4");
        builder.AppendLine("candidate_file: care_review_office_trailer_steam_upload_v0.3.0_remaster_upload.mp4");
        builder.AppendLine("rollback_file: care_review_office_trailer_steam_upload_v0.3.0.mp4");
        builder.AppendLine("candidate_validation: " + (candidateReady ? "passed" : "failed"));
        builder.AppendLine();
        builder.AppendLine("- 기본 선택은 기존 고비트레이트 Steam 업로드 후보를 유지한다.");
        builder.AppendLine("- 리마스터 업로드 후보로 전환하려면 `current_selection`을 `remaster_upload_candidate`로 바꾸고, 상점 제출안의 업로드 후보 파일명도 같은 파일로 교체한다.");
        builder.AppendLine("- 전환 후 마케팅 감사와 릴리즈 후보 감사를 다시 실행한다.");
        builder.AppendLine("- 문제 발생 시 `rollback_file`로 되돌리고 switch를 `current_upload`로 복구한다.");
        builder.AppendLine("- current_bytes: " + currentBytes);
        builder.AppendLine("- candidate_bytes: " + candidateBytes);
        builder.AppendLine("- current_sha256: " + ComputeSha256(currentUploadPath));
        builder.AppendLine("- candidate_sha256: " + ComputeSha256(remasterUploadPath));
        return builder.ToString();
    }

    private static void AddRequiredPngAsset(MarketingAssetAudit audit, string category, string path, int expectedWidth, int expectedHeight, long minimumBytes, string note)
    {
        MarketingAssetAuditRow row = NewMarketingAssetRow(category, path, note);
        row.expectedWidth = expectedWidth;
        row.expectedHeight = expectedHeight;
        row.minimumBytes = minimumBytes;
        if (row.exists)
        {
            row.bytes = new FileInfo(path).Length;
            if (TryReadPngDimensions(path, out int width, out int height))
            {
                row.actualWidth = width;
                row.actualHeight = height;
            }
        }

        row.dimensionsMatch = row.exists && row.actualWidth == expectedWidth && row.actualHeight == expectedHeight;
        row.minimumBytesMet = row.exists && row.bytes >= minimumBytes;
        row.passed = row.exists && row.dimensionsMatch && row.minimumBytesMet && row.noPortableUnsafePath;
        audit.rows.Add(row);
    }

    private static void AddBinaryAsset(MarketingAssetAudit audit, string category, string path, long minimumBytes, string note)
    {
        MarketingAssetAuditRow row = NewMarketingAssetRow(category, path, note);
        row.minimumBytes = minimumBytes;
        if (row.exists)
        {
            row.bytes = new FileInfo(path).Length;
        }

        row.dimensionsMatch = true;
        row.minimumBytesMet = row.exists && row.bytes >= minimumBytes;
        row.passed = row.exists && row.minimumBytesMet && row.noPortableUnsafePath;
        audit.rows.Add(row);
    }

    private static void AddTextManifestAsset(MarketingAssetAudit audit, string category, string path, params string[] requiredTokens)
    {
        MarketingAssetAuditRow row = NewMarketingAssetRow(category, path, "text manifest");
        string content = SafeReadAllText(path);
        row.bytes = row.exists ? new FileInfo(path).Length : 0L;
        row.dimensionsMatch = true;
        row.minimumBytesMet = row.exists && row.bytes > 0L;
        row.noPortableUnsafePath = row.exists && !ContainsPortableUnsafePath(content);
        bool hasRequiredTokens = row.exists;
        foreach (string token in requiredTokens)
        {
            if (!content.Contains(token))
            {
                hasRequiredTokens = false;
                break;
            }
        }

        row.passed = row.exists && row.minimumBytesMet && row.noPortableUnsafePath && hasRequiredTokens;
        if (!hasRequiredTokens)
        {
            row.note = "required token missing";
        }

        audit.rows.Add(row);
    }

    private static MarketingAssetAuditRow NewMarketingAssetRow(string category, string path, string note)
    {
        return new MarketingAssetAuditRow
        {
            category = category,
            path = path.Replace("\\", "/"),
            fileName = Path.GetFileName(path),
            exists = File.Exists(path),
            noPortableUnsafePath = !ContainsPortableUnsafePath(path),
            note = note
        };
    }

