        builder.AppendLine("  \"trailerRemasterUploadCandidateReady\": " + BoolJson(audit.trailerRemasterUploadCandidateReady) + ",");
        builder.AppendLine("  \"hasTrailerRemasterPromotionGate\": " + BoolJson(audit.hasTrailerRemasterPromotionGate) + ",");
