            builder.AppendLine("    {");
            builder.AppendLine("      \"category\": \"" + EscapeJson(row.category) + "\",");
            builder.AppendLine("      \"fileName\": \"" + EscapeJson(row.fileName) + "\",");
            builder.AppendLine("      \"path\": \"" + EscapeJson(row.path) + "\",");
            builder.AppendLine("      \"exists\": " + BoolJson(row.exists) + ",");
            builder.AppendLine("      \"passed\": " + BoolJson(row.passed) + ",");
            builder.AppendLine("      \"expectedWidth\": " + row.expectedWidth + ",");
            builder.AppendLine("      \"expectedHeight\": " + row.expectedHeight + ",");
            builder.AppendLine("      \"actualWidth\": " + row.actualWidth + ",");
            builder.AppendLine("      \"actualHeight\": " + row.actualHeight + ",");
            builder.AppendLine("      \"bytes\": " + row.bytes + ",");
            builder.AppendLine("      \"minimumBytes\": " + row.minimumBytes + ",");
