            builder.Append("    }");
            if (i < audit.rows.Count - 1)
            {
                builder.AppendLine(",");
            }
            else
            {
                builder.AppendLine();
            }
        }
        builder.AppendLine("  ]");
        builder.AppendLine("}");
        return builder.ToString();
    }

    private static string BuildMarketingAssetAuditCsv(MarketingAssetAudit audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("category,fileName,passed,expectedWidth,expectedHeight,actualWidth,actualHeight,bytes,minimumBytes,dimensionsMatch,minimumBytesMet,noPortableUnsafePath,note,path");
        foreach (MarketingAssetAuditRow row in audit.rows)
        {
            builder.AppendLine(
                CsvCell(row.category) + "," +
                CsvCell(row.fileName) + "," +
                BoolJson(row.passed) + "," +
                row.expectedWidth + "," +
                row.expectedHeight + "," +
                row.actualWidth + "," +
                row.actualHeight + "," +
                row.bytes + "," +
                row.minimumBytes + "," +
                BoolJson(row.dimensionsMatch) + "," +
                BoolJson(row.minimumBytesMet) + "," +
                BoolJson(row.noPortableUnsafePath) + "," +
                CsvCell(row.note) + "," +
                CsvCell(row.path));
        }

        return builder.ToString();
    }

