        builder.AppendLine("- 리마스터 후보: " + audit.trailerRemasterBytes + " bytes, candidateReady=" + (audit.trailerRemasterCandidateReady ? "yes" : "no") + ", promoted=" + (audit.trailerRemasterPromotedAsSteamUpload ? "yes" : "no"));
        builder.AppendLine("- 리마스터 업로드 후보: " + audit.trailerRemasterUploadCandidateBytes + " bytes, uploadCandidateReady=" + (audit.trailerRemasterUploadCandidateReady ? "yes" : "no"));
