        builder.AppendLine("- 상점 후보 캠페인 기록 상세 줄바꿈 시각 검수: " + (audit.storeCandidateCareerRecordDetailWrapVisualChecked ? "yes" : "no"));
        builder.AppendLine("- 상점 후보 UI 힌트 시각 검수: " + (audit.storeCandidateUiHintVisualChecked ? "yes" : "no"));
        builder.AppendLine("- 상점 후보 판단 복기 포커스 시각 검수: " + (audit.storeCandidateDecisionAuditCoachingFocusVisualChecked ? "yes" : "no"));
        builder.AppendLine();
        builder.AppendLine("| 구분 | 파일 | 통과 | 규격 | 실제 | 용량 | 비고 |");
        builder.AppendLine("| --- | --- | --- | --- | --- | ---: | --- |");
        foreach (MarketingAssetAuditRow row in audit.rows)
        {
            string expectedSize = row.expectedWidth > 0 ? row.expectedWidth + "x" + row.expectedHeight : "-";
            string actualSize = row.actualWidth > 0 ? row.actualWidth + "x" + row.actualHeight : "-";
            builder.AppendLine("| " + row.category + " | `" + row.fileName + "` | " + (row.passed ? "yes" : "no") + " | " + expectedSize + " | " + actualSize + " | " + row.bytes + " | " + row.note + " |");
        }

        return builder.ToString();
    }

