    private static void AddPackageAuditCheck(ReleaseCandidateAudit audit, string label, string zipPath, string hashPath, long minimumBytes)
    {
        bool zipExists = File.Exists(zipPath);
        bool hashExists = File.Exists(hashPath);
        long bytes = zipExists ? new FileInfo(zipPath).Length : 0L;
        string actualHash = zipExists ? ComputeSha256(zipPath) : "";
        string recordedHash = hashExists ? File.ReadAllText(hashPath, Encoding.UTF8).Trim() : "";
        bool passed = zipExists && hashExists && bytes >= minimumBytes && string.Equals(actualHash, recordedHash, StringComparison.OrdinalIgnoreCase);
        string evidence = Path.GetFileName(zipPath) + " bytes=" + bytes + " hash=" + (string.IsNullOrEmpty(actualHash) ? "missing" : actualHash);
        AddReleaseCandidateCheck(audit, label, passed, evidence);
    }

    private static DistributionIntegrityAudit BuildDistributionIntegrityAudit()
    {
        Directory.CreateDirectory(DistributionIntegrityAuditPath);

        DistributionIntegrityAudit audit = new()
        {
            generatedAt = DateTime.Now.ToString("s"),
            version = ReleaseVersion,
            rows = new List<DistributionIntegrityRow>()
        };

        string releaseZipPath = Path.Combine(ReleaseRootPath, ReleasePackageName + ".zip");
        string releaseHashPath = Path.Combine(ReleaseRootPath, ReleasePackageName + "_SHA256.txt");
        string playtestZipPath = "Builds/Playtest/CareReviewOffice_PlaytestKit_v0.3.0.zip";
        string playtestHashPath = "Builds/Playtest/CareReviewOffice_PlaytestKit_v0.3.0_SHA256.txt";
        string steamworksZipPath = "Builds/Steamworks/CareReviewOffice_Steamworks_v0.3.0.zip";
        string steamworksHashPath = "Builds/Steamworks/CareReviewOffice_Steamworks_v0.3.0_SHA256.txt";
        string handoffZipPath = ExternalValidationHandoffZipPath;
        string handoffHashPath = ExternalValidationHandoffHashPath;
        string playtestReleaseZipPath = "Builds/Playtest/v0.3.0/" + ReleasePackageName + ".zip";
        string playtestReleaseHashPath = "Builds/Playtest/v0.3.0/" + ReleasePackageName + "_SHA256.txt";

        BuildExternalReleaseGateAudit();

        string releaseHash = SafeReadAllText(releaseHashPath).Trim();
        string playtestHash = SafeReadAllText(playtestHashPath).Trim();
        string steamworksHash = SafeReadAllText(steamworksHashPath).Trim();
        string handoffHash = SafeReadAllText(handoffHashPath).Trim();
        string releaseActualHash = File.Exists(releaseZipPath) ? ComputeSha256(releaseZipPath) : releaseHash;
        string playtestActualHash = File.Exists(playtestZipPath) ? ComputeSha256(playtestZipPath) : playtestHash;
        string steamworksActualHash = File.Exists(steamworksZipPath) ? ComputeSha256(steamworksZipPath) : steamworksHash;
        string handoffActualHash = File.Exists(handoffZipPath) ? ComputeSha256(handoffZipPath) : handoffHash;
        long releaseBytes = File.Exists(releaseZipPath) ? new FileInfo(releaseZipPath).Length : 0L;
        long playtestBytes = File.Exists(playtestZipPath) ? new FileInfo(playtestZipPath).Length : 0L;
        long steamworksBytes = File.Exists(steamworksZipPath) ? new FileInfo(steamworksZipPath).Length : 0L;
        long handoffBytes = File.Exists(handoffZipPath) ? new FileInfo(handoffZipPath).Length : 0L;
        SyncHumanDocsReleaseZipSha(releaseActualHash);
        SyncHumanDocsPlaytestZipSha(playtestActualHash, playtestBytes);
        SyncHumanDocsHandoffZipSha(handoffActualHash, handoffBytes);
        SyncHumanDocsSteamworksZipSha(steamworksActualHash, steamworksBytes);
        SyncHumanDocsReadmeSmokeZipSha(steamworksActualHash, steamworksBytes, handoffActualHash, handoffBytes);

        AddDistributionIntegrityCheck(audit, "릴리즈 zip 해시 기록 일치", PackageHashMatches(releaseZipPath, releaseHashPath, 50_000_000L, out string releaseEvidence), releaseEvidence);
        AddDistributionIntegrityCheck(audit, "플레이테스트 kit zip 해시 기록 일치", PackageHashMatches(playtestZipPath, playtestHashPath, 50_000_000L, out string playtestEvidence), playtestEvidence);
        AddDistributionIntegrityCheck(audit, "Steamworks zip 해시 기록 일치", PackageHashMatches(steamworksZipPath, steamworksHashPath, 50_000_000L, out string steamworksEvidence), steamworksEvidence);
        AddDistributionIntegrityCheck(audit, "외부 검증 handoff zip 해시 기록 일치", PackageHashMatches(handoffZipPath, handoffHashPath, 1_000L, out string handoffEvidence), handoffEvidence);
        AddDistributionIntegrityCheck(audit, "플레이어 메타데이터 출시명 적용", ReleasePlayerMetadataUsesReleaseNames(), "ProjectSettings + app.info use release company/product names and exclude SNU/Prototype/Final Project");
        AddDistributionIntegrityCheck(audit, "플레이어 자동 업로드/Analytics 설정 비활성", ReleasePlayerCloudUploadSettingsDisabled(), "ProjectSettings submitAnalytics/cloud disabled and UnityConnect analytics/diagnostics/ads/performance reporting disabled");
        AddDistributionIntegrityCheck(audit, "플레이어 멀티플레이어 센터 패키지 제외", ReleasePlayerExcludesMultiplayerCenterPackage(), "Packages and player builds exclude unused Unity Multiplayer Center package/assembly");
        AddDistributionIntegrityCheck(audit, "플레이어 Unity 패키지 최소 manifest", ReleaseManifestContainsOnlyNeededPlayerPackages(), "Packages manifest/lock keep only player runtime packages and required transitive UGUI modules");
        AddDistributionIntegrityCheck(audit, "플레이어 Resources 폐기 리소스 제외", ReleaseResourcesExcludeDeprecatedFallbackArt(), "Assets/Resources excludes deprecated fallback/source art sheets");
        AddDistributionIntegrityCheck(audit, "플레이어 Resources 런타임 자산 allowlist", ReleaseResourcesContainOnlyPlayerRuntimeAssets(), "Assets/Resources contains only current player art/audio/data/font assets");
