    private static bool PackageHashMatches(string zipPath, string hashPath, long minimumBytes, out string evidence)
    {
        bool zipExists = File.Exists(zipPath);
        bool hashExists = File.Exists(hashPath);
        long bytes = zipExists ? new FileInfo(zipPath).Length : 0L;
        string actualHash = zipExists ? ComputeSha256(zipPath) : "";
        string recordedHash = hashExists ? SafeReadAllText(hashPath).Trim() : "";
        bool passed = zipExists && hashExists && bytes >= minimumBytes && string.Equals(actualHash, recordedHash, StringComparison.OrdinalIgnoreCase);
        evidence = Path.GetFileName(zipPath) + " bytes=" + bytes + " actual=" + (string.IsNullOrEmpty(actualHash) ? "missing" : actualHash) + " recorded=" + (string.IsNullOrEmpty(recordedHash) ? "missing" : recordedHash);
        return passed;
    }

    private static void AddDistributionIntegrityCheck(DistributionIntegrityAudit audit, string label, bool passed, string evidence)
    {
        audit.rows.Add(new DistributionIntegrityRow
        {
            label = label,
            passed = passed,
            evidence = evidence
        });
    }

