    private static void ReplaceLineContaining(string path, string marker, string replacement)
    {
        if (!File.Exists(path))
        {
            return;
        }

        string[] lines = File.ReadAllLines(path, Encoding.UTF8);
        bool changed = false;
        for (int i = 0; i < lines.Length; i++)
        {
            if (lines[i].Contains(marker, StringComparison.Ordinal) && !string.Equals(lines[i], replacement, StringComparison.Ordinal))
            {
                lines[i] = replacement;
                changed = true;
            }
        }

        if (changed)
        {
            File.WriteAllLines(path, lines, new UTF8Encoding(false));
        }
    }

    private static bool ZipEntryTextContains(string zipPath, string entryName, string expectedText)
    {
        if (string.IsNullOrEmpty(expectedText))
        {
            return false;
        }

        string text = ReadZipEntryText(zipPath, entryName);
        return !string.IsNullOrEmpty(text) && text.Contains(expectedText);
    }

    private static bool ZipEntryTextEquals(string zipPath, string entryName, string expectedText)
    {
        if (string.IsNullOrEmpty(expectedText))
        {
            return false;
        }

        string text = ReadZipEntryText(zipPath, entryName).Trim();
        return string.Equals(text, expectedText, StringComparison.OrdinalIgnoreCase);
    }

    private static string ReadZipEntryText(string zipPath, string entryName)
    {
        if (!File.Exists(zipPath))
        {
            return "";
        }

        try
        {
            using ZipArchive archive = ZipFile.OpenRead(zipPath);
            ZipArchiveEntry entry = archive.GetEntry(entryName);
            if (entry == null)
            {
                return "";
            }

            using Stream stream = entry.Open();
            using StreamReader reader = new(stream, Encoding.UTF8);
            return reader.ReadToEnd();
        }
        catch
        {
            return "";
        }
    }

    private static byte[] ReadZipEntryBytes(string zipPath, string entryName)
    {
        if (!File.Exists(zipPath))
        {
            return Array.Empty<byte>();
        }

        try
        {
            using ZipArchive archive = ZipFile.OpenRead(zipPath);
            ZipArchiveEntry entry = archive.GetEntry(entryName);
            if (entry == null)
            {
                return Array.Empty<byte>();
            }

            using Stream stream = entry.Open();
            using MemoryStream memory = new();
            stream.CopyTo(memory);
            return memory.ToArray();
        }
        catch
        {
            return Array.Empty<byte>();
        }
    }

    private static bool ZipEntryBytesExist(string zipPath, string entryName)
    {
        return ReadZipEntryBytes(zipPath, entryName).Length > 0;
    }

    private static byte[] ReadFileBytes(string path)
    {
        if (!File.Exists(path))
        {
            return Array.Empty<byte>();
        }

        try
        {
            return File.ReadAllBytes(path);
        }
        catch
        {
            return Array.Empty<byte>();
        }
    }

    private static string BuildDistributionIntegrityAuditJson(DistributionIntegrityAudit audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("{");
        builder.AppendLine("  \"generatedAt\": \"" + EscapeJson(audit.generatedAt) + "\",");
        builder.AppendLine("  \"version\": \"" + EscapeJson(audit.version) + "\",");
        builder.AppendLine("  \"auditCompleted\": " + BoolJson(audit.auditCompleted) + ",");
        builder.AppendLine("  \"allPassed\": " + BoolJson(audit.allPassed) + ",");
        builder.AppendLine("  \"hasHandoffTriageActionsCsv\": " + BoolJson(audit.hasHandoffTriageActionsCsv) + ",");
        builder.AppendLine("  \"handoffZipContainsTriageActionsCsv\": " + BoolJson(audit.handoffZipContainsTriageActionsCsv) + ",");
        builder.AppendLine("  \"hasHandoffStoreCandidateHashManifest\": " + BoolJson(audit.hasHandoffStoreCandidateHashManifest) + ",");
        builder.AppendLine("  \"handoffZipContainsStoreCandidateHashManifest\": " + BoolJson(audit.handoffZipContainsStoreCandidateHashManifest) + ",");
        builder.AppendLine("  \"checkCount\": " + audit.checkCount + ",");
        builder.AppendLine("  \"passedCheckCount\": " + audit.passedCheckCount + ",");
        builder.AppendLine("  \"checks\": [");
        for (int i = 0; i < audit.rows.Count; i++)
        {
            DistributionIntegrityRow row = audit.rows[i];
            builder.AppendLine("    {");
            builder.AppendLine("      \"label\": \"" + EscapeJson(row.label) + "\",");
            builder.AppendLine("      \"passed\": " + BoolJson(row.passed) + ",");
            builder.AppendLine("      \"evidence\": \"" + EscapeJson(row.evidence) + "\"");
            builder.Append("    }");
            builder.AppendLine(i == audit.rows.Count - 1 ? "" : ",");
        }

        builder.AppendLine("  ]");
        builder.AppendLine("}");
        return builder.ToString();
    }

    private static string BuildDistributionIntegrityAuditCsv(DistributionIntegrityAudit audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("label,passed,evidence");
        foreach (DistributionIntegrityRow row in audit.rows)
        {
            builder.Append(EscapeCsv(row.label)).Append(',')
                .Append(row.passed ? "true" : "false").Append(',')
                .AppendLine(EscapeCsv(row.evidence));
        }

        return builder.ToString();
    }

    private static string BuildDistributionIntegrityAuditMarkdown(DistributionIntegrityAudit audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("# 배포 패킷 무결성 감사");
        builder.AppendLine();
        builder.AppendLine("- 생성 시각: " + audit.generatedAt);
        builder.AppendLine("- 대상 버전: " + audit.version);
        builder.AppendLine("- 통과: " + audit.passedCheckCount + " / " + audit.checkCount);
        builder.AppendLine("- 전체 통과: " + (audit.allPassed ? "yes" : "no"));
        builder.AppendLine();
        builder.AppendLine("| Check | Pass | Evidence |");
        builder.AppendLine("| --- | --- | --- |");
        foreach (DistributionIntegrityRow row in audit.rows)
        {
            builder.Append("| ").Append(row.label).Append(" | ")
                .Append(row.passed ? "yes" : "no").Append(" | ")
                .Append(row.evidence.Replace("|", "/")).AppendLine(" |");
        }

        return builder.ToString();
    }

