    private static void AddSteamPreflightAudit(ReleaseCandidateAudit audit)
    {
        string preflightPath = Path.Combine(SteamworksRootPath, "STEAM_SUBMISSION_PREFLIGHT_KO.md");
        bool exists = File.Exists(preflightPath);
        AddReleaseCandidateCheck(audit, "Steam 제출 전 자체점검 보고서", exists, preflightPath);
        if (!exists)
        {
            return;
        }

        List<string> localUnchecked = new();
        foreach (string line in File.ReadAllLines(preflightPath, Encoding.UTF8))
        {
            string trimmed = line.Trim();
            if (!trimmed.StartsWith("- [ ]", StringComparison.Ordinal))
            {
                continue;
            }

            if (trimmed.Contains("ACTION REQUIRED"))
            {
                string externalAction = trimmed.Replace("- [ ] ACTION REQUIRED: ", "");
                if (!PreflightExternalActionSatisfied(externalAction))
                {
                    AddExternalAction(audit, externalAction);
                }
            }
            else
            {
                if (trimmed.Contains("릴리즈 후보 감사 결과"))
                {
                    continue;
                }
                localUnchecked.Add(trimmed);
            }
        }

        AddReleaseCandidateCheck(audit, "프리플라이트 로컬 미해결 항목 없음", localUnchecked.Count == 0, localUnchecked.Count == 0 ? "only ACTION REQUIRED remains" : string.Join(" | ", localUnchecked));
    }

    private static bool PreflightExternalActionSatisfied(string action)
    {
        if (ContainsOrdinalIgnoreCase(action, "AppID"))
        {
            return SteamAppIdConfigured(out _);
        }

        if (ContainsOrdinalIgnoreCase(action, "DepotID"))
        {
            return SteamDepotIdConfigured(out _);
        }

        if (ContainsOrdinalIgnoreCase(action, "SteamCMD preview"))
        {
            return SteamCmdPreviewPassed(out _) ||
                ExternalGateEvidenceNotePassed("STEAMCMD_PREVIEW", out _, "SteamCMD", "Preview", "통과");
        }

        if (ContainsOrdinalIgnoreCase(action, "비공개 테스트 브랜치"))
        {
            return ExternalGateEvidenceNotePassed("PRIVATE_BRANCH", out _, "Steam", "비공개", "실행");
        }

        if (ContainsOrdinalIgnoreCase(action, "Store Presence"))
        {
            return ExternalGateEvidenceNotePassed("STORE_PRESENCE", out _, "상점", "스크린샷", "캡슐", "트레일러", "SHA", "A/B", "selected_upload_set", "promoted_candidate", "decision_audit_coaching_candidate_evidence", "14_case_archive_decision_audit_coaching_focus.png", "복기 W-207", "decision_audit_coaching_hud_evidence", "reviewHudUpdatesAfterDecision=true", "briefing_retrospective_candidate_evidence", "storeCandidateMentionsBriefingRetrospective=true", "브리핑 회고");
        }

        if (ContainsOrdinalIgnoreCase(action, "Achievements"))
        {
            return ExternalGateEvidenceNotePassed("ACHIEVEMENTS", out _, "12", "API");
        }

        return false;
    }

    private static void AddReleaseCandidateCheck(ReleaseCandidateAudit audit, string label, bool passed, string evidence)
    {
        audit.checks.Add(new ReleaseCandidateCheck
        {
            label = label,
            passed = passed,
            evidence = evidence
        });
    }

    private static void RefreshReleaseCandidateDistributionIntegrityCheck(ReleaseCandidateAudit audit)
    {
        DistributionIntegrityAudit distributionAudit = BuildDistributionIntegrityAudit();
        bool passed = distributionAudit.allPassed &&
            FileContainsAll(
                Path.Combine(DistributionIntegrityAuditPath, "care_review_distribution_integrity_smoke_result.json"),
                "\"completed\": true",
                "\"allPassed\": true",
                "\"hasHandoffTriageActionsCsv\": true",
                "\"handoffZipContainsTriageActionsCsv\": true",
                "\"hasHandoffStoreCandidateHashManifest\": true",
                "\"handoffZipContainsStoreCandidateHashManifest\": true");
        UpdateReleaseCandidateCheck(audit, "배포 패킷 무결성 QA", passed, "Builds/QA/v0.3.0/distribution_integrity");
    }

    private static void UpdateReleaseCandidateCheck(ReleaseCandidateAudit audit, string label, bool passed, string evidence)
    {
        foreach (ReleaseCandidateCheck check in audit.checks)
        {
            if (string.Equals(check.label, label, StringComparison.Ordinal))
            {
                check.passed = passed;
                check.evidence = evidence;
                return;
            }
        }

        AddReleaseCandidateCheck(audit, label, passed, evidence);
    }

    private static void RecalculateReleaseCandidateSummary(ReleaseCandidateAudit audit)
    {
        audit.localBlockerCount = 0;
        foreach (ReleaseCandidateCheck check in audit.checks)
        {
            if (!check.passed)
            {
                audit.localBlockerCount++;
            }
        }

        audit.checkCount = audit.checks.Count;
        audit.passedCheckCount = audit.checkCount - audit.localBlockerCount;
        audit.externalActionCount = audit.externalActions.Count;
        audit.optionalExternalValidationCount = audit.optionalExternalValidations.Count;
        audit.localReleaseCandidateReady = audit.localBlockerCount == 0;
        audit.steamPublicReleaseReady = audit.localReleaseCandidateReady && audit.externalActionCount == 0;
    }

    private static void AddExternalAction(ReleaseCandidateAudit audit, string action)
    {
        if (!string.IsNullOrEmpty(OptionalExternalValidationCategory(action)) ||
            action.StartsWith("5명 이상에게 플레이테스트", StringComparison.Ordinal) ||
            action.StartsWith("완전 회수 10명 이상", StringComparison.Ordinal) ||
            action.Contains("플레이테스트 키트 배포", StringComparison.Ordinal) ||
            action.Contains("완전 회수 10명 이상 확보", StringComparison.Ordinal))
        {
            AddOptionalExternalValidation(audit, action);
            return;
        }

        if (action.StartsWith("실제 사람 플레이테스트 -", StringComparison.Ordinal) &&
            HasExternalActionPrefix(audit.externalActions, "실제 사람 플레이테스트 "))
        {
            return;
        }

        if (!audit.externalActions.Contains(action))
        {
            audit.externalActions.Add(action);
        }
    }

    private static void AddOptionalExternalValidation(ReleaseCandidateAudit audit, string action)
    {
        string category = OptionalExternalValidationCategory(action);
        if (!string.IsNullOrEmpty(category))
        {
            foreach (string existingAction in audit.optionalExternalValidations)
            {
                string existingCategory = OptionalExternalValidationCategory(existingAction);
                if (string.Equals(existingCategory, category, StringComparison.Ordinal) ||
                    (string.Equals(category, "human_playtest_general", StringComparison.Ordinal) &&
                        existingCategory.StartsWith("human_playtest_", StringComparison.Ordinal)))
                {
                    return;
                }
            }
        }

        if (action.StartsWith("실제 사람 플레이테스트 -", StringComparison.Ordinal) &&
            HasExternalActionPrefix(audit.optionalExternalValidations, "실제 사람 플레이테스트 "))
        {
            return;
        }

        if (!audit.optionalExternalValidations.Contains(action))
        {
            audit.optionalExternalValidations.Add(action);
        }
    }

    private static string OptionalExternalValidationCategory(string action)
    {
        if (action.Contains("5명 이상", StringComparison.Ordinal))
        {
            return "human_playtest_5";
        }

        if (action.Contains("10명 이상", StringComparison.Ordinal))
        {
            return "human_playtest_10";
        }

        if (action.StartsWith("실제 사람 플레이테스트", StringComparison.Ordinal))
        {
            return "human_playtest_general";
        }

        return "";
    }

    private static bool HasExternalActionPrefix(List<string> actions, string prefix)
    {
        foreach (string existingAction in actions)
        {
            if (existingAction.StartsWith(prefix, StringComparison.Ordinal))
            {
                return true;
            }
        }

        return false;
    }

    private static bool HashesMatch(string leftPath, string rightPath)
    {
        return File.Exists(leftPath) &&
            File.Exists(rightPath) &&
            string.Equals(ComputeSha256(leftPath), ComputeSha256(rightPath), StringComparison.OrdinalIgnoreCase);
    }

    private static bool PngDimensionsMatch(string path, int expectedWidth, int expectedHeight)
    {
        return File.Exists(path) &&
            TryReadPngDimensions(path, out int width, out int height) &&
            width == expectedWidth &&
            height == expectedHeight;
    }

    private static string ComputeSha256(string path)
    {
        try
        {
            using SHA256 sha256 = SHA256.Create();
            using FileStream stream = File.OpenRead(path);
            byte[] hash = sha256.ComputeHash(stream);
            StringBuilder builder = new();
            foreach (byte value in hash)
            {
                builder.Append(value.ToString("X2"));
            }

            return builder.ToString();
        }
        catch
        {
            return "";
        }
    }

    private static string ComputeSha256(byte[] bytes)
    {
        using SHA256 sha256 = SHA256.Create();
        byte[] hash = sha256.ComputeHash(bytes);
        StringBuilder builder = new();
        foreach (byte value in hash)
        {
            builder.Append(value.ToString("X2"));
        }

        return builder.ToString();
    }

    private static string ShortHash(string hash)
    {
        return string.IsNullOrWhiteSpace(hash) || hash.Length < 12
            ? hash
            : hash.Substring(0, 12);
    }

    private static string BuildReleaseCandidateAuditJson(ReleaseCandidateAudit audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("{");
        builder.AppendLine("  \"generatedAt\": \"" + EscapeJson(audit.generatedAt) + "\",");
        builder.AppendLine("  \"version\": \"" + EscapeJson(audit.version) + "\",");
        builder.AppendLine("  \"localReleaseCandidateReady\": " + BoolJson(audit.localReleaseCandidateReady) + ",");
        builder.AppendLine("  \"steamPublicReleaseReady\": " + BoolJson(audit.steamPublicReleaseReady) + ",");
        builder.AppendLine("  \"checkCount\": " + audit.checkCount + ",");
        builder.AppendLine("  \"passedCheckCount\": " + audit.passedCheckCount + ",");
        builder.AppendLine("  \"localBlockerCount\": " + audit.localBlockerCount + ",");
        builder.AppendLine("  \"externalActionCount\": " + audit.externalActionCount + ",");
        builder.AppendLine("  \"optionalExternalValidationCount\": " + audit.optionalExternalValidationCount + ",");
        AppendReleaseCandidateStorePresenceEvidenceBundleJson(builder, audit);
        builder.AppendLine("  \"checks\": [");
        for (int i = 0; i < audit.checks.Count; i++)
        {
            ReleaseCandidateCheck check = audit.checks[i];
            builder.AppendLine("    {");
            builder.AppendLine("      \"label\": \"" + EscapeJson(check.label) + "\",");
            builder.AppendLine("      \"passed\": " + BoolJson(check.passed) + ",");
            builder.AppendLine("      \"evidence\": \"" + EscapeJson(check.evidence) + "\"");
            builder.Append("    }");
            builder.AppendLine(i == audit.checks.Count - 1 ? "" : ",");
        }
        builder.AppendLine("  ],");
        builder.AppendLine("  \"externalActions\": [");
        for (int i = 0; i < audit.externalActions.Count; i++)
        {
            builder.Append("    \"").Append(EscapeJson(audit.externalActions[i])).Append("\"");
            builder.AppendLine(i == audit.externalActions.Count - 1 ? "" : ",");
        }
        builder.AppendLine("  ],");
        builder.AppendLine("  \"optionalExternalValidations\": [");
        for (int i = 0; i < audit.optionalExternalValidations.Count; i++)
        {
            builder.Append("    \"").Append(EscapeJson(audit.optionalExternalValidations[i])).Append("\"");
            builder.AppendLine(i == audit.optionalExternalValidations.Count - 1 ? "" : ",");
        }
        builder.AppendLine("  ]");
        builder.AppendLine("}");
        return builder.ToString();
    }

    private static void AppendReleaseCandidateStorePresenceEvidenceBundleJson(StringBuilder builder, ReleaseCandidateAudit audit)
    {
        string[] labels = StorePresenceEvidenceBundleLabels();
        int passedCount = 0;
        foreach (string label in labels)
        {
            ReleaseCandidateCheck check = FindReleaseCandidateCheck(audit, label);
            if (check != null && check.passed)
            {
                passedCount++;
            }
        }

        builder.AppendLine("  \"storePresenceEvidenceBundle\": {");
        builder.AppendLine("    \"label\": \"보정 후보 / Store Presence 증거 묶음\",");
        builder.AppendLine("    \"checkCount\": " + labels.Length + ",");
        builder.AppendLine("    \"passedCheckCount\": " + passedCount + ",");
        builder.AppendLine("    \"allPassed\": " + BoolJson(passedCount == labels.Length) + ",");
        builder.AppendLine("    \"uploadManifestCrossReference\": \"STEAMWORKS_UPLOAD_MANIFEST.txt; Store Presence release candidate JSON cross-check; Store Presence evidence bundle\",");
        builder.AppendLine("    \"checks\": [");
        for (int i = 0; i < labels.Length; i++)
        {
            ReleaseCandidateCheck check = FindReleaseCandidateCheck(audit, labels[i]);
            bool passed = check != null && check.passed;
            string evidence = check == null ? "missing release candidate check" : check.evidence;
            builder.AppendLine("      {");
            builder.AppendLine("        \"label\": \"" + EscapeJson(labels[i]) + "\",");
            builder.AppendLine("        \"passed\": " + BoolJson(passed) + ",");
            builder.AppendLine("        \"evidence\": \"" + EscapeJson(evidence) + "\",");
            builder.AppendLine("        \"memberSummary\": \"" + EscapeJson(BuildStorePresenceEvidenceBundleMemberSummary(labels[i], evidence)) + "\"");
            builder.Append("      }");
            builder.AppendLine(i == labels.Length - 1 ? "" : ",");
        }
        builder.AppendLine("    ]");
        builder.AppendLine("  },");
    }

    private static string BuildStorePresenceEvidenceBundleMemberSummary(string label, string evidence)
    {
        if (string.Equals(label, "외부 handoff 문서 Store Presence A/B 응답 회수 입력란 요약", StringComparison.Ordinal))
        {
            return "draft=Evidence/STORE_PRESENCE.md; fields=screenshot_ab_loop_response_count,screenshot_ab_loop_not_collected_count,screenshot_ab_loop_collection_status,screenshot_ab_loop_understanding_comment_count; mapping=store_presence_ab_todo_mapping; sources=post_external_collection_promotion_summary,main_menu_loop_entry,menu_campaign_briefing_weakness,achievement_career_copy_alignment,reward_loop_understanding; priority_badges=store_presence_priority_badge_backreference:triage_priority_badge_reward_loop_candidate/P0_WAIT_EXTERNAL_AB,store_presence_main_menu_baseline_backreference:triage_priority_badge_main_menu_baseline/P1_BASELINE_GUARD,store_presence_copy_alignment_backreference:triage_priority_badge_copy_alignment/P1_COPY_ALIGNMENT_COLLECT; values=screenshot_ab_loop_response_count=0,screenshot_ab_loop_not_collected_count=221,screenshot_ab_loop_collection_status=waiting_for_screenshot_ab_loop_responses,screenshot_ab_loop_understanding_comment_count=0";
        }

        if (string.Equals(label, "Store Presence 브리핑 회고 후보 근거 입력란", StringComparison.Ordinal))
        {
            return "draft=Evidence/STORE_PRESENCE.md; fields=briefing_retrospective_candidate_evidence,briefing_retrospective_candidate_file,briefing_retrospective_candidate_terms,briefing_retrospective_candidate_smoke; source=care_review_career_record_smoke_result.json; candidate=12_career_record_next_objective.png; values=storeCandidateMentionsBriefingRetrospective=true,브리핑 회고,예고 위험,실제 결과";
        }

        if (string.Equals(label, "Store Presence 14번 판단 복기 HUD 근거", StringComparison.Ordinal))
        {
            return "draft=Evidence/STORE_PRESENCE.md; fields=decision_audit_coaching_hud_evidence,decision_audit_coaching_hud_terms; source=care_review_decision_audit_coaching_hud_smoke_result.json; candidate=14_case_archive_decision_audit_coaching_focus.png; values=판단 복기 진행,coachingStateApplied=true,reviewHudMentionsCoachingObjective=true,reviewHudUpdatesAfterDecision=true";
        }

        return "evidence=" + evidence;
    }

    private static bool ReleaseCandidateStorePresenceEvidenceBundleReady(ReleaseCandidateAudit audit)
    {
        string[] labels = StorePresenceEvidenceBundleLabels();
        foreach (string label in labels)
        {
            ReleaseCandidateCheck check = FindReleaseCandidateCheck(audit, label);
            if (check == null || !check.passed)
            {
                return false;
            }
        }

        return true;
    }

