    private static int StorePresenceEvidenceBundlePassedCount(ReleaseCandidateAudit audit)
    {
        int passedCount = 0;
        foreach (string label in StorePresenceEvidenceBundleLabels())
        {
            ReleaseCandidateCheck check = FindReleaseCandidateCheck(audit, label);
            if (check != null && check.passed)
            {
                passedCount++;
            }
        }

        return passedCount;
    }

    private static string[] StorePresenceEvidenceBundleLabels()
    {
        return new[]
        {
            "상점 Store Presence 통합 선택 manifest",
            "상점 Store Presence 통합 선택 회귀",
