    private static string BuildReleaseCandidateAuditCsv(ReleaseCandidateAudit audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("label,passed,evidence,store_presence_bundle_member,store_presence_bundle_summary");
        foreach (ReleaseCandidateCheck check in audit.checks)
        {
            builder.Append(EscapeCsv(check.label)).Append(',')
                .Append(check.passed ? "true" : "false").Append(',')
                .Append(EscapeCsv(check.evidence)).Append(',')
                .Append(IsStorePresenceEvidenceBundleLabel(check.label) ? "true" : "false").Append(',')
                .AppendLine("false");
        }

        AppendReleaseCandidateStorePresenceEvidenceBundleCsvSummary(builder, audit);
        return builder.ToString();
    }

    private static void AppendReleaseCandidateStorePresenceEvidenceBundleCsvSummary(StringBuilder builder, ReleaseCandidateAudit audit)
    {
        string[] labels = StorePresenceEvidenceBundleLabels();
        int passedCount = 0;
        foreach (string label in labels)
        {
            ReleaseCandidateCheck check = FindReleaseCandidateCheck(audit, label);
            if (check != null && check.passed)
            {
                passedCount++;
            }
        }

        bool allPassed = passedCount == labels.Length;
        string evidence = "checkCount=" + labels.Length + "; passedCheckCount=" + passedCount + "; allPassed=" + BoolJson(allPassed) + "; preflight=STEAM_SUBMISSION_PREFLIGHT_KO.md; preflight_check=외부 검증 Store Presence 증거 묶음 요약";
        builder.Append(EscapeCsv("STORE_PRESENCE_EVIDENCE_BUNDLE_SUMMARY")).Append(',')
            .Append(allPassed ? "true" : "false").Append(',')
            .Append(EscapeCsv(evidence)).Append(',')
            .Append("false,")
            .AppendLine("true");
    }

