    private static string BuildReleaseCandidateAuditMarkdown(ReleaseCandidateAudit audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("# 릴리즈 후보 감사 리포트");
        builder.AppendLine();
        builder.AppendLine("- 생성 시각: " + audit.generatedAt);
        builder.AppendLine("- 대상 버전: " + audit.version);
        builder.AppendLine("- 로컬 체크: " + audit.passedCheckCount + " / " + audit.checkCount);
        builder.AppendLine("- 로컬 미해결 항목: " + audit.localBlockerCount);
        builder.AppendLine("- Steam 제출 전 필수 외부 항목: " + audit.externalActionCount);
        builder.AppendLine("- 선택적 외부 검증 항목: " + audit.optionalExternalValidationCount);
        builder.AppendLine();
        builder.AppendLine("## 판정");
        builder.AppendLine();
        builder.AppendLine(audit.localReleaseCandidateReady
            ? "- [x] 로컬 릴리즈 후보 산출물은 패키지/상점 사본/QA 증거 기준을 통과했다."
            : "- [ ] 로컬 릴리즈 후보 산출물에 미해결 항목이 있다.");
        builder.AppendLine(audit.steamPublicReleaseReady
            ? "- [x] Steam 공개 제출 전 필수 외부 항목도 모두 완료됐다."
            : "- [ ] Steam 공개 제출 전 필수 외부 항목이 남아 있다.");
        builder.AppendLine();
        AppendReleaseCandidateStorePresenceDraftStatus(builder);
        builder.AppendLine();
        AppendReleaseCandidateStorePresenceEvidenceBundle(builder, audit);
        builder.AppendLine();
        builder.AppendLine("## 로컬 체크");
        builder.AppendLine();
        builder.AppendLine("| Check | Pass | Evidence |");
        builder.AppendLine("| --- | --- | --- |");
        foreach (ReleaseCandidateCheck check in audit.checks)
        {
            builder.Append("| ").Append(check.label).Append(" | ")
                .Append(check.passed ? "yes" : "no").Append(" | ")
                .Append(check.evidence.Replace("|", "/")).AppendLine(" |");
        }

        builder.AppendLine();
        builder.AppendLine("## Steam 제출 전 필수 외부 항목");
        builder.AppendLine();
        if (audit.externalActions.Count == 0)
        {
            builder.AppendLine("- 없음");
        }
        else
        {
            foreach (string action in audit.externalActions)
            {
                builder.AppendLine("- [ ] " + action);
            }
        }

        builder.AppendLine();
        builder.AppendLine("## 선택적 외부 검증 항목");
        builder.AppendLine();
        if (audit.optionalExternalValidations.Count == 0)
        {
            builder.AppendLine("- 없음");
        }
        else
        {
            foreach (string action in audit.optionalExternalValidations)
            {
                builder.AppendLine("- [ ] " + action);
            }
        }

        return builder.ToString();
    }

    private static void AppendReleaseCandidateStorePresenceEvidenceBundle(StringBuilder builder, ReleaseCandidateAudit audit)
    {
        builder.AppendLine("## 보정 후보 / Store Presence 증거 묶음");
        builder.AppendLine();
        builder.AppendLine("| Evidence Group | Pass | Source |");
        builder.AppendLine("| --- | --- | --- |");
        foreach (string label in StorePresenceEvidenceBundleLabels())
        {
            AppendReleaseCandidateEvidenceBundleRow(builder, audit, label);
