    private static void AppendReleaseCandidateEvidenceBundleRow(StringBuilder builder, ReleaseCandidateAudit audit, string label)
    {
        ReleaseCandidateCheck check = FindReleaseCandidateCheck(audit, label);
        bool passed = check != null && check.passed;
        string evidence = check == null ? "missing release candidate check" : check.evidence;
        builder.Append("| ").Append(label).Append(" | ")
            .Append(passed ? "yes" : "no").Append(" | ")
            .Append(evidence.Replace("|", "/")).AppendLine(" |");
    }

    private static ReleaseCandidateCheck FindReleaseCandidateCheck(ReleaseCandidateAudit audit, string label)
    {
        foreach (ReleaseCandidateCheck check in audit.checks)
        {
            if (string.Equals(check.label, label, StringComparison.Ordinal))
            {
                return check;
            }
        }

        return null;
    }

    private static void BuildExternalValidationHandoffFiles(ReleaseCandidateAudit audit)
    {
        Directory.CreateDirectory(ExternalValidationHandoffPath);
        BuildExternalGateEvidenceTemplates();

        string[] fileNames =
        {
            "README_KO.txt",
            "EXTERNAL_RELEASE_HANDOFF_KO.md",
            "EXTERNAL_RELEASE_GATE_TRACKER.csv",
            "TESTER_RECRUITMENT_BATCH_KO.md",
            "LOW_SPEC_PC_QA_CARD_KO.md",
            "STEAM_PRIVATE_BRANCH_QA_CARD_KO.md",
            "STORE_PRESENCE_QA_CARD_KO.md",
            "PLAYTEST_COMMERCIAL_TRIAGE_ACTIONS.csv",
            "STORE_CANDIDATE_CAPTURE_SYNC_HASHES.sha256",
            "ACHIEVEMENT_TOAST_UI_CAPTURE.md"
        };

        File.WriteAllText(Path.Combine(ExternalValidationHandoffPath, fileNames[0]), BuildExternalValidationReadme(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(ExternalValidationHandoffPath, fileNames[1]), BuildExternalReleaseHandoffMarkdown(audit), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(ExternalValidationHandoffPath, fileNames[2]), BuildExternalReleaseGateTrackerCsv(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(ExternalValidationHandoffPath, fileNames[3]), BuildTesterRecruitmentBatchMarkdown(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(ExternalValidationHandoffPath, fileNames[4]), BuildLowSpecQaCardMarkdown(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(ExternalValidationHandoffPath, fileNames[5]), BuildSteamPrivateBranchQaCardMarkdown(), new UTF8Encoding(false));
        File.WriteAllText(Path.Combine(ExternalValidationHandoffPath, fileNames[6]), BuildStorePresenceQaCardMarkdown(), new UTF8Encoding(false));
        string actionCsvSourcePath = Path.Combine(PlaytestCollectionAuditPath, "care_review_playtest_commercial_triage_actions.csv");
        string actionCsvBody = File.Exists(actionCsvSourcePath)
            ? File.ReadAllText(actionCsvSourcePath, Encoding.UTF8)
            : "priority,area,owner_screen,owner_screen_evidence,support_bundle_manifest_handoff_zip_sha256,evidence,recommendation\n";
        File.WriteAllText(Path.Combine(ExternalValidationHandoffPath, fileNames[7]), actionCsvBody, new UTF8Encoding(false));
        CopyStoreCandidateCaptureHashManifest(Path.Combine(ExternalValidationHandoffPath, fileNames[8]));
        CopyAchievementToastUiCaptureMarkdown(Path.Combine(ExternalValidationHandoffPath, fileNames[9]));

        if (Directory.Exists(SteamworksRootPath))
        {
            foreach (string fileName in fileNames)
            {
                File.Copy(Path.Combine(ExternalValidationHandoffPath, fileName), Path.Combine(SteamworksRootPath, fileName), true);
            }
        }

        PackageExternalValidationHandoff();
    }

    private static void CopyAchievementToastUiCaptureMarkdown(string destinationPath)
    {
        string sourcePath = "Builds/QA/v0.3.0/achievement_toast/care_review_achievement_toast_ui_capture.md";
        Directory.CreateDirectory(Path.GetDirectoryName(destinationPath));
        if (File.Exists(sourcePath))
        {
            File.Copy(sourcePath, destinationPath, true);
            return;
        }

        File.WriteAllText(
            destinationPath,
            "# Achievement Toast UI Capture\n\n- ready: false\n- readable: false\n- source missing: `Builds/QA/v0.3.0/achievement_toast/care_review_achievement_toast_ui_capture.md`\n",
            new UTF8Encoding(false));
    }

    private static void PackageExternalValidationHandoff()
    {
        if (!Directory.Exists(ExternalValidationHandoffPath))
        {
            return;
        }

        Directory.CreateDirectory(Path.GetDirectoryName(ExternalValidationHandoffZipPath));
        if (File.Exists(ExternalValidationHandoffZipPath))
        {
            File.Delete(ExternalValidationHandoffZipPath);
        }

        string rootName = new DirectoryInfo(ExternalValidationHandoffPath).Name;
        using (FileStream zipStream = new(ExternalValidationHandoffZipPath, FileMode.CreateNew))
        using (ZipArchive archive = new(zipStream, ZipArchiveMode.Create))
        {
            string[] files = Directory.GetFiles(ExternalValidationHandoffPath, "*", SearchOption.AllDirectories);
            Array.Sort(files, StringComparer.OrdinalIgnoreCase);
            DateTimeOffset stableTimestamp = new(2026, 5, 31, 0, 0, 0, TimeSpan.Zero);
            foreach (string file in files)
            {
                string relativePath = Path.GetRelativePath(ExternalValidationHandoffPath, file).Replace("\\", "/");
                ZipArchiveEntry entry = archive.CreateEntry(rootName + "/" + relativePath, System.IO.Compression.CompressionLevel.Optimal);
                entry.LastWriteTime = stableTimestamp;
                using Stream entryStream = entry.Open();
                using FileStream fileStream = File.OpenRead(file);
                fileStream.CopyTo(entryStream);
            }
        }

        File.WriteAllText(ExternalValidationHandoffHashPath, ComputeSha256(ExternalValidationHandoffZipPath), new UTF8Encoding(false));
    }

    private static void RefreshSteamSubmissionPreflightIfPossible()
    {
        if (!Directory.Exists(SteamworksContentPath))
        {
            return;
        }

        int contentFileCount = CountFiles(SteamworksContentPath);
        long contentBytes = SumFileBytes(SteamworksContentPath);
        string zipHashPath = Path.Combine(ReleaseRootPath, ReleasePackageName + "_SHA256.txt");
        string zipHash = File.Exists(zipHashPath) ? File.ReadAllText(zipHashPath, Encoding.UTF8).Trim() : "not generated";
        Directory.CreateDirectory(SteamworksRootPath);
        File.WriteAllText(Path.Combine(SteamworksRootPath, "STEAM_SUBMISSION_PREFLIGHT_KO.md"), BuildSteamSubmissionPreflightReport(contentFileCount, contentBytes, zipHash), new UTF8Encoding(false));
    }

