    private static string BuildPlaytestCollectionAuditCsv(PlaytestCollectionAudit audit)
    {
        StringBuilder builder = new();
        builder.AppendLine("session_id,source,received_via_support_bundle,support_bundle_name,has_support_bundle_manifest,support_bundle_has_runtime_issues,support_bundle_triage_actions_csv_reference,support_bundle_external_handoff_hash_reference,support_bundle_external_handoff_zip_sha256,support_bundle_has_external_handoff_hash,complete,decision_rows,has_play_log,has_survey,has_diagnostic,has_campaign_grade,has_next_campaign_objective,files_have_no_local_absolute_path,commercial_checklist_aggregate_cross_check_ready,commercial_checklist_aggregate_covers_collection_surveys,commercial_checklist_aggregate_survey_count,commercial_checklist_aggregate_replay_reward_positive_count,commercial_checklist_aggregate_price_value_positive_count,commercial_checklist_aggregate_replay_intent_positive_count,commercial_checklist_aggregate_follow_up_count,screenshot_ab_loop_aggregate_summary_ready,screenshot_ab_loop_question_column_ready,screenshot_ab_loop_question_id_count,screenshot_ab_loop_response_count,screenshot_ab_loop_not_collected_count,screenshot_ab_loop_achievement_next_goal_preference_count,screenshot_ab_loop_career_record_preference_count,screenshot_ab_loop_both_clear_preference_count,screenshot_ab_loop_both_unclear_preference_count,screenshot_ab_loop_understanding_comment_count,notes");
        foreach (PlaytestSessionAuditRow row in audit.rows)
        {
            builder.Append(EscapeCsv(row.sessionId)).Append(',')
                .Append(EscapeCsv(row.source)).Append(',')
                .Append(row.receivedViaSupportBundle ? "true" : "false").Append(',')
                .Append(EscapeCsv(row.supportBundleName)).Append(',')
                .Append(row.hasSupportBundleManifest ? "true" : "false").Append(',')
                .Append(row.supportBundleHasRuntimeIssues ? "true" : "false").Append(',')
                .Append(EscapeCsv(row.supportBundleTriageActionsCsvReferencePath)).Append(',')
                .Append(EscapeCsv(row.supportBundleExternalHandoffHashReferencePath)).Append(',')
                .Append(EscapeCsv(row.supportBundleExternalHandoffZipSha256)).Append(',')
                .Append(row.supportBundleHasExternalHandoffHash ? "true" : "false").Append(',')
                .Append(row.complete ? "true" : "false").Append(',')
                .Append(row.decisionRows).Append(',')
                .Append(row.hasPlayLogJson && row.hasPlayLogCsv ? "true" : "false").Append(',')
                .Append(row.hasSurveyJson && row.hasSurveyMarkdown && row.hasSurveyRatings ? "true" : "false").Append(',')
                .Append(row.hasDiagnosticJson && row.hasDiagnosticMarkdown && row.hasDiagnosticFrameSample ? "true" : "false").Append(',')
                .Append(row.hasCampaignGrade ? "true" : "false").Append(',')
                .Append(row.hasNextCampaignObjective ? "true" : "false").Append(',')
                .Append(row.filesHaveNoLocalAbsolutePath ? "true" : "false").Append(',')
                .Append(audit.commercialChecklistAggregateSummaryCrossCheckReady ? "true" : "false").Append(',')
                .Append(audit.commercialChecklistAggregateCoversCollectionSurveys ? "true" : "false").Append(',')
                .Append(audit.commercialChecklistAggregateSurveyCount).Append(',')
                .Append(audit.commercialChecklistAggregateReplayRewardPositiveCount).Append(',')
                .Append(audit.commercialChecklistAggregatePriceValuePositiveCount).Append(',')
                .Append(audit.commercialChecklistAggregateReplayIntentPositiveCount).Append(',')
                .Append(audit.commercialChecklistAggregateFollowUpCount).Append(',')
                .Append(audit.screenshotAbLoopAggregateSummaryReady ? "true" : "false").Append(',')
                .Append(audit.screenshotAbLoopQuestionColumnReady ? "true" : "false").Append(',')
                .Append(audit.screenshotAbLoopQuestionIdCount).Append(',')
                .Append(audit.screenshotAbLoopResponseCount).Append(',')
                .Append(audit.screenshotAbLoopNotCollectedCount).Append(',')
                .Append(audit.screenshotAbLoopAchievementNextGoalPreferenceCount).Append(',')
                .Append(audit.screenshotAbLoopCareerRecordPreferenceCount).Append(',')
                .Append(audit.screenshotAbLoopBothClearPreferenceCount).Append(',')
                .Append(audit.screenshotAbLoopBothUnclearPreferenceCount).Append(',')
                .Append(audit.screenshotAbLoopUnderstandingCommentCount).Append(',')
                .AppendLine(EscapeCsv(row.notes));
        }

        return builder.ToString();
    }

