        builder.AppendLine("- 선호 후보: `10_achievement_next_goal.png` " + audit.screenshotAbLoopAchievementNextGoalPreferenceCount + "건, `12_career_record_next_objective.png` " + audit.screenshotAbLoopCareerRecordPreferenceCount + "건, 둘 다 이해됨 " + audit.screenshotAbLoopBothClearPreferenceCount + "건, 둘 다 불명확 " + audit.screenshotAbLoopBothUnclearPreferenceCount + "건");
        builder.AppendLine("- 이해 코멘트: " + audit.screenshotAbLoopUnderstandingCommentCount + "건");
        builder.AppendLine("- 회수 판정 연결: 응답 회수가 `recommendedHumanMinimum` 이상 쌓이면 `SCREENSHOT_CANDIDATE_AB_TEST_KO.md`와 Store Presence QA 카드의 성과-캠페인 루프 승격 판단에 반영한다.");
        builder.AppendLine();
        builder.AppendLine("## 판정");
        builder.AppendLine();
        builder.AppendLine(audit.readyForBalanceTuning
            ? "- [x] 5명 이상 완전 회수 기준을 충족해 밸런스 조정 근거로 사용할 수 있다."
            : "- [ ] 5명 이상 완전 회수 기준 미달. 실제 사람 플레이테스트 회수가 필요하다.");
        builder.AppendLine(audit.readyForCommercialTuning
            ? "- [x] 10명 이상 완전 회수 기준을 충족해 10달러 판매 후보 밸런스 판단에 사용할 수 있다."
            : "- [ ] 10명 이상 완전 회수 기준 미달. 판매 후보 밸런스 판단 전 추가 회수가 필요하다.");
        builder.AppendLine();
        builder.AppendLine("## 세션별 점검");
        builder.AppendLine();
        builder.AppendLine("| Session | Source | Bundle | Handoff SHA | Complete | Decisions | Survey | Diagnostic | Grade | Next | Path Safe | Notes |");
        builder.AppendLine("| --- | --- | --- | --- | --- | ---: | --- | --- | --- | --- | --- | --- |");
        foreach (PlaytestSessionAuditRow row in audit.rows)
        {
            builder.Append("| `").Append(row.sessionId).Append("` | ")
                .Append(row.source).Append(" | ")
                .Append(row.receivedViaSupportBundle ? "yes" : "no").Append(" | ")
                .Append(row.supportBundleHasExternalHandoffHash ? ShortHash(row.supportBundleExternalHandoffZipSha256) : "").Append(" | ")
                .Append(row.complete ? "yes" : "no").Append(" | ")
                .Append(row.decisionRows).Append(" | ")
                .Append(row.hasSurveyJson && row.hasSurveyMarkdown && row.hasSurveyRatings ? "yes" : "no").Append(" | ")
                .Append(row.hasDiagnosticJson && row.hasDiagnosticMarkdown && row.hasDiagnosticFrameSample ? "yes" : "no").Append(" | ")
                .Append(row.hasCampaignGrade ? "yes" : "no").Append(" | ")
                .Append(row.hasNextCampaignObjective ? "yes" : "no").Append(" | ")
                .Append(row.filesHaveNoLocalAbsolutePath ? "yes" : "no").Append(" | ")
                .Append(row.notes).AppendLine(" |");
        }

        return builder.ToString();
    }

    private static void PopulateCommercialChecklistAggregateCrossCheck(PlaytestCollectionAudit audit)
    {
        const string aggregateJsonPath = "Builds/QA/v0.3.0/playtest_packet/care_review_playtest_aggregate.json";
        const string aggregateMarkdownPath = "Builds/QA/v0.3.0/playtest_packet/care_review_playtest_aggregate.md";
        const string aggregateSmokePath = "Builds/QA/v0.3.0/playtest_packet/care_review_playtest_aggregate_smoke_result.json";

        string aggregateJson = SafeReadAllText(aggregateJsonPath);
        string aggregateMarkdown = SafeReadAllText(aggregateMarkdownPath);
        string aggregateSmoke = SafeReadAllText(aggregateSmokePath);
        bool jsonReady = ExtractJsonBool(aggregateJson, "commercialChecklistAggregateSummaryReady") &&
            aggregateJson.Contains("\"commercialChecklistSurveyCount\"") &&
            aggregateJson.Contains("\"commercialChecklistPriceValuePositiveCount\"") &&
            aggregateJson.Contains("\"commercialChecklistReplayRewardPositiveCount\"") &&
            aggregateJson.Contains("\"commercialChecklistReplayIntentPositiveCount\"") &&
            aggregateJson.Contains("\"commercialChecklistFollowUpCount\"");
        bool markdownReady = aggregateMarkdown.Contains("상용화 보강 체크 응답 요약") &&
            aggregateMarkdown.Contains("성과 기록") &&
            aggregateMarkdown.Contains("캠페인 기록") &&
            aggregateMarkdown.Contains("상점 후보") &&
            aggregateMarkdown.Contains("다시 할 이유") &&
            aggregateMarkdown.Contains("PLAYTEST_COMMERCIAL_TRIAGE_ACTIONS.csv");
        bool smokeReady = aggregateSmoke.Contains("\"jsonHasCommercialChecklistAggregateSummary\": true") &&
            aggregateSmoke.Contains("\"markdownMentionsCommercialChecklistSummary\": true");

        audit.commercialChecklistAggregateSourcePath = aggregateJsonPath;
        audit.commercialChecklistAggregateMarkdownPath = aggregateMarkdownPath;
        audit.commercialChecklistAggregateSmokePath = aggregateSmokePath;
        audit.commercialChecklistAggregateSurveyCount = ExtractJsonInt(aggregateJson, "commercialChecklistSurveyCount");
        audit.commercialChecklistAggregatePriceValuePositiveCount = ExtractJsonInt(aggregateJson, "commercialChecklistPriceValuePositiveCount");
        audit.commercialChecklistAggregateReplayRewardPositiveCount = ExtractJsonInt(aggregateJson, "commercialChecklistReplayRewardPositiveCount");
        audit.commercialChecklistAggregateReplayIntentPositiveCount = ExtractJsonInt(aggregateJson, "commercialChecklistReplayIntentPositiveCount");
        audit.commercialChecklistAggregateFollowUpCount = ExtractJsonInt(aggregateJson, "commercialChecklistFollowUpCount");
        audit.commercialChecklistAggregateCoversCollectionSurveys = audit.commercialChecklistAggregateSurveyCount >= audit.surveySessionCount;
        audit.commercialChecklistAggregateSummaryCrossCheckReady = jsonReady &&
            markdownReady &&
            smokeReady &&
            audit.commercialChecklistAggregateCoversCollectionSurveys;
    }

    private static void PopulateScreenshotAbLoopAggregateCrossCheck(PlaytestCollectionAudit audit)
    {
        const string sessionsIndexPath = "Builds/QA/v0.3.0/playtest_packet/care_review_playtest_sessions_index.csv";
        const string aggregateSmokePath = "Builds/QA/v0.3.0/playtest_packet/care_review_playtest_aggregate_smoke_result.json";

        audit.screenshotAbLoopAggregateSourcePath = sessionsIndexPath;
        if (!File.Exists(sessionsIndexPath))
        {
            return;
        }

        string aggregateSmoke = SafeReadAllText(aggregateSmokePath);
        string[] lines = File.ReadAllLines(sessionsIndexPath, Encoding.UTF8);
        if (lines.Length == 0)
        {
            return;
        }

        List<string> header = ParseCsvLine(lines[0]);
        int questionIdIndex = header.IndexOf("screenshot_ab_loop_question_id");
        int preferredCandidateIndex = header.IndexOf("screenshot_ab_loop_preferred_candidate");
        int understandingCommentIndex = header.IndexOf("screenshot_ab_loop_understanding_comment");
        audit.screenshotAbLoopQuestionColumnReady = questionIdIndex >= 0 &&
            header.IndexOf("screenshot_ab_loop_question_text") >= 0 &&
            preferredCandidateIndex >= 0 &&
            understandingCommentIndex >= 0 &&
            aggregateSmoke.Contains("\"csvHasScreenshotAbLoopQuestionColumns\": true");

        if (!audit.screenshotAbLoopQuestionColumnReady)
        {
            return;
        }

        for (int i = 1; i < lines.Length; i++)
        {
            if (string.IsNullOrWhiteSpace(lines[i]))
            {
                continue;
            }

            List<string> cells = ParseCsvLine(lines[i]);
            string questionId = GetCsvCell(cells, questionIdIndex);
            string preferredCandidate = GetCsvCell(cells, preferredCandidateIndex);
            string understandingComment = GetCsvCell(cells, understandingCommentIndex);
            if (string.IsNullOrWhiteSpace(questionId))
            {
                continue;
            }

            audit.screenshotAbLoopQuestionIdCount++;
            string normalizedPreference = preferredCandidate.Trim();
            if (string.IsNullOrWhiteSpace(normalizedPreference) ||
                normalizedPreference.Equals("not_collected", StringComparison.OrdinalIgnoreCase))
            {
                audit.screenshotAbLoopNotCollectedCount++;
            }
            else
            {
                audit.screenshotAbLoopResponseCount++;
                if (normalizedPreference.Equals("10_achievement_next_goal.png", StringComparison.OrdinalIgnoreCase))
                {
                    audit.screenshotAbLoopAchievementNextGoalPreferenceCount++;
                }
                else if (normalizedPreference.Equals("12_career_record_next_objective.png", StringComparison.OrdinalIgnoreCase))
                {
                    audit.screenshotAbLoopCareerRecordPreferenceCount++;
                }
                else if (normalizedPreference.Contains("둘 다 이해", StringComparison.Ordinal))
                {
                    audit.screenshotAbLoopBothClearPreferenceCount++;
                }
                else if (normalizedPreference.Contains("둘 다 불명확", StringComparison.Ordinal))
                {
                    audit.screenshotAbLoopBothUnclearPreferenceCount++;
                }
            }

            if (!string.IsNullOrWhiteSpace(understandingComment) &&
                !understandingComment.Equals("not_collected", StringComparison.OrdinalIgnoreCase))
            {
                audit.screenshotAbLoopUnderstandingCommentCount++;
            }
        }

        audit.screenshotAbLoopAggregateSummaryReady = audit.screenshotAbLoopQuestionColumnReady &&
            audit.screenshotAbLoopQuestionIdCount > 0 &&
            audit.screenshotAbLoopQuestionIdCount == audit.screenshotAbLoopResponseCount + audit.screenshotAbLoopNotCollectedCount;
    }

    private static List<string> ParseCsvLine(string line)
    {
        List<string> cells = new();
        if (line == null)
        {
            return cells;
        }

        StringBuilder cell = new();
        bool inQuotes = false;
        for (int i = 0; i < line.Length; i++)
        {
            char current = line[i];
            if (current == '"')
            {
                if (inQuotes && i + 1 < line.Length && line[i + 1] == '"')
                {
                    cell.Append('"');
                    i++;
                }
                else
                {
                    inQuotes = !inQuotes;
                }
            }
            else if (current == ',' && !inQuotes)
            {
                cells.Add(cell.ToString());
                cell.Length = 0;
            }
            else
            {
                cell.Append(current);
            }
        }

        cells.Add(cell.ToString());
        return cells;
    }

    private static string GetCsvCell(List<string> cells, int index)
    {
        return index >= 0 && index < cells.Count ? cells[index] : "";
    }

    private static PlaytestCommercialTriageReport BuildPlaytestCommercialTriageReport(PlaytestCollectionAudit audit)
    {
        List<PlaytestSessionAuditRow> surveyRows = new();
        List<PlaytestSessionAuditRow> completeHumanRows = new();
        foreach (PlaytestSessionAuditRow row in audit.rows)
        {
            if (row.hasSurveyRatings)
            {
                surveyRows.Add(row);
            }

            if (row.complete && row.source == "external_inbox")
            {
                completeHumanRows.Add(row);
            }
        }

        List<PlaytestSessionAuditRow> ratingRows = completeHumanRows.Count > 0 ? completeHumanRows : surveyRows;
        PlaytestCommercialTriageReport report = new()
        {
            generatedAt = DateTime.Now.ToString("s"),
            evidenceScope = completeHumanRows.Count > 0 ? "external_complete_sessions" : "qa_or_incomplete_survey_sessions",
            completeHumanSessionCount = completeHumanRows.Count,
            totalSurveySessionCount = surveyRows.Count,
            externalSurveySessionCount = CountRowsBySource(surveyRows, "external_inbox"),
            qaSurveySessionCount = CountRowsBySource(surveyRows, "qa_sample_archive"),
            supportBundleExternalHandoffHashCount = audit.supportBundleExternalHandoffHashCount,
            externalHandoffZipSha256 = FirstSupportBundleHandoffSha(audit.rows),
            recommendedHumanMinimum = audit.recommendedHumanMinimum,
            recommendedCommercialMinimum = audit.recommendedCommercialMinimum,
            averageDifficultyRating = AverageRating(ratingRows, RatingMetric.Difficulty),
            averageDecisionClarityRating = AverageRating(ratingRows, RatingMetric.DecisionClarity),
            averageResultFairnessRating = AverageRating(ratingRows, RatingMetric.ResultFairness),
            averageUiReadabilityRating = AverageRating(ratingRows, RatingMetric.UiReadability),
            averagePriceValueRating = AverageRating(ratingRows, RatingMetric.PriceValue),
            averageReplayRewardValueRating = AverageRating(ratingRows, RatingMetric.ReplayRewardValue),
            replayIntentPercent = AverageBoolPercent(ratingRows, BoolMetric.ReplayIntent),
            difficultyTooHighCount = CountBoolRows(ratingRows, BoolMetric.DifficultyTooHigh),
            uiNeedsWorkCount = CountBoolRows(ratingRows, BoolMetric.UiNeedsWork),
            caseExplanationNeededCount = CountBoolRows(ratingRows, BoolMetric.CaseExplanationNeeded),
            rows = new List<PlaytestCommercialTriageRow>(),
            actions = new List<PlaytestCommercialTriageAction>()
        };

        report.hasTriageOutputs = true;
        report.enoughForBalanceTuning = report.completeHumanSessionCount >= audit.recommendedHumanMinimum;
        report.enoughForCommercialTuning = report.completeHumanSessionCount >= audit.recommendedCommercialMinimum;
        report.priceValueReady = report.averagePriceValueRating >= 4f && report.replayIntentPercent >= 70f;
        report.replayRewardValueReady = report.averageReplayRewardValueRating >= 4f;
        report.usabilityReady = report.averageUiReadabilityRating >= 4f && report.averageDecisionClarityRating >= 4f;
        report.fairnessReady = report.averageResultFairnessRating >= 4f && report.averageDifficultyRating >= 2.8f && report.averageDifficultyRating <= 4.4f;

        foreach (PlaytestSessionAuditRow row in ratingRows)
        {
            report.rows.Add(new PlaytestCommercialTriageRow
            {
                sessionId = row.sessionId,
                source = row.source,
                complete = row.complete,
                campaignMandateName = row.campaignMandateName,
                campaignGrade = row.campaignGrade,
                campaignScore = row.campaignScore,
                endingTitle = row.endingTitle,
                difficultyRating = row.difficultyRating,
                decisionClarityRating = row.decisionClarityRating,
                resultFairnessRating = row.resultFairnessRating,
                uiReadabilityRating = row.uiReadabilityRating,
                priceValueRating = row.priceValueRating,
                replayRewardValueRating = row.replayRewardValueRating,
                supportBundleExternalHandoffZipSha256 = row.supportBundleExternalHandoffZipSha256,
                supportBundleHasExternalHandoffHash = row.supportBundleHasExternalHandoffHash,
                replayIntent = row.replayIntent,
                difficultyTooHigh = row.difficultyTooHigh,
                uiNeedsWork = row.uiNeedsWork,
                caseExplanationNeeded = row.caseExplanationNeeded
            });
        }

        AppendCommercialTriageActions(report);
        report.actionCount = report.actions.Count;
        report.readyForTenDollarCommercialTuning = report.enoughForCommercialTuning &&
            report.priceValueReady &&
            report.replayRewardValueReady &&
            report.usabilityReady &&
            report.fairnessReady &&
            report.actionCount == 0;
        report.readinessStatus = BuildCommercialTriageStatus(report);
        return report;
    }

    private static void AppendCommercialTriageActions(PlaytestCommercialTriageReport report)
    {
        if (report.completeHumanSessionCount < report.recommendedHumanMinimum)
        {
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "high",
                area = "회수 수량",
                ownerScreen = "플레이테스트 회수 패킷",
                evidence = $"완전 회수 외부 세션 {report.completeHumanSessionCount}/{report.recommendedHumanMinimum}",
                recommendation = "최소 5명 이상 실제 사람 플레이 로그, 설문, 환경 진단을 완전 회수한다."
            });
        }

        if (report.completeHumanSessionCount < report.recommendedCommercialMinimum)
        {
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "high",
                area = "10달러 판매 후보 근거",
                ownerScreen = "플레이테스트 회수 패킷 / 상점 판단",
                evidence = $"완전 회수 외부 세션 {report.completeHumanSessionCount}/{report.recommendedCommercialMinimum}",
                recommendation = "10명 이상 완전 회수 후 가격 가치감과 재플레이 의향 평균을 다시 판단한다."
            });
        }

        if (report.totalSurveySessionCount == 0)
        {
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "high",
                area = "설문 누락",
                ownerScreen = "최종 리포트 설문 / 로그 저장",
                evidence = "5점 척도 설문 세션 0건",
                recommendation = "최종 리포트의 테스터 설문 저장 후 로그 저장을 안내 문구 맨 앞에 둔다."
            });
            return;
        }

        if (report.averagePriceValueRating > 0f && report.averagePriceValueRating < 4f)
        {
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "high",
                area = "10달러 가치감",
                ownerScreen = "상점 페이지 / 반복 목표 안내",
                evidence = $"평균 {FormatFloat(report.averagePriceValueRating)}/5",
                recommendation = "반복 플레이 목표, 엔딩 기록, 사례 다양성, 상점 설명의 가치 제안을 우선 보강한다."
            });
        }

        if (report.averageReplayRewardValueRating > 0f && report.averageReplayRewardValueRating < 4f)
        {
            string replayRewardEvidence = $"평균 {FormatFloat(report.averageReplayRewardValueRating)}/5";
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "high",
                area = "반복 보상/장기 기록 가치감",
                ownerScreen = "성과 기록 / 캠페인 기록 / 상점 페이지",
                evidence = replayRewardEvidence,
                recommendation = "성과 반복 보상 이력, 캠페인 기록 필터, 장기 추세 패널이 다음 회차 목표로 보이는지 우선 확인하고 상점/튜토리얼 문구를 보강한다."
            });
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "high",
                area = "반복 가치 세부: 성과 기록 보상",
                ownerScreen = "성과 기록",
                evidence = replayRewardEvidence + "; 설문 축=성과 기록 보상",
                recommendation = "성과 반복 보상 패널의 2/4/6회 누적 보상, 다음 목표 버튼, 기록 이동 힌트가 재플레이 보상으로 읽히는지 우선 확인한다."
            });
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "high",
                area = "반복 가치 세부: 캠페인 기록 다음 목표",
                ownerScreen = "캠페인 기록",
                evidence = replayRewardEvidence + "; 설문 축=캠페인 기록 다음 목표",
                recommendation = "캠페인 기록의 액션 안내, 다음 목표/목표 재시작 버튼, 후보 결과 필터가 다음 회차 행동으로 바로 이어지는지 확인한다."
            });
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "high",
                area = "반복 가치 세부: 상점 후보 루프 이해",
                ownerScreen = "상점 페이지 / Store Candidate",
                evidence = replayRewardEvidence + "; 설문 축=상점 후보 루프 이해",
                recommendation = "01/10/12번 후보 스크린샷과 A/B 질문에서 목표 실행 -> 캠페인 기록 -> 보상 누적 루프가 한눈에 읽히는지 확인한다."
            });
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "high",
                area = "우선순위 배지: 상점 후보 루프 이해",
                ownerScreen = "상점 페이지 / Store Candidate",
                evidence = "triage_priority_badge_reward_loop_candidate/P0_WAIT_EXTERNAL_AB; evidence=post_external_collection_promotion_summary",
                recommendation = "A/B 응답 5건 전까지 12번 후보를 유지하고, 회수 후 selected_upload_set/promoted_candidate 갱신 여부를 결정한다."
            });
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "high",
                area = "우선순위 배지: 메인 메뉴 기준 화면",
                ownerScreen = "메인 메뉴 / Store Presence 기준 화면",
                evidence = "triage_priority_badge_main_menu_baseline/P1_BASELINE_GUARD; evidence=main_menu_loop_entry",
                recommendation = "01번 메인 메뉴 후보가 성과 보기 진입과 반복 목표를 첫 화면에서 설명하는지 A/B 응답과 대조한다."
            });
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "high",
                area = "우선순위 배지: 성과-캠페인 문구 일치",
                ownerScreen = "성과 기록 / 캠페인 기록",
                evidence = "triage_priority_badge_copy_alignment/P1_COPY_ALIGNMENT_COLLECT; evidence=achievement_career_copy_alignment",
                recommendation = "성과 목표 힌트와 캠페인 기록 다음 목표 문구가 같은 행동으로 읽히는지 회수 코멘트로 확인한다."
            });
        }

        if (report.replayIntentPercent > 0f && report.replayIntentPercent < 70f)
        {
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "medium",
                area = "재플레이 의향",
                ownerScreen = "메인 메뉴 / 추천 심사 재시작",
                evidence = $"재플레이 의향 {FormatFloat(report.replayIntentPercent)}%",
                recommendation = "운영 기준별 챌린지 차이와 추천 심사 재시작 동선을 더 눈에 띄게 만든다."
            });
        }

        if (report.averageDecisionClarityRating > 0f && report.averageDecisionClarityRating < 4f)
        {
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "medium",
                area = "판단 기준 명확성",
                ownerScreen = "심사 화면 / 심사 기준표",
                evidence = $"평균 {FormatFloat(report.averageDecisionClarityRating)}/5",
                recommendation = "사례 압박 요약, 심사 기준표, 판단 직후 권장 비교 피드백 문구를 보강한다."
            });
        }

        if (report.averageResultFairnessRating > 0f && report.averageResultFairnessRating < 4f)
        {
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "medium",
                area = "결과 납득도",
                ownerScreen = "후속 연락함 / 엔딩 에필로그",
                evidence = $"평균 {FormatFloat(report.averageResultFairnessRating)}/5",
                recommendation = "후속 연락함과 엔딩 에필로그에서 왜 지표가 변했는지 더 직접적으로 설명한다."
            });
        }

        if (report.averageUiReadabilityRating > 0f && report.averageUiReadabilityRating < 4f)
        {
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "medium",
                area = "UI 가독성",
                ownerScreen = "공통 UI / 저해상도 캡처",
                evidence = $"평균 {FormatFloat(report.averageUiReadabilityRating)}/5",
                recommendation = "기본 글자 크기, 줄 간격, 버튼 밀도를 조정하고 1280x720 캡처를 다시 확인한다."
            });
        }

        if (report.averageDifficultyRating > 0f && (report.averageDifficultyRating < 2.8f || report.averageDifficultyRating > 4.4f))
        {
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "medium",
                area = "난이도",
                ownerScreen = "운영 기준 밸런스 / 일일 브리핑",
                evidence = $"평균 {FormatFloat(report.averageDifficultyRating)}/5",
                recommendation = report.averageDifficultyRating > 4.4f
                    ? "1회차 균형 심사의 예산/민원 압박을 완화하고 긴축 감사는 고난도 기준으로 분리한다."
                    : "지원 확대 기준은 유지하되 균형 심사의 민원/예산 압박을 소폭 올려 긴장감을 보강한다."
            });
        }

        if (report.uiNeedsWorkCount > 0)
        {
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "low",
                area = "빠른 체크: UI",
                ownerScreen = "HTML 대시보드 / 화면 캡처",
                evidence = $"UI 보강 체크 {report.uiNeedsWorkCount}건",
                recommendation = "체크된 세션의 HTML 대시보드와 캡처를 열어 어떤 화면에서 읽기 부담이 컸는지 확인한다."
            });
        }

        if (report.caseExplanationNeededCount > 0)
        {
            report.actions.Add(new PlaytestCommercialTriageAction
            {
                priority = "low",
                area = "빠른 체크: 사례 설명",
                ownerScreen = "사례 자료실 / 심사 기준표",
                evidence = $"사례 설명 보강 체크 {report.caseExplanationNeededCount}건",
                recommendation = "사례 자료실 필터와 심사 기준표의 설명을 해당 가족 유형 중심으로 보강한다."
            });
        }
    }

    private static string BuildCommercialTriageStatus(PlaytestCommercialTriageReport report)
    {
        if (report.completeHumanSessionCount == 0)
        {
            return "실제 사람 완전 회수 세션이 아직 없어 10달러 판매 후보 판단은 보류한다. QA 샘플 설문은 리포트 형식 검증용으로만 사용한다.";
        }

        if (!report.enoughForCommercialTuning)
        {
            return "실제 사람 회수는 시작됐지만 10명 기준 미달이다. 밸런스 조정 후보를 모으되 판매 후보 확정은 보류한다.";
        }

        if (report.readyForTenDollarCommercialTuning)
        {
            return "10명 이상 완전 회수와 핵심 설문 기준을 통과했다. Steam 비공개 브랜치 QA와 Store Presence 입력으로 넘어갈 수 있다.";
        }

        return "10명 이상 회수 후에도 설문 기준에서 보강 항목이 남아 있다. 액션 항목을 처리한 뒤 재회수한다.";
    }

