            builder.AppendLine("      \"source\": \"" + EscapeJson(row.source) + "\",");
            builder.AppendLine("      \"complete\": " + BoolJson(row.complete) + ",");
            builder.AppendLine("      \"campaignMandateName\": \"" + EscapeJson(row.campaignMandateName) + "\",");
            builder.AppendLine("      \"campaignGrade\": \"" + EscapeJson(row.campaignGrade) + "\",");
            builder.AppendLine("      \"campaignScore\": " + row.campaignScore + ",");
            builder.AppendLine("      \"endingTitle\": \"" + EscapeJson(row.endingTitle) + "\",");
            builder.AppendLine("      \"difficultyRating\": " + row.difficultyRating + ",");
            builder.AppendLine("      \"decisionClarityRating\": " + row.decisionClarityRating + ",");
            builder.AppendLine("      \"resultFairnessRating\": " + row.resultFairnessRating + ",");
            builder.AppendLine("      \"uiReadabilityRating\": " + row.uiReadabilityRating + ",");
            builder.AppendLine("      \"priceValueRating\": " + row.priceValueRating + ",");
            builder.AppendLine("      \"replayRewardValueRating\": " + row.replayRewardValueRating + ",");
            builder.AppendLine("      \"supportBundleExternalHandoffZipSha256\": \"" + EscapeJson(row.supportBundleExternalHandoffZipSha256) + "\",");
            builder.AppendLine("      \"supportBundleHasExternalHandoffHash\": " + BoolJson(row.supportBundleHasExternalHandoffHash) + ",");
            builder.AppendLine("      \"replayIntent\": " + BoolJson(row.replayIntent));
            builder.Append("    }");
            builder.AppendLine(i == report.rows.Count - 1 ? "" : ",");
        }
        builder.AppendLine("  ]");
        builder.AppendLine("}");
        return builder.ToString();
    }

    private static string BuildPlaytestCommercialTriageCsv(PlaytestCommercialTriageReport report)
    {
        StringBuilder builder = new();
        builder.AppendLine("session_id,source,complete,campaign_mandate,campaign_grade,campaign_score,ending_title,difficulty,decision_clarity,result_fairness,ui_readability,price_value,replay_reward_value,support_bundle_external_handoff_zip_sha256,support_bundle_has_external_handoff_hash,replay_intent,difficulty_too_high,ui_needs_work,case_explanation_needed");
        foreach (PlaytestCommercialTriageRow row in report.rows)
        {
            builder.Append(EscapeCsv(row.sessionId)).Append(',')
                .Append(EscapeCsv(row.source)).Append(',')
                .Append(row.complete ? "true" : "false").Append(',')
                .Append(EscapeCsv(row.campaignMandateName)).Append(',')
                .Append(EscapeCsv(row.campaignGrade)).Append(',')
                .Append(row.campaignScore).Append(',')
                .Append(EscapeCsv(row.endingTitle)).Append(',')
                .Append(row.difficultyRating).Append(',')
                .Append(row.decisionClarityRating).Append(',')
                .Append(row.resultFairnessRating).Append(',')
                .Append(row.uiReadabilityRating).Append(',')
                .Append(row.priceValueRating).Append(',')
                .Append(row.replayRewardValueRating).Append(',')
                .Append(EscapeCsv(row.supportBundleExternalHandoffZipSha256)).Append(',')
                .Append(row.supportBundleHasExternalHandoffHash ? "true" : "false").Append(',')
                .Append(row.replayIntent ? "true" : "false").Append(',')
                .Append(row.difficultyTooHigh ? "true" : "false").Append(',')
                .Append(row.uiNeedsWork ? "true" : "false").Append(',')
                .AppendLine(row.caseExplanationNeeded ? "true" : "false");
        }
        return builder.ToString();
    }

    private static string BuildPlaytestCommercialTriageActionCsv(PlaytestCommercialTriageReport report)
    {
        StringBuilder builder = new();
        builder.AppendLine("priority,area,owner_screen,owner_screen_evidence,support_bundle_manifest_handoff_zip_sha256,evidence,recommendation");
        foreach (PlaytestCommercialTriageAction action in report.actions)
        {
            builder.Append(EscapeCsv(action.priority)).Append(',')
                .Append(EscapeCsv(action.area)).Append(',')
                .Append(EscapeCsv(action.ownerScreen)).Append(',')
                .Append(EscapeCsv(CommercialTriageOwnerScreenEvidence(action))).Append(',')
                .Append(EscapeCsv(report.externalHandoffZipSha256)).Append(',')
                .Append(EscapeCsv(action.evidence)).Append(',')
                .AppendLine(EscapeCsv(action.recommendation));
        }
        return builder.ToString();
    }

    private static string CommercialTriageOwnerScreenEvidence(PlaytestCommercialTriageAction action)
    {
        if (action == null)
        {
            return "";
        }

        if (action.area == "반복 보상/장기 기록 가치감")
        {
            return "care_review_playtest_readiness_smoke_result.json: commercialChecklistMentionsSurfaceActions=true, commercialChecklistReadable=true; care_review_main_menu_case_objective_smoke_result.json: menuMentionsAchievementBadge=true; low_resolution_ui/care_review_low_resolution_ui_smoke_result.json: mainMenuAchievementBadgeReadable=true; care_review_career_record_smoke_result.json: appealTriageQueueReturnOpensCareerRecord=true, 보정 후보 결과; care_review_achievement_smoke_result.json: achievementCardMentionsAppealTriageResult=true; STORE_CANDIDATE_CAPTURE_SYNC_HASHES.sha256";
        }

        if (action.area == "반복 가치 세부: 성과 기록 보상")
        {
            return "care_review_achievement_smoke_result.json: achievementReplayRewardPanelMentionsRecordLinkHint=true, achievementRecordLinkHintReadable=true, achievementDecisionPracticeTierRecordButtonsActive=true";
        }

        if (action.area == "반복 가치 세부: 캠페인 기록 다음 목표")
        {
            return "low_resolution_ui/care_review_low_resolution_ui_smoke_result.json: careerRecordActionHintReadable=true, lowResolutionReleaseCopyAlignmentReadable=true; care_review_career_record_smoke_result.json: careerRecordActionHintSummarizesButtons=true";
        }

        if (action.area == "반복 가치 세부: 상점 후보 루프 이해")
        {
            return "SCREENSHOT_CANDIDATE_AB_TEST_KO.md: achievement_career_copy_alignment, main_menu_loop_entry, menu_campaign_briefing_weakness; PLAYTEST_SESSION_INDEX_TEMPLATE.csv: screenshot_ab_loop_question_id; STORE_CANDIDATE_CAPTURE_SYNC_HASHES.sha256";
        }

        if (action.area == "우선순위 배지: 상점 후보 루프 이해")
        {
            return "SCREENSHOT_CANDIDATE_DECISION_MATRIX_KO.md: triage_priority_badge_reward_loop_candidate, P0_WAIT_EXTERNAL_AB; STORE_PRESENCE_QA_CARD_KO.md: post_external_collection_promotion_summary; PLAYTEST_SESSION_INDEX_TEMPLATE.csv: triage_priority_badge_id";
        }

        if (action.area == "우선순위 배지: 메인 메뉴 기준 화면")
        {
            return "SCREENSHOT_CANDIDATE_DECISION_MATRIX_KO.md: triage_priority_badge_main_menu_baseline, P1_BASELINE_GUARD; PLAYTEST_SESSION_INDEX_TEMPLATE.csv: main_menu_loop_entry, menu_campaign_briefing_weakness; store_page/STORE_PRESENCE_SELECTION_KO.md: 01_main_menu.png; care_review_main_menu_mandate_smoke_result.json: briefingMentionsPreviousWeakness=true, briefingUsesCoachingWeaknessTerms=true, briefingWeaknessFocusCaptionReadable=true, briefingContrastEffectApplied=true, changedBriefingKeepsPreviousWeakness=true, changedBriefingKeepsCoachingWeaknessTerms=true, changedBriefingKeepsWeaknessFocusCaption=true; low_resolution_ui/care_review_low_resolution_ui_smoke_result.json: mainMenuBriefingWeaknessFocusReadable=true";
        }

        if (action.area == "우선순위 배지: 성과-캠페인 문구 일치")
        {
            return "SCREENSHOT_CANDIDATE_DECISION_MATRIX_KO.md: triage_priority_badge_copy_alignment, P1_COPY_ALIGNMENT_COLLECT; PLAYTEST_SESSION_INDEX_TEMPLATE.csv: achievement_career_copy_alignment; low_resolution_ui/care_review_low_resolution_ui_smoke_result.json: lowResolutionReleaseCopyAlignmentReadable=true";
        }

        if (action.ownerScreen != null && action.ownerScreen.Contains("상점"))
        {
            return "SCREENSHOT_CANDIDATE_DECISION_MATRIX_KO.md; STORE_CANDIDATE_CAPTURE_SYNC_HASHES.sha256";
        }

        if (action.ownerScreen != null && action.ownerScreen.Contains("캠페인 기록"))
        {
            return "care_review_career_record_smoke_result.json";
        }

        if (action.ownerScreen != null && action.ownerScreen.Contains("성과 기록"))
        {
            return "care_review_achievement_smoke_result.json";
        }

        return "care_review_playtest_commercial_triage.md";
    }

    private static string BuildPlaytestCommercialTriageMarkdown(PlaytestCommercialTriageReport report)
    {
        StringBuilder builder = new();
        builder.AppendLine("# 10달러 상용화 플레이테스트 트리아지");
        builder.AppendLine();
        builder.AppendLine("- 생성 시각: " + report.generatedAt);
        builder.AppendLine("- 근거 범위: `" + report.evidenceScope + "`");
        builder.AppendLine("- 실제 사람 완전 회수: " + report.completeHumanSessionCount + " / " + report.recommendedCommercialMinimum);
        builder.AppendLine("- 설문 세션: " + report.totalSurveySessionCount + "건 (외부 " + report.externalSurveySessionCount + ", QA 샘플 " + report.qaSurveySessionCount + ")");
        builder.AppendLine("- 지원 번들 외부 handoff SHA 포함 세션: " + report.supportBundleExternalHandoffHashCount);
        builder.AppendLine("- 지원 번들 manifest handoff SHA256: `" + report.externalHandoffZipSha256 + "`");
        builder.AppendLine("- 평균 난이도: " + FormatFloat(report.averageDifficultyRating) + "/5");
        builder.AppendLine("- 평균 판단 기준 명확성: " + FormatFloat(report.averageDecisionClarityRating) + "/5");
        builder.AppendLine("- 평균 결과 납득도: " + FormatFloat(report.averageResultFairnessRating) + "/5");
        builder.AppendLine("- 평균 UI 가독성: " + FormatFloat(report.averageUiReadabilityRating) + "/5");
        builder.AppendLine("- 평균 10달러 가치감: " + FormatFloat(report.averagePriceValueRating) + "/5");
        builder.AppendLine("- 평균 반복 보상/장기 기록 가치감: " + FormatFloat(report.averageReplayRewardValueRating) + "/5");
        builder.AppendLine("- 재플레이 의향: " + FormatFloat(report.replayIntentPercent) + "%");
        builder.AppendLine("- 판정: " + report.readinessStatus);
        builder.AppendLine();
        builder.AppendLine("## 조치 우선순위");
        builder.AppendLine();
        foreach (PlaytestCommercialTriageAction action in report.actions)
        {
            builder.AppendLine($"- [{action.priority}] {action.area}: {action.evidence} -> {action.recommendation}");
        }
        if (report.actions.Count == 0)
        {
            builder.AppendLine("- 현재 설문 기준으로 즉시 조치할 항목은 없다.");
        }
        builder.AppendLine();
        builder.AppendLine("## 담당 화면별 체크리스트");
        builder.AppendLine();
        builder.AppendLine("| 담당 화면 | 우선순위 | 영역 | 담당 화면 증거 | 권고 |");
        builder.AppendLine("| --- | --- | --- | --- | --- |");
        foreach (PlaytestCommercialTriageAction action in report.actions)
        {
            builder.Append("| ")
                .Append(action.ownerScreen).Append(" | ")
                .Append(action.priority).Append(" | ")
                .Append(action.area).Append(" | ")
                .Append(CommercialTriageOwnerScreenEvidence(action)).Append(" | ")
                .Append(action.recommendation).AppendLine(" |");
        }
        if (report.actions.Count == 0)
        {
            builder.AppendLine("| - | - | - | - | 현재 담당 화면별 추가 조치가 없다. |");
        }
        builder.AppendLine();
        builder.AppendLine("## 세션별 설문");
        builder.AppendLine();
        builder.AppendLine("| Session | Source | Complete | 기준 | 등급 | 난이도 | 명확성 | 납득도 | 가독성 | 가치감 | 반복 가치 | Handoff SHA | 재플레이 |");
        builder.AppendLine("| --- | --- | --- | --- | --- | ---: | ---: | ---: | ---: | ---: | ---: | --- | --- |");
        foreach (PlaytestCommercialTriageRow row in report.rows)
        {
            builder.Append("| `").Append(row.sessionId).Append("` | ")
                .Append(row.source).Append(" | ")
                .Append(row.complete ? "yes" : "no").Append(" | ")
                .Append(row.campaignMandateName).Append(" | ")
                .Append(row.campaignGrade).Append('(').Append(row.campaignScore).Append(") | ")
                .Append(row.difficultyRating).Append(" | ")
                .Append(row.decisionClarityRating).Append(" | ")
                .Append(row.resultFairnessRating).Append(" | ")
                .Append(row.uiReadabilityRating).Append(" | ")
                .Append(row.priceValueRating).Append(" | ")
                .Append(row.replayRewardValueRating).Append(" | ")
                .Append(row.supportBundleHasExternalHandoffHash ? ShortHash(row.supportBundleExternalHandoffZipSha256) : "").Append(" | ")
                .Append(row.replayIntent ? "yes" : "no").AppendLine(" |");
        }
        return builder.ToString();
    }

    private static string BuildPlaytestCommercialTriageHtml(PlaytestCommercialTriageReport report)
    {
        StringBuilder html = new();
        html.AppendLine("<!doctype html><html lang=\"ko\"><head><meta charset=\"utf-8\"><title>Care Review Commercial Triage</title>");
        html.AppendLine("<style>body{font-family:Segoe UI,Malgun Gothic,sans-serif;background:#101418;color:#eef2f2;margin:0;padding:28px;}h1,h2{margin:0 0 14px;}section{margin:0 0 28px;}table{border-collapse:collapse;width:100%;background:#172025;}th,td{border:1px solid #314047;padding:8px 10px;text-align:left;}th{background:#223039}.metric{display:inline-block;margin:4px 8px 4px 0;padding:6px 10px;border-radius:6px;background:#223039}.high{background:#5a2e35}.medium{background:#5a3d2a}.low{background:#2e4b55}</style>");
        html.AppendLine("</head><body>");
        html.AppendLine("<h1>10달러 상용화 플레이테스트 트리아지</h1>");
        html.AppendLine("<section><p>" + HtmlEscape(report.readinessStatus) + "</p>");
        html.AppendLine("<p><span class=\"metric\">실제 완전 회수 " + report.completeHumanSessionCount + "/" + report.recommendedCommercialMinimum + "</span><span class=\"metric\">가치감 " + FormatFloat(report.averagePriceValueRating) + "/5</span><span class=\"metric\">반복 가치 " + FormatFloat(report.averageReplayRewardValueRating) + "/5</span><span class=\"metric\">재플레이 " + FormatFloat(report.replayIntentPercent) + "%</span><span class=\"metric\">근거 " + HtmlEscape(report.evidenceScope) + "</span><span class=\"metric\">handoff SHA " + HtmlEscape(ShortHash(report.externalHandoffZipSha256)) + "</span></p></section>");
        html.AppendLine("<section><h2>조치 우선순위</h2>");
        html.AppendLine("<table><thead><tr><th>우선순위</th><th>영역</th><th>담당 화면</th><th>담당 화면 증거</th><th>Handoff SHA</th><th>근거</th><th>권고</th></tr></thead><tbody>");
        foreach (PlaytestCommercialTriageAction action in report.actions)
        {
            html.Append("<tr><td><span class=\"metric ").Append(HtmlEscape(action.priority)).Append("\">").Append(HtmlEscape(action.priority)).Append("</span></td><td>")
                .Append(HtmlEscape(action.area)).Append("</td><td>")
                .Append(HtmlEscape(action.ownerScreen)).Append("</td><td>")
                .Append(HtmlEscape(CommercialTriageOwnerScreenEvidence(action))).Append("</td><td>")
                .Append(HtmlEscape(ShortHash(report.externalHandoffZipSha256))).Append("</td><td>")
                .Append(HtmlEscape(action.evidence)).Append("</td><td>")
                .Append(HtmlEscape(action.recommendation)).AppendLine("</td></tr>");
        }
        html.AppendLine("</tbody></table></section>");
        html.AppendLine("<section><h2>담당 화면별 체크리스트</h2><table><thead><tr><th>담당 화면</th><th>우선순위</th><th>영역</th><th>담당 화면 증거</th><th>권고</th></tr></thead><tbody>");
        foreach (PlaytestCommercialTriageAction action in report.actions)
        {
            html.Append("<tr><td>").Append(HtmlEscape(action.ownerScreen)).Append("</td><td>")
                .Append(HtmlEscape(action.priority)).Append("</td><td>")
                .Append(HtmlEscape(action.area)).Append("</td><td>")
                .Append(HtmlEscape(CommercialTriageOwnerScreenEvidence(action))).Append("</td><td>")
                .Append(HtmlEscape(action.recommendation)).AppendLine("</td></tr>");
        }
        html.AppendLine("</tbody></table></section>");
        html.AppendLine("<section><h2>세션별 설문</h2><table><thead><tr><th>Session</th><th>Source</th><th>Complete</th><th>기준</th><th>등급</th><th>난이도</th><th>명확성</th><th>납득도</th><th>가독성</th><th>가치감</th><th>반복 가치</th><th>Handoff SHA</th><th>재플레이</th></tr></thead><tbody>");
        foreach (PlaytestCommercialTriageRow row in report.rows)
        {
            html.Append("<tr><td>").Append(HtmlEscape(row.sessionId)).Append("</td><td>")
                .Append(HtmlEscape(row.source)).Append("</td><td>")
                .Append(row.complete ? "yes" : "no").Append("</td><td>")
                .Append(HtmlEscape(row.campaignMandateName)).Append("</td><td>")
                .Append(HtmlEscape(row.campaignGrade)).Append('(').Append(row.campaignScore).Append(")</td><td>")
                .Append(row.difficultyRating).Append("</td><td>")
                .Append(row.decisionClarityRating).Append("</td><td>")
                .Append(row.resultFairnessRating).Append("</td><td>")
                .Append(row.uiReadabilityRating).Append("</td><td>")
                .Append(row.priceValueRating).Append("</td><td>")
                .Append(row.replayRewardValueRating).Append("</td><td>")
                .Append(HtmlEscape(row.supportBundleHasExternalHandoffHash ? ShortHash(row.supportBundleExternalHandoffZipSha256) : "")).Append("</td><td>")
                .Append(row.replayIntent ? "yes" : "no").AppendLine("</td></tr>");
        }
        html.AppendLine("</tbody></table></section></body></html>");
        return html.ToString();
    }

