    private enum RatingMetric
    {
        Difficulty,
        DecisionClarity,
        ResultFairness,
        UiReadability,
        PriceValue,
        ReplayRewardValue
    }

    private enum BoolMetric
    {
        ReplayIntent,
        DifficultyTooHigh,
        UiNeedsWork,
        CaseExplanationNeeded
    }

    private static int CountRowsBySource(List<PlaytestSessionAuditRow> rows, string source)
    {
        int count = 0;
        foreach (PlaytestSessionAuditRow row in rows)
        {
            if (row.source == source)
            {
                count++;
            }
        }
        return count;
    }

    private static string FirstSupportBundleHandoffSha(List<PlaytestSessionAuditRow> rows)
    {
        foreach (PlaytestSessionAuditRow row in rows)
        {
            if (row.supportBundleHasExternalHandoffHash)
            {
                return row.supportBundleExternalHandoffZipSha256;
            }
        }

        return "";
    }

    private static float AverageRating(List<PlaytestSessionAuditRow> rows, RatingMetric metric)
    {
        int total = 0;
        int count = 0;
        foreach (PlaytestSessionAuditRow row in rows)
        {
            int value = metric switch
            {
                RatingMetric.Difficulty => row.difficultyRating,
                RatingMetric.DecisionClarity => row.decisionClarityRating,
                RatingMetric.ResultFairness => row.resultFairnessRating,
                RatingMetric.UiReadability => row.uiReadabilityRating,
                RatingMetric.ReplayRewardValue => row.replayRewardValueRating,
                _ => row.priceValueRating
            };
            if (value > 0)
            {
                total += value;
                count++;
            }
        }
        return count > 0 ? total / (float)count : 0f;
    }

    private static float AverageBoolPercent(List<PlaytestSessionAuditRow> rows, BoolMetric metric)
    {
        if (rows.Count == 0)
        {
            return 0f;
        }
        return CountBoolRows(rows, metric) * 100f / rows.Count;
    }

    private static int CountBoolRows(List<PlaytestSessionAuditRow> rows, BoolMetric metric)
    {
        int count = 0;
        foreach (PlaytestSessionAuditRow row in rows)
        {
            bool value = metric switch
            {
                BoolMetric.DifficultyTooHigh => row.difficultyTooHigh,
                BoolMetric.UiNeedsWork => row.uiNeedsWork,
                BoolMetric.CaseExplanationNeeded => row.caseExplanationNeeded,
                _ => row.replayIntent
            };
            if (value)
            {
                count++;
            }
        }
        return count;
    }

    private static bool FileContainsAll(string path, params string[] values)
    {
        if (!File.Exists(path))
        {
            return false;
        }

        string content = File.ReadAllText(path, Encoding.UTF8);
        foreach (string value in values)
        {
            if (!content.Contains(value))
            {
                return false;
            }
        }

        return true;
    }

    private static string SafeReadAllText(string path)
    {
        return File.Exists(path) ? File.ReadAllText(path, Encoding.UTF8) : "";
    }

    private static bool ContainsLocalAbsolutePath(string text)
    {
        if (string.IsNullOrEmpty(text))
        {
            return false;
        }

        return ContainsOrdinalIgnoreCase(text, "C:/Users") ||
            ContainsOrdinalIgnoreCase(text, "C:\\Users") ||
            ContainsOrdinalIgnoreCase(text, "C:\\\\Users") ||
            ContainsOrdinalIgnoreCase(text, "/AppData/") ||
            ContainsOrdinalIgnoreCase(text, "\\AppData\\") ||
            ContainsOrdinalIgnoreCase(text, "\\\\AppData\\\\") ||
            ContainsOrdinalIgnoreCase(text, "LocalLow");
    }

    private static bool ContainsPortableUnsafePath(string text)
    {
        if (string.IsNullOrEmpty(text))
        {
            return false;
        }

        return ContainsLocalAbsolutePath(text) ||
            ContainsOrdinalIgnoreCase(text, "C:/") ||
            ContainsOrdinalIgnoreCase(text, "C:\\") ||
            ContainsOrdinalIgnoreCase(text, "C:\\\\");
    }

    private static bool ContainsOrdinalIgnoreCase(string text, string pattern)
    {
        return text.IndexOf(pattern, StringComparison.OrdinalIgnoreCase) >= 0;
    }

    private static bool ContainsAnyOrdinalIgnoreCase(string text, params string[] patterns)
    {
        foreach (string pattern in patterns)
        {
            if (ContainsOrdinalIgnoreCase(text, pattern))
            {
                return true;
            }
        }

        return false;
    }

