    }

    private static string EscapeJson(string value)
    {
        if (string.IsNullOrEmpty(value))
        {
            return "";
        }

        return value.Replace("\\", "\\\\").Replace("\"", "\\\"").Replace("\r", "\\r").Replace("\n", "\\n");
    }

    private static string HtmlEscape(string value)
    {
        if (string.IsNullOrEmpty(value))
        {
            return "";
        }

        return value
            .Replace("&", "&amp;")
            .Replace("<", "&lt;")
            .Replace(">", "&gt;")
            .Replace("\"", "&quot;")
            .Replace("'", "&#39;");
    }

    private static string CsvCell(string value)
    {
        if (string.IsNullOrEmpty(value))
        {
            return "";
        }

        bool needsQuotes = value.Contains(",") || value.Contains("\"") || value.Contains("\n") || value.Contains("\r");
        string escaped = value.Replace("\"", "\"\"");
        return needsQuotes ? "\"" + escaped + "\"" : escaped;
    }

    private static string FirstNonEmpty(string first, string second)
    {
        return string.IsNullOrWhiteSpace(first) ? (second ?? "") : first;
    }

    private static int FirstNonZero(int first, int second)
    {
        return first != 0 ? first : second;
    }

    private static string ExtractMarkdownField(string text, string key)
    {
        if (string.IsNullOrEmpty(text))
        {
            return "";
        }

        string marker = key + ":";
        using StringReader reader = new(text);
        string line;
        while ((line = reader.ReadLine()) != null)
        {
            string trimmed = line.Trim();
            if (trimmed.StartsWith(marker, StringComparison.OrdinalIgnoreCase))
            {
                return trimmed.Substring(marker.Length).Trim();
            }
        }

        return "";
    }

    private static int ExtractJsonInt(string json, string key)
    {
        string number = ExtractJsonNumber(json, key);
        return int.TryParse(number, NumberStyles.Integer, CultureInfo.InvariantCulture, out int value) ? value : 0;
    }

    private static float ExtractJsonFloat(string json, string key)
    {
        string number = ExtractJsonNumber(json, key);
        return float.TryParse(number, NumberStyles.Float, CultureInfo.InvariantCulture, out float value) ? value : 0f;
    }

    private static bool ExtractJsonBool(string json, string key)
    {
        if (string.IsNullOrEmpty(json))
        {
            return false;
        }

        string marker = "\"" + key + "\":";
        int markerIndex = json.IndexOf(marker, StringComparison.Ordinal);
        if (markerIndex < 0)
        {
            return false;
        }

        int valueIndex = markerIndex + marker.Length;
        while (valueIndex < json.Length && char.IsWhiteSpace(json[valueIndex]))
        {
            valueIndex++;
        }

        return json.Substring(valueIndex).StartsWith("true", StringComparison.OrdinalIgnoreCase);
    }

    private static string ExtractJsonString(string json, string key)
    {
        if (string.IsNullOrEmpty(json))
        {
            return "";
        }

        string marker = "\"" + key + "\":";
        int markerIndex = json.IndexOf(marker, StringComparison.Ordinal);
        if (markerIndex < 0)
        {
            return "";
        }

        int valueIndex = markerIndex + marker.Length;
        while (valueIndex < json.Length && char.IsWhiteSpace(json[valueIndex]))
        {
            valueIndex++;
        }

        if (valueIndex >= json.Length || json[valueIndex] != '"')
        {
            return "";
        }

        valueIndex++;
        StringBuilder builder = new();
        while (valueIndex < json.Length)
        {
            char current = json[valueIndex++];
            if (current == '"')
            {
                break;
            }

            if (current == '\\' && valueIndex < json.Length)
            {
                char escaped = json[valueIndex++];
                builder.Append(escaped switch
                {
                    'n' => '\n',
                    'r' => '\r',
                    't' => '\t',
                    '"' => '"',
                    '\\' => '\\',
                    _ => escaped
                });
            }
            else
            {
                builder.Append(current);
            }
        }

        return builder.ToString();
    }

    private static string ExtractJsonNumber(string json, string key)
    {
        if (string.IsNullOrEmpty(json))
        {
            return "";
        }

        string marker = "\"" + key + "\":";
        int markerIndex = json.IndexOf(marker, StringComparison.Ordinal);
        if (markerIndex < 0)
        {
            return "";
        }

        int valueIndex = markerIndex + marker.Length;
        while (valueIndex < json.Length && char.IsWhiteSpace(json[valueIndex]))
        {
            valueIndex++;
        }

        int endIndex = valueIndex;
        if (endIndex < json.Length && json[endIndex] == '-')
        {
            endIndex++;
        }

        while (endIndex < json.Length &&
            (char.IsDigit(json[endIndex]) ||
                json[endIndex] == '.' ||
                json[endIndex] == 'e' ||
                json[endIndex] == 'E' ||
                json[endIndex] == '+' ||
                json[endIndex] == '-'))
        {
            endIndex++;
        }

        return endIndex > valueIndex ? json.Substring(valueIndex, endIndex - valueIndex) : "";
    }

    private static void AppendPreflightCheck(StringBuilder builder, string label, bool passed, string evidence)
    {
        builder.AppendLine("- [" + (passed ? "x" : " ") + "] " + label + " - " + evidence);
    }

    private static void AppendPreflightAction(StringBuilder builder, string label, string evidence)
    {
        builder.AppendLine("- [ ] ACTION REQUIRED: " + label + " - " + evidence);
    }

    private static void AppendPngDimensionCheck(StringBuilder builder, string label, string path, int expectedWidth, int expectedHeight)
    {
        bool exists = File.Exists(path);
        bool dimensionsMatch = exists && TryReadPngDimensions(path, out int width, out int height) && width == expectedWidth && height == expectedHeight;
        string evidence = exists
            ? Path.GetFileName(path) + " (" + (dimensionsMatch ? expectedWidth + "x" + expectedHeight : "dimension mismatch") + ")"
            : Path.GetFileName(path) + " missing";
        AppendPreflightCheck(builder, label, dimensionsMatch, evidence);
    }

    private static bool TryReadPngDimensions(string path, out int width, out int height)
    {
        width = 0;
        height = 0;
        try
        {
            byte[] bytes = File.ReadAllBytes(path);
            if (bytes.Length < 24 || bytes[0] != 0x89 || bytes[1] != 0x50 || bytes[2] != 0x4E || bytes[3] != 0x47)
            {
                return false;
            }

            width = ReadBigEndianInt(bytes, 16);
            height = ReadBigEndianInt(bytes, 20);
            return width > 0 && height > 0;
        }
        catch
        {
            return false;
        }
    }

    private static int ReadBigEndianInt(byte[] bytes, int offset)
    {
        return (bytes[offset] << 24) |
            (bytes[offset + 1] << 16) |
            (bytes[offset + 2] << 8) |
            bytes[offset + 3];
    }

    private static string AbsoluteForwardPath(string path)
    {
        return Path.GetFullPath(path).Replace("\\", "/");
    }

    private static int CountFiles(string directoryPath)
    {
        int count = 0;
        foreach (string ignored in Directory.GetFiles(directoryPath, "*", SearchOption.AllDirectories))
        {
            count++;
        }

        return count;
    }

    private static long SumFileBytes(string directoryPath)
    {
        long total = 0;
        foreach (string filePath in Directory.GetFiles(directoryPath, "*", SearchOption.AllDirectories))
        {
            total += new FileInfo(filePath).Length;
        }

        return total;
    }

    private static void PrepareTexture(string path, bool alpha)
    {
        TextureImporter importer = AssetImporter.GetAtPath(path) as TextureImporter;
        if (importer == null)
        {
            Debug.LogWarning("Missing texture: " + path);
            return;
        }

        importer.textureType = TextureImporterType.Sprite;
        importer.spriteImportMode = SpriteImportMode.Single;
        importer.isReadable = false;
        importer.mipmapEnabled = false;
        importer.alphaIsTransparency = alpha;
        importer.maxTextureSize = 4096;
        importer.textureCompression = TextureImporterCompression.Compressed;
        importer.compressionQuality = 70;
        importer.SaveAndReimport();
    }

    private static void PrepareAudioAssets()
    {
        PrepareAudioDirectory("Assets/Resources/Audio/Bgm", true);
        PrepareAudioDirectory("Assets/Resources/Audio/Sfx", false);
    }

    private static void PrepareAudioDirectory(string directoryPath, bool bgm)
    {
        if (!Directory.Exists(directoryPath))
        {
            Debug.LogWarning("Missing audio directory: " + directoryPath);
            return;
        }

        foreach (string filePath in Directory.GetFiles(directoryPath, "*.wav", SearchOption.TopDirectoryOnly))
        {
            PrepareAudio(filePath.Replace('\\', '/'), bgm);
        }
    }

    private static void PrepareAudio(string path, bool bgm)
    {
        AudioImporter importer = AssetImporter.GetAtPath(path) as AudioImporter;
        if (importer == null)
        {
            Debug.LogWarning("Missing audio: " + path);
            return;
        }

        AudioImporterSampleSettings settings = importer.defaultSampleSettings;
        settings.loadType = bgm ? AudioClipLoadType.Streaming : AudioClipLoadType.DecompressOnLoad;
        settings.compressionFormat = bgm ? AudioCompressionFormat.Vorbis : AudioCompressionFormat.ADPCM;
        settings.quality = bgm ? 0.62f : 1f;
        settings.sampleRateSetting = AudioSampleRateSetting.OverrideSampleRate;
        settings.sampleRateOverride = bgm ? 32000u : 22050u;
        settings.preloadAudioData = false;
        importer.defaultSampleSettings = settings;
        importer.forceToMono = !bgm;
        importer.loadInBackground = bgm;
        importer.SaveAndReimport();
    }

    private readonly struct AchievementCandidate
    {
